// 구독 해지
export async function DELETE() {
    const session = await getServerSession();
    if (!session?.dbId) return NextResponse.json({ error: "로그인이 필요합니다." }, { status: 401 });

    try {
        const existing = await prisma.subscription.findUnique({ where: { userId: session.dbId } });
        if (!existing || existing.status !== "ACTIVE") {
            return NextResponse.json({ error: "구독 중이 아닙니다." }, { status: 400 });
        }

        // 구독 취소
        await prisma.subscription.update({
            where: { userId: session.dbId },
            data: { status: "CANCELLED", cancelledAt: new Date() },
        });

        // 프로필 사진 초기화 (role 기반)
        const resetAvatarUrl = session.role === "CREATOR" ? "/creator.png" : null;
        await prisma.$executeRaw`
            UPDATE "User" SET "avatarUrl" = ${resetAvatarUrl}, "updatedAt" = NOW()
            WHERE id = ${session.dbId}
        `;

        return NextResponse.json({ ok: true });
    } catch (e) {
        console.error(e);
        return NextResponse.json({ error: "해지 처리 중 오류가 발생했습니다." }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "@/lib/session";
import { prisma } from "@/lib/prisma";
import { createHmac } from "crypto";
import { SESSION_COOKIE_NAME, SESSION_MAX_AGE_SECONDS } from "@/lib/constants";

const MAX_SIZE_BYTES = 2 * 1024 * 1024; // 2MB

function signSession(payload: Record<string, unknown>, secret: string) {
    const json = JSON.stringify(payload);
    const signature = createHmac("sha256", secret).update(json).digest("base64url");
    return `${Buffer.from(json).toString("base64url")}.${signature}`;
}

// 프로필 이미지 업로드 (Base64 dataURL)
export async function PATCH(req: NextRequest) {
    const session = await getServerSession();
    if (!session?.dbId) {
        return NextResponse.json({ error: "로그인이 필요합니다." }, { status: 401 });
    }

    // PRO 구독자 또는 ADMIN만 프로필 사진 변경 가능
    const { avatarUrl } = body;

    // null이면 삭제 (카카오 이미지로 복귀)
    if (avatarUrl !== null && avatarUrl !== undefined) {
        // dataURL 형식 검사
        if (!avatarUrl.startsWith("data:image/")) {
            return NextResponse.json({ error: "올바른 이미지 형식이 아닙니다." }, { status: 400 });
        }
        // 크기 검사 (Base64 → 실제 크기 근사)
        const base64Data = avatarUrl.split(",")[1] ?? "";
        const approxBytes = Math.ceil((base64Data.length * 3) / 4);
        if (approxBytes > MAX_SIZE_BYTES) {
            return NextResponse.json({ error: "이미지 크기는 2MB 이하여야 합니다." }, { status: 400 });
        }
    }

    await prisma.$executeRaw`
        UPDATE "User" SET "avatarUrl" = ${avatarUrl ?? null}, "updatedAt" = NOW() WHERE id = ${session.dbId}
    `;

    // 세션 쿠키 갱신
    const sessionSecret = process.env.KAKAO_SESSION_SECRET!;
    const newPayload = {
        provider: session.provider,
        dbId: session.dbId,
        id: session.id,
        email: session.email,
        name: session.name,
        nickname: session.nickname,
        role: session.role,
        issuedAt: Date.now(),
    };
    const newToken = signSession(newPayload, sessionSecret);

    const res = NextResponse.json({ avatarUrl: avatarUrl ?? null });
    res.cookies.set({
        name: SESSION_COOKIE_NAME,
        value: newToken,
        httpOnly: true,
        secure: process.env.NODE_ENV === "production",
        sameSite: "lax",
        path: "/",
        maxAge: SESSION_MAX_AGE_SECONDS,
    });
    return res;
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "@/lib/session";
import { prisma } from "@/lib/prisma";
import { createHmac } from "crypto";
import { SESSION_COOKIE_NAME, SESSION_MAX_AGE_SECONDS } from "@/lib/constants";

const MAX_SIZE_BYTES = 2 * 1024 * 1024; // 2MB

function signSession(payload: Record<string, unknown>, secret: string) {
    const json = JSON.stringify(payload);
    const signature = createHmac("sha256", secret).update(json).digest("base64url");
    return `${Buffer.from(json).toString("base64url")}.${signature}`;
}

// 프로필 이미지 업로드 (Base64 dataURL)
export async function PATCH(req: NextRequest) {
    try {
        const session = await getServerSession();
        if (!session?.dbId) {
            return NextResponse.json({ error: "로그인이 필요합니다." }, { status: 401 });
        }

        // PRO 구독자 또는 ADMIN만 프로필 사진 변경 가능 (CREATOR도 PRO면 허용)
        const role = String(session.role ?? "USER");
        let canEdit = false;

        if (role === "ADMIN") {
            canEdit = true;
        } else {
            // USER, CREATOR 모두 구독 상태 확인
            const subRows = await prisma.$queryRaw<{ status: string }[]>`
                SELECT status::text FROM "Subscription"
                WHERE "userId" = ${session.dbId}
                LIMIT 1
            `;
            canEdit = subRows.length > 0 && subRows[0].status.toUpperCase() === "ACTIVE";
        }

        if (!canEdit) {
            return NextResponse.json(
                { error: "PRO 구독자만 프로필 사진을 변경할 수 있습니다." },
                { status: 403 }
            );
        }

        const body = await req.json() as { avatarUrl?: string | null };
        const { avatarUrl } = body;

        // null이면 삭제
        if (avatarUrl !== null && avatarUrl !== undefined) {
            if (!avatarUrl.startsWith("data:image/")) {
                return NextResponse.json({ error: "올바른 이미지 형식이 아닙니다." }, { status: 400 });
            }
            const base64Data = avatarUrl.split(",")[1] ?? "";
            const approxBytes = Math.ceil((base64Data.length * 3) / 4);
            if (approxBytes > MAX_SIZE_BYTES) {
                return NextResponse.json({ error: "이미지 크기는 2MB 이하여야 합니다." }, { status: 400 });
            }
        }

        await prisma.$executeRaw`
            UPDATE "User" SET "avatarUrl" = ${avatarUrl ?? null}, "updatedAt" = NOW() WHERE id = ${session.dbId}
        `;

        // 세션 쿠키 갱신
        const sessionSecret = process.env.KAKAO_SESSION_SECRET!;
        const newPayload = {
            provider: session.provider,
            dbId: session.dbId,
            id: session.id,
            email: session.email,
            name: session.name,
            nickname: session.nickname,
            role: session.role,
            issuedAt: Date.now(),
        };
        const newToken = signSession(newPayload, sessionSecret);

        const res = NextResponse.json({ avatarUrl: avatarUrl ?? null });
        res.cookies.set({
            name: SESSION_COOKIE_NAME,
            value: newToken,
            httpOnly: true,
            secure: process.env.NODE_ENV === "production",
            sameSite: "lax",
            path: "/",
            maxAge: SESSION_MAX_AGE_SECONDS,
        });
        return res;
    } catch (e) {
        console.error("[avatar PATCH error]", e);
        return NextResponse.json({ error: "서버 오류가 발생했습니다." }, { status: 500 });
    }
}

'use client';

import { useEffect, useState } from "react";
import Link from "next/link";

type SessionData = {
    dbId?: string | null;
    id?: string | null;
    name?: string | null;
    nickname?: string | null;
    image?: string | null;
    email?: string | null;
    role?: "USER" | "CREATOR" | "ADMIN" | null;
};

type SessionResponse = {
    session: SessionData | null;
};

type AuthStatusProps = {
    myPageColor?: string;
};

export default function AuthStatus({ myPageColor }: AuthStatusProps) {
    const [session, setSession] = useState<SessionData | null>(null);
    const [loaded, setLoaded] = useState(false);

    useEffect(() => {
        let cancelled = false;

        const loadSession = async () => {
            try {
                const response = await fetch("/api/auth/session", { cache: "no-store" });
                if (!response.ok) {
                    return;
                }
                const data = (await response.json()) as SessionResponse;
                if (!cancelled) {
                    setSession(data.session ?? null);
                }
            } finally {
                if (!cancelled) {
                    setLoaded(true);
                }
            }
        };

        loadSession();

        return () => {
            cancelled = true;
        };
    }, []);

    if (!loaded) {
        return null;
    }

    if (!session) {
        return (
            <a
                href="/api/auth/kakao"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: "#3A1D1D" }}
            >
                카카오 로그인
            </a>
        );
    }

    return (
        <div className="flex items-center gap-3">
            <span className="text-[13px] font-semibold" style={{ color: "#3A1D1D" }}>
                {session.nickname ?? "사용자"}
            </span>
            <Link
                href="/mypage"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: myPageColor ?? "#3A1D1D" }}
            >
                마이페이지
            </Link>
            <a
                href="/api/auth/logout"
                className="px-2 py-1 rounded-md text-[12px] font-semibold transition-opacity hover:opacity-70"
                style={{ border: "1px solid #3A1D1D", color: "#3A1D1D" }}
            >
                로그아웃
            </a>
        </div>
    );
}

'use client';

import { useEffect, useState, useCallback } from "react";
import Link from "next/link";
import Image from "next/image";

type SessionData = {
    dbId?: string | null;
    id?: string | null;
    name?: string | null;
    nickname?: string | null;
    image?: string | null;
    avatarUrl?: string | null;
    email?: string | null;
    role?: "USER" | "CREATOR" | "ADMIN" | null;
};

type SessionResponse = {
    session: SessionData | null;
};

type AuthStatusProps = {
    myPageColor?: string;
};

function getAvatarSrc(role: string | null | undefined, avatarUrl: string | null | undefined): string {
    // 커스텀 업로드 사진 (PRO 유저 - '/'로 시작하지 않는 data URL 등)
    if (avatarUrl && !avatarUrl.startsWith("/")) return avatarUrl;
    // 역할별 기본 이미지
    if (role === "CREATOR" || role === "ADMIN") return "/creator.png";
    return "/user.png";
}

export default function AuthStatus({ myPageColor }: AuthStatusProps) {
    const [session, setSession] = useState<SessionData | null>(null);
    const [loaded, setLoaded] = useState(false);

    const loadSession = useCallback(async () => {
        try {
            const response = await fetch("/api/auth/session", { cache: "no-store" });
            if (!response.ok) return;
            const data = (await response.json()) as SessionResponse;
            setSession(data.session ?? null);
        } finally {
            setLoaded(true);
        }
    }, []);

    useEffect(() => {
        loadSession();
    }, [loadSession]);

    // 프로필 사진 변경 또는 구독 해지 시 즉시 갱신
    useEffect(() => {
        const handler = () => { void loadSession(); };
        window.addEventListener("avatar-updated", handler);
        return () => window.removeEventListener("avatar-updated", handler);
    }, [loadSession]);

    if (!loaded) return null;

    if (!session) {
        return (
            <a
                href="/api/auth/kakao"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: "#3A1D1D" }}
            >
                카카오 로그인
            </a>
        );
    }

    const avatarSrc = getAvatarSrc(session.role, session.avatarUrl);

    return (
        <div className="flex items-center gap-3">
            <Link href="/mypage" className="shrink-0 transition-opacity hover:opacity-80">
                <Image
                    src={avatarSrc}
                    alt={session.nickname ?? "프로필"}
                    width={30}
                    height={30}
                    className="rounded-full object-cover"
                    style={{ width: 30, height: 30 }}
                    unoptimized={!!session.avatarUrl && !session.avatarUrl.startsWith("/")}
                />
            </Link>
            <span className="text-[13px] font-semibold" style={{ color: "#3A1D1D" }}>
                {session.nickname ?? "사용자"}
            </span>
            <Link
                href="/mypage"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: myPageColor ?? "#3A1D1D" }}
            >
                마이페이지
            </Link>
            <a
                href="/api/auth/logout"
                className="px-2 py-1 rounded-md text-[12px] font-semibold transition-opacity hover:opacity-70"
                style={{ border: "1px solid #3A1D1D", color: "#3A1D1D" }}
            >
                로그아웃
            </a>
        </div>
    );
}

"use client";

import Image from "next/image";
import Link from "next/link";
import AuthStatus from "./AuthStatus";
import NotificationBell from "./NotificationBell";
import LoginRequiredModal from "./LoginRequiredModal";
import { usePathname, useSearchParams } from "next/navigation";
import { useEffect, useState } from "react";

const BASE_NAV_ITEMS = [
    { href: "/store", label: "테마 스토어" },
    { href: "/gallery", label: "꾸미 갤러리" },
    { href: "/create", label: "새 테마 만들기" },
    { href: "/my-themes", label: "내 테마" },
    { href: "/pricing", label: "요금제" },
    { href: "/support", label: "고객센터" },
];

const CREATOR_APPLY = { href: "/mypage/creator-apply", label: "입점 신청" };
const THEME_REGISTER = { href: "/store/register", label: "테마 등록" };
const ADMIN_PAGE = { href: "/admin", label: "관리자페이지" };

function getNavItems(role: string | null) {
    if (role === "ADMIN") {
        return [
            BASE_NAV_ITEMS[0],
            BASE_NAV_ITEMS[1],
            BASE_NAV_ITEMS[2],
            BASE_NAV_ITEMS[3],
            CREATOR_APPLY,
            THEME_REGISTER,
            BASE_NAV_ITEMS[4],
            BASE_NAV_ITEMS[5],
            ADMIN_PAGE,
        ];
    }
    if (role === "CREATOR") {
        return [
            BASE_NAV_ITEMS[0],
            BASE_NAV_ITEMS[1],
            BASE_NAV_ITEMS[2],
            BASE_NAV_ITEMS[3],
            THEME_REGISTER,
            BASE_NAV_ITEMS[4],
            BASE_NAV_ITEMS[5],
        ];
    }
    // USER 또는 비로그인
    return [
        BASE_NAV_ITEMS[0],
        BASE_NAV_ITEMS[1],
        BASE_NAV_ITEMS[2],
        BASE_NAV_ITEMS[3],
        CREATOR_APPLY,
        BASE_NAV_ITEMS[4],
        BASE_NAV_ITEMS[5],
    ];
}

export default function Header() {
    const pathname = usePathname();
    const searchParams = useSearchParams();
    const isEditingTheme = pathname === "/create" && !!searchParams.get("id");

    const [role, setRole] = useState<string | null>(null);
    const [sessionLoaded, setSessionLoaded] = useState(false);
    const [loginModal, setLoginModal] = useState<string | null>(null);

    useEffect(() => {
        fetch("/api/auth/session", { cache: "no-store" })
            .then((r) => r.json())
            .then((d: { session?: { role?: string } | null }) => {
                setRole(d?.session?.role ?? null);
                setSessionLoaded(true);
            })
            .catch(() => { setSessionLoaded(true); });
    }, []);

    const NAV_ITEMS = getNavItems(role);

    // 로그인이 필요한 href 목록 (비로그인 상태에서만)
    const LOGIN_REQUIRED_HREFS: Record<string, string> = {
        "/create": "테마 만들기는 로그인이 필요한 기능이에요.",
        "/my-themes": "내 테마는 로그인이 필요한 기능이에요.",
        "/store/register": "테마 등록은 로그인이 필요한 기능이에요.",
        "/mypage/creator-apply": "입점 신청은 로그인이 필요한 기능이에요.",
    };

    const handleNavClick = (e: React.MouseEvent, href: string) => {
        if (!sessionLoaded) return;
        if (role === null && LOGIN_REQUIRED_HREFS[href]) {
            e.preventDefault();
            setLoginModal(LOGIN_REQUIRED_HREFS[href]);
        }
    };

    const isActive = (href: string) => {
        if (href === "/store") {
            return pathname === "/store" || (pathname.startsWith("/store") && pathname !== "/store/register" && !pathname.startsWith("/store/register"));
        }
        if (href === "/mypage") {
            return pathname === "/mypage" || pathname.startsWith("/mypage/");
        }
        return pathname === href || pathname.startsWith(href + "/");
    };

    return (
        <>
        <header
            className="sticky top-0 z-50 border-b border-black/[0.06] bg-[#f7f7f8]/95 px-6 backdrop-blur supports-[backdrop-filter]:bg-[#f7f7f8]/80"
            style={{
                boxShadow: "0 1px 0 rgba(255,255,255,0.7) inset",
            }}
        >
            <div className="mx-auto flex h-14 max-w-[1320px] items-center gap-8">
                <Link
                    href="/"
                    className="flex shrink-0 items-center transition-opacity duration-200 hover:opacity-80"
                    aria-label="카꾸미 홈"
                >
                    <Image src="/카꾸미.png" alt="카꾸미" width={110} height={44} quality={100} unoptimized style={{ objectFit: "contain" }} />
                </Link>

                <nav className="hidden items-center gap-1 md:flex">
                    {NAV_ITEMS.map(({ href, label }) => {
                        const active = isActive(href);
                        const isAdminLink = href === "/admin";

                        // /create 활성 상태일 때: 편집 중이면 "테마 편집하기"(클릭 불가), 아니면 "새 테마 만들기"(클릭 불가)
                        if (href === "/create" && active) {
                            const displayLabel = isEditingTheme ? "테마 편집하기" : label;
                            return (
                                <span
                                    key={href}
                                    className="rounded-lg px-3 py-2 text-[13px] cursor-default select-none"
                                    style={{ color: "#ff9500", fontWeight: 700 }}
                                >
                                    {displayLabel}
                                </span>
                            );
                        }

                        return (
                            <Link
                                key={href}
                                href={href}
                                onClick={(e) => handleNavClick(e, href)}
                                className="rounded-lg px-3 py-2 text-[13px] font-medium transition-colors duration-150"
                                style={{
                                    color: active ? "#ff9500" : isAdminLink ? "#ff3b30" : "#3a3a3c",
                                    background: "transparent",
                                    fontWeight: active ? 700 : isAdminLink ? 600 : 500,
                                }}
                            >
                                {label}
                            </Link>
                        );
                    })}
                </nav>

                <div className="ml-auto flex items-center gap-5">
                    {role && <NotificationBell />}
                    <AuthStatus myPageColor={isActive("/mypage") ? "#ff9500" : undefined} />
                </div>
            </div>
        </header>
        {loginModal && (
            <LoginRequiredModal message={loginModal} onClose={() => setLoginModal(null)} />
        )}
        </>
    );
}

