"use client";

import { useState, useEffect, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";

type Comment = {
    id: string; content: string; isDeleted: boolean; createdAt: string; parentId: string | null;
    userId: string; userNickname: string | null; userName: string;
    userAvatar: string | null; userImage: string | null;
    reportCount: number; myReported: boolean;
};
type PostDetail = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null; createdAt: string;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
    userRole: string;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function Avatar({ avatar, image, name, size = 32 }: { avatar: string | null; image: string | null; name: string; size?: number }) {
    const src = avatar ?? image ?? null;
    if (src) return <Image src={src} alt={name} width={size} height={size} className="rounded-full object-cover" style={{ width: size, height: size }} />;
    return (
        <div className="rounded-full flex items-center justify-center text-white font-bold"
            style={{ width: size, height: size, background: "linear-gradient(135deg,#FF9500,#FF6B00)", fontSize: size * 0.38 }}>
            {name.slice(0, 1)}
        </div>
    );
}

function Toast({ msg }: { msg: string }) {
    return (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-full text-[13px] font-medium shadow-lg"
            style={{ background: "#1c1917", color: "#fafaf9" }}>
            {msg}
        </div>
    );
}

// ── 댓글 아이템 ───────────────────────────────────
function CommentItem({
    comment, myId, isPostOwner, depth,
    onDelete, onReport, onReply,
    replies,
}: {
    comment: Comment; myId: string | null; isPostOwner: boolean; depth: number;
    onDelete: (id: string) => void;
    onReport: (id: string) => void;
    onReply: (parentId: string, parentName: string) => void;
    replies: Comment[];
}) {
    const name = comment.userNickname ?? comment.userName;
    const canDelete = myId === comment.userId || isPostOwner;
    const canReport = !!myId && myId !== comment.userId;

    return (
        <div>
            <div className="flex items-start gap-3 py-3.5" style={{
                borderBottom: depth === 0 && replies.length === 0 ? "1px solid #f5f5f4" : "none",
                paddingLeft: depth > 0 ? 40 : 0,
            }}>
                {comment.isDeleted ? (
                    <p className="text-[13px] py-1 ml-1" style={{ color: "#d6d3d1" }}>삭제된 댓글입니다.</p>
                ) : (
                    <>
                        {depth > 0 && (
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0 mt-1">
                                <path d="M9 18l6-6-6-6"/>
                            </svg>
                        )}
                        <Link href={`/creator/${comment.userId}`} className="shrink-0">
                            <Avatar avatar={comment.userAvatar} image={comment.userImage} name={name} role={comment.userRole} size={28} />
                        </Link>
                        <Avatar avatar={comment.userAvatar} image={comment.userImage} name={name} size={28} />
                                    {name}
                                </Link>
                                <span className="text-[11px]" style={{ color: "#d6d3d1" }}>{timeAgo(comment.createdAt)}</span>
                            </div>
                                <span className="text-[13px] font-semibold" style={{ color: "#1c1917" }}>{name}</span>
                                    className="mt-1.5 text-[11px] font-medium transition-opacity hover:opacity-60"
                                    style={{ color: "#a8a29e" }}>
                                    답글
                                </button>
                            )}
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                            {canDelete && (
                                <button onClick={() => onDelete(comment.id)}
                                    className="text-[11px] transition-opacity hover:opacity-60"
                                    style={{ color: "#d6d3d1" }}>삭제</button>
                            )}
                            {canReport && (
                                <button onClick={() => !comment.myReported && onReport(comment.id)}
                                    disabled={comment.myReported}
                                    className="text-[11px] transition-opacity hover:opacity-60 disabled:opacity-30"
                                    style={{ color: comment.myReported ? "#d6d3d1" : "#a8a29e" }}>
                                    {comment.myReported ? "신고됨" : "신고"}
                                </button>
                            )}
                        </div>
                    </>
                )}
            </div>

            {/* 대댓글 */}
            {replies.length > 0 && (
                <div style={{ borderBottom: "1px solid #f5f5f4" }}>
                    {replies.map((r) => (
                        <CommentItem key={r.id} comment={r} myId={myId} isPostOwner={isPostOwner}
                            depth={1} onDelete={onDelete} onReport={onReport} onReply={onReply} replies={[]} />
                    ))}
                </div>
            )}
        </div>
    );
}

// ── 메인 페이지 ──────────────────────────────────
export default function GalleryDetailPage() {
    const params = useParams<{ id: string }>();
    const router = useRouter();
    const postId = params.id;

    const [post, setPost] = useState<PostDetail | null>(null);
    const [comments, setComments] = useState<Comment[]>([]);
    const [loading, setLoading] = useState(true);
    const [myId, setMyId] = useState<string | null>(null);
    const [commentText, setCommentText] = useState("");
    const [submitting, setSubmitting] = useState(false);
    const [imgIndex, setImgIndex] = useState(0);
    const [toast, setToast] = useState<string | null>(null);

    // 대댓글 관련
    const [replyTo, setReplyTo] = useState<{ parentId: string; parentName: string } | null>(null);

    // 수정 관련
    const [editing, setEditing] = useState(false);
    const [editName, setEditName] = useState("");
    const [editDesc, setEditDesc] = useState("");
    const [editSaving, setEditSaving] = useState(false);

    const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(null), 2500); };

    useEffect(() => {
        fetch("/api/auth/session").then((r) => r.json()).then((d) => {
            if (d?.session) setMyId(d.session.dbId ?? null);
        }).catch(() => {});
    }, []);

    const fetchPost = useCallback(async () => {
        try {
            const res = await fetch(`/api/gallery/${postId}`);
            if (!res.ok) { router.replace("/gallery"); return; }
            const data = await res.json() as { post: PostDetail; comments: Comment[] };
            setPost(data.post);
            setComments(data.comments);
            setEditName(data.post.themeName);
            setEditDesc(data.post.description ?? "");
        } finally {
            setLoading(false);
        }
    }, [postId, router]);

    useEffect(() => { fetchPost(); }, [fetchPost]);

    const handleLike = async () => {
        if (!myId || !post) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPost((p) => p ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p);
    };

    const handleComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!commentText.trim() || !myId) return;
        setSubmitting(true);
        try {
            const body: { content: string; parentId?: string } = { content: commentText.trim() };
            if (replyTo) body.parentId = replyTo.parentId;
            const res = await fetch(`/api/gallery/${postId}/comments`, {
                method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body),
            });
            if (res.ok) {
                const data = await res.json() as { comment: Comment };
                setComments((prev) => [...prev, data.comment]);
                setCommentText("");
                setReplyTo(null);
            }
        } finally {
            setSubmitting(false);
        }
    };

    const handleDeleteComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "DELETE" });
        if (res.ok) setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, isDeleted: true } : c));
    };

    const handleReportComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "POST" });
        if (res.ok) {
            setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, myReported: true } : c));
            showToast("신고가 접수되었어요");
        } else {
            const d = await res.json() as { error?: string };
            showToast(d.error ?? "오류가 발생했습니다.");
        }
    };

    const handleDeletePost = async () => {
        if (!confirm("게시글을 삭제하시겠습니까?")) return;
        const res = await fetch(`/api/gallery/${postId}`, { method: "DELETE" });
        if (res.ok) router.replace("/gallery");
    };

    const handleSaveEdit = async () => {
        if (!editName.trim()) return;
        setEditSaving(true);
        try {
            const res = await fetch(`/api/gallery/${postId}`, {
                method: "PATCH", headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ themeName: editName.trim(), description: editDesc.trim() }),
            });
            if (res.ok) {
                setPost((p) => p ? { ...p, themeName: editName.trim(), description: editDesc.trim() || null } : p);
                setEditing(false);
                showToast("수정됐어요");
            }
        } finally {
            setEditSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
                <Header />
                <div className="flex-1 flex items-center justify-center">
                    <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                </div>
            </div>
        );
    }
    if (!post) return null;

    const displayName = post.userNickname ?? post.userName;
    const isOwner = myId === post.userId;

    // 댓글 트리 구성 (최상위 댓글만, 대댓글은 replies로)
    const topComments = comments.filter((c) => !c.parentId);
    const getReplies = (parentId: string) => comments.filter((c) => c.parentId === parentId);
    const visibleCount = comments.filter((c) => !c.isDeleted).length;

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[720px] mx-auto w-full px-5 pt-12 pb-24">

                {/* 뒤로 */}
                <button onClick={() => router.back()}
                    className="flex items-center gap-1.5 text-[13px] mb-8 transition-opacity hover:opacity-60"
                    style={{ color: "#a8a29e" }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5"/><path d="M12 19l-7-7 7-7"/>
                    </svg>
                    갤러리
                </button>

                {/* 작성자 + 수정/삭제 */}
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                        <Link href={`/creator/${post.userId}`}>
                            <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} role={post.userRole} size={40} />
                        </Link>
                        <div>
                            <Link href={`/creator/${post.userId}`} className="text-[14px] font-semibold hover:underline" style={{ color: "#1c1917" }}>
                                {displayName}
                            </Link>
                            <p className="text-[12px]" style={{ color: "#a8a29e" }}>{timeAgo(post.createdAt)}</p>
                        </div>
                    </div>
                        <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} size={40} />
                                className="text-[12px] font-medium transition-opacity hover:opacity-60"
                                style={{ color: "#a8a29e" }}>
                            <p className="text-[14px] font-semibold" style={{ color: "#1c1917" }}>{displayName}</p>
                                style={{ color: "#FF3B30" }}>
                                삭제
                            </button>
                        </div>
                    )}
                </div>

                {/* 이미지 슬라이더 */}
                <div className="relative rounded-2xl overflow-hidden mb-6" style={{ background: "#e7e5e4" }}>
                    <div className="relative w-full" style={{ paddingBottom: "75%" }}>
                        <Image src={post.images[imgIndex]} alt={post.themeName} fill className="object-cover" />
                    </div>
                    {post.images.length > 1 && (
                        <>
                            {imgIndex > 0 && (
                                <button onClick={() => setImgIndex((v) => v - 1)}
                                    className="absolute left-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M15 18l-6-6 6-6"/></svg>
                                </button>
                            )}
                            {imgIndex < post.images.length - 1 && (
                                <button onClick={() => setImgIndex((v) => v + 1)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                </button>
                            )}
                            <div className="absolute bottom-3 left-1/2 -translate-x-1/2 flex gap-1.5">
                                {post.images.map((_, i) => (
                                    <button key={i} onClick={() => setImgIndex(i)}
                                        className="rounded-full transition-all"
                                        style={{ width: i === imgIndex ? 16 : 6, height: 6, background: i === imgIndex ? "#fff" : "rgba(255,255,255,0.5)" }} />
                                ))}
                            </div>
                        </>
                    )}
                </div>

                {/* 제목 + 설명 (수정 모드) */}
                <div className="mb-6" style={{ borderBottom: "1px solid #e7e5e4", paddingBottom: 20 }}>
                    {editing ? (
                        <div className="flex flex-col gap-4">
                            <input value={editName} onChange={(e) => setEditName(e.target.value)} maxLength={50}
                                className="text-[20px] font-bold outline-none bg-transparent w-full"
                                style={{ color: "#1c1917", borderBottom: "1.5px solid rgb(74,123,247)", paddingBottom: 6 }} />
                            <div className="flex flex-col gap-1">
                                <textarea value={editDesc} onChange={(e) => setEditDesc(e.target.value)} maxLength={200} rows={3}
                                    placeholder="소개 (선택)"
                                    className="text-[14px] outline-none bg-transparent resize-none leading-relaxed w-full placeholder:text-[#d6d3d1]"
                                    style={{ color: "#78716c", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }} />
                                <span className="text-[11px] text-right" style={{ color: "#d6d3d1" }}>{editDesc.length}/200</span>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => setEditing(false)}
                                    className="px-4 py-2 rounded-full text-[13px] transition-opacity hover:opacity-60"
                                    style={{ background: "rgba(0,0,0,0.05)", color: "#78716c" }}>취소</button>
                                <button onClick={handleSaveEdit} disabled={editSaving || !editName.trim()}
                                    className="px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {editSaving ? "저장 중…" : "저장"}
                                </button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <h1 className="text-[22px] font-bold tracking-tight mb-2" style={{ color: "#1c1917" }}>{post.themeName}</h1>
                            {post.description && <p className="text-[14px] leading-relaxed" style={{ color: "#78716c" }}>{post.description}</p>}
                            {(post.themeId || post.storeLink) && (
                                <Link href={post.themeId ? `/store/${post.themeId}` : (post.storeLink ?? "#")}
                                    className="inline-flex items-center gap-1.5 mt-3 text-[13px] font-medium transition-opacity hover:opacity-70"
                                    style={{ color: "rgb(74,123,247)" }}>
                                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/>
                                        <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/>
                                    </svg>
                                    스토어에서 보기
                                </Link>
                            )}
                        </>
                    )}
                </div>

                {/* 좋아요 (하트만) */}
                <div className="flex items-center gap-3 mb-8">
                    <button onClick={handleLike}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-full text-[13px] font-medium transition-all"
                        style={{
                            background: post.liked ? "rgba(255,59,48,0.08)" : "rgba(0,0,0,0.04)",
                            color: post.liked ? "#FF3B30" : "#78716c",
                        }}>
                        <svg width="14" height="14" viewBox="0 0 24 24"
                            fill={post.liked ? "currentColor" : "none"}
                            stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                        </svg>
                        좋아요 {post.likeCount}
                    </button>
                </div>

                {/* 댓글 */}
                <div style={{ borderTop: "1px solid #e7e5e4" }}>
                    <p className="text-[11px] font-semibold tracking-wide uppercase py-4" style={{ color: "#a8a29e" }}>
                        댓글 {visibleCount}
                    </p>

                    {topComments.map((c) => (
                        <CommentItem
                            key={c.id}
                            comment={c}
                            myId={myId}
                            isPostOwner={isOwner}
                            depth={0}
                            onDelete={handleDeleteComment}
                            onReport={handleReportComment}
                            onReply={(parentId, parentName) => {
                                setReplyTo({ parentId, parentName });
                                setTimeout(() => document.getElementById("comment-input")?.focus(), 50);
                            }}
                            replies={getReplies(c.id)}
                        />
                    ))}

                    {/* 댓글 입력 */}
                    {myId ? (
                        <form onSubmit={handleComment} className="flex flex-col gap-2 pt-5">
                            {/* 답글 대상 표시 */}
                            {replyTo && (
                                <div className="flex items-center gap-2 px-3 py-2 rounded-lg"
                                    style={{ background: "rgba(74,123,247,0.06)" }}>
                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="rgb(74,123,247)" strokeWidth="2" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                    <span className="text-[12px]" style={{ color: "rgb(74,123,247)" }}>
                                        <b>{replyTo.parentName}</b>에게 답글
                                    </span>
                                    <button type="button" onClick={() => setReplyTo(null)} className="ml-auto transition-opacity hover:opacity-60">
                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="2.5" strokeLinecap="round"><path d="M18 6L6 18M6 6l12 12"/></svg>
                                    </button>
                                </div>
                            )}
                            <div className="flex items-end gap-3">
                                <textarea
                                    id="comment-input"
                                    value={commentText}
                                    onChange={(e) => setCommentText(e.target.value)}
                                    placeholder={replyTo ? `${replyTo.parentName}에게 답글 달기…` : "댓글을 입력하세요…"}
                                    rows={2} maxLength={200}
                                    className="flex-1 text-[14px] outline-none bg-transparent resize-none leading-relaxed placeholder:text-[#d6d3d1]"
                                    style={{ color: "#1c1917", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }}
                                    onKeyDown={(e) => {
                                        if (e.key === "Enter" && !e.shiftKey) {
                                            e.preventDefault();
                                            if (commentText.trim()) handleComment(e as unknown as React.FormEvent);
                                        }
                                    }}
                                />
                                <button type="submit" disabled={submitting || !commentText.trim()}
                                    className="shrink-0 px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {submitting ? "…" : "등록"}
                                </button>
                            </div>
                        </form>
                    ) : (
                        <p className="text-[13px] py-4" style={{ color: "#a8a29e" }}>
                            <Link href="/api/auth/kakao" className="underline hover:opacity-70">로그인</Link> 후 댓글을 작성할 수 있어요.
                        </p>
                    )}
                </div>
            </div>

            {toast && <Toast msg={toast} />}
            <Footer />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";

type Comment = {
    id: string; content: string; isDeleted: boolean; createdAt: string; parentId: string | null;
    userId: string; userNickname: string | null; userName: string;
    userAvatar: string | null; userImage: string | null; userRole: string;
    reportCount: number; myReported: boolean;
};
type PostDetail = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null; createdAt: string;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
    userRole: string;
    likeCount: number; commentCount: number; liked: boolean;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function getAvatarSrc(role: string, avatarUrl: string | null): string {
    // 커스텀 업로드 사진 (PRO 유저 - '/'로 시작하지 않는 data URL 등)
    if (avatarUrl && !avatarUrl.startsWith("/")) return avatarUrl;
    // 역할별 기본 이미지
    if (role === "CREATOR" || role === "ADMIN") return "/creator.png";
    return "/user.png";
}

function Avatar({ avatar, name, role, size = 32 }: { avatar: string | null; image?: string | null; name: string; role: string; size?: number }) {
    const src = getAvatarSrc(role, avatar);
    return (
        <Image
            src={src} alt={name} width={size} height={size}
            className="rounded-full object-cover"
            style={{ width: size, height: size }}
            unoptimized={!!avatar && !avatar.startsWith("/")}
        />
    );
}

function Toast({ msg }: { msg: string }) {
    return (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-full text-[13px] font-medium shadow-lg"
            style={{ background: "#1c1917", color: "#fafaf9" }}>
            {msg}
        </div>
    );
}

// ── 댓글 아이템 ───────────────────────────────────
function CommentItem({
    comment, myId, isPostOwner, depth,
    onDelete, onReport, onReply,
    replies,
}: {
    comment: Comment; myId: string | null; isPostOwner: boolean; depth: number;
    onDelete: (id: string) => void;
    onReport: (id: string) => void;
    onReply: (parentId: string, parentName: string) => void;
    replies: Comment[];
}) {
    const name = comment.userNickname ?? comment.userName;
    const canDelete = myId === comment.userId || isPostOwner;
    const canReport = !!myId && myId !== comment.userId;

    return (
        <div>
            <div className="flex items-start gap-3 py-3.5" style={{
                borderBottom: depth === 0 && replies.length === 0 ? "1px solid #f5f5f4" : "none",
                paddingLeft: depth > 0 ? 40 : 0,
            }}>
                {comment.isDeleted ? (
                    <p className="text-[13px] py-1 ml-1" style={{ color: "#d6d3d1" }}>삭제된 댓글입니다.</p>
                ) : (
                    <>
                        {depth > 0 && (
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0 mt-1">
                                <path d="M9 18l6-6-6-6"/>
                            </svg>
                        )}
                        <Link href={`/creator/${comment.userId}`} className="shrink-0">
                            <Avatar avatar={comment.userAvatar} image={comment.userImage} name={name} role={comment.userRole} size={28} />
                        </Link>
                        <div className="flex-1 min-w-0">
                            <div className="flex items-baseline gap-2 mb-0.5">
                                <Link href={`/creator/${comment.userId}`} className="text-[13px] font-semibold hover:underline" style={{ color: "#1c1917" }}>
                                    {name}
                                </Link>
                                <span className="text-[11px]" style={{ color: "#d6d3d1" }}>{timeAgo(comment.createdAt)}</span>
                            </div>
                            <p className="text-[13px] leading-relaxed" style={{ color: "#78716c" }}>{comment.content}</p>
                            {/* 답글 버튼 (depth 0만) */}
                            {myId && depth === 0 && (
                                <button onClick={() => onReply(comment.id, name)}
                                    className="mt-1.5 text-[11px] font-medium transition-opacity hover:opacity-60"
                                    style={{ color: "#a8a29e" }}>
                                    답글
                                </button>
                            )}
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                            {canDelete && (
                                <button onClick={() => onDelete(comment.id)}
                                    className="text-[11px] transition-opacity hover:opacity-60"
                                    style={{ color: "#d6d3d1" }}>삭제</button>
                            )}
                            {canReport && (
                                <button onClick={() => !comment.myReported && onReport(comment.id)}
                                    disabled={comment.myReported}
                                    className="text-[11px] transition-opacity hover:opacity-60 disabled:opacity-30"
                                    style={{ color: comment.myReported ? "#d6d3d1" : "#a8a29e" }}>
                                    {comment.myReported ? "신고됨" : "신고"}
                                </button>
                            )}
                        </div>
                    </>
                )}
            </div>

            {/* 대댓글 */}
            {replies.length > 0 && (
                <div style={{ borderBottom: "1px solid #f5f5f4" }}>
                    {replies.map((r) => (
                        <CommentItem key={r.id} comment={r} myId={myId} isPostOwner={isPostOwner}
                            depth={1} onDelete={onDelete} onReport={onReport} onReply={onReply} replies={[]} />
                    ))}
                </div>
            )}
        </div>
    );
}

// ── 메인 페이지 ──────────────────────────────────
export default function GalleryDetailPage() {
    const params = useParams<{ id: string }>();
    const router = useRouter();
    const postId = params.id;

    const [post, setPost] = useState<PostDetail | null>(null);
    const [comments, setComments] = useState<Comment[]>([]);
    const [loading, setLoading] = useState(true);
    const [myId, setMyId] = useState<string | null>(null);
    const [commentText, setCommentText] = useState("");
    const [submitting, setSubmitting] = useState(false);
    const [imgIndex, setImgIndex] = useState(0);
    const [toast, setToast] = useState<string | null>(null);

    // 대댓글 관련
    const [replyTo, setReplyTo] = useState<{ parentId: string; parentName: string } | null>(null);

    // 수정 관련
    const [editing, setEditing] = useState(false);
    const [editName, setEditName] = useState("");
    const [editDesc, setEditDesc] = useState("");
    const [editSaving, setEditSaving] = useState(false);

    const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(null), 2500); };

    useEffect(() => {
        fetch("/api/auth/session").then((r) => r.json()).then((d) => {
            if (d?.session) setMyId(d.session.dbId ?? null);
        }).catch(() => {});
    }, []);

    const fetchPost = useCallback(async () => {
        try {
            const res = await fetch(`/api/gallery/${postId}`);
            if (!res.ok) { router.replace("/gallery"); return; }
            const data = await res.json() as { post: PostDetail; comments: Comment[] };
            setPost(data.post);
            setComments(data.comments);
            setEditName(data.post.themeName);
            setEditDesc(data.post.description ?? "");
        } finally {
            setLoading(false);
        }
    }, [postId, router]);

    useEffect(() => { fetchPost(); }, [fetchPost]);

    const handleLike = async () => {
        if (!myId || !post) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPost((p) => p ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p);
    };

    const handleComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!commentText.trim() || !myId) return;
        setSubmitting(true);
        try {
            const body: { content: string; parentId?: string } = { content: commentText.trim() };
            if (replyTo) body.parentId = replyTo.parentId;
            const res = await fetch(`/api/gallery/${postId}/comments`, {
                method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body),
            });
            if (res.ok) {
                const data = await res.json() as { comment: Comment };
                setComments((prev) => [...prev, data.comment]);
                setCommentText("");
                setReplyTo(null);
            }
        } finally {
            setSubmitting(false);
        }
    };

    const handleDeleteComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "DELETE" });
        if (res.ok) setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, isDeleted: true } : c));
    };

    const handleReportComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "POST" });
        if (res.ok) {
            setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, myReported: true } : c));
            showToast("신고가 접수되었어요");
        } else {
            const d = await res.json() as { error?: string };
            showToast(d.error ?? "오류가 발생했습니다.");
        }
    };

    const handleDeletePost = async () => {
        if (!confirm("게시글을 삭제하시겠습니까?")) return;
        const res = await fetch(`/api/gallery/${postId}`, { method: "DELETE" });
        if (res.ok) router.replace("/gallery");
    };

    const handleSaveEdit = async () => {
        if (!editName.trim()) return;
        setEditSaving(true);
        try {
            const res = await fetch(`/api/gallery/${postId}`, {
                method: "PATCH", headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ themeName: editName.trim(), description: editDesc.trim() }),
            });
            if (res.ok) {
                setPost((p) => p ? { ...p, themeName: editName.trim(), description: editDesc.trim() || null } : p);
                setEditing(false);
                showToast("수정됐어요");
            }
        } finally {
            setEditSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
                <Header />
                <div className="flex-1 flex items-center justify-center">
                    <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                </div>
            </div>
        );
    }
    if (!post) return null;

    const displayName = post.userNickname ?? post.userName;
    const isOwner = myId === post.userId;

    // 댓글 트리 구성 (최상위 댓글만, 대댓글은 replies로)
    const topComments = comments.filter((c) => !c.parentId);
    const getReplies = (parentId: string) => comments.filter((c) => c.parentId === parentId);
    const visibleCount = comments.filter((c) => !c.isDeleted).length;

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[720px] mx-auto w-full px-5 pt-12 pb-24">

                {/* 뒤로 */}
                <button onClick={() => router.back()}
                    className="flex items-center gap-1.5 text-[13px] mb-8 transition-opacity hover:opacity-60"
                    style={{ color: "#a8a29e" }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5"/><path d="M12 19l-7-7 7-7"/>
                    </svg>
                    갤러리
                </button>

                {/* 작성자 + 수정/삭제 */}
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                        <Link href={`/creator/${post.userId}`}>
                            <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} role={post.userRole} size={40} />
                        </Link>
                        <div>
                            <Link href={`/creator/${post.userId}`} className="text-[14px] font-semibold hover:underline" style={{ color: "#1c1917" }}>
                                {displayName}
                            </Link>
                            <p className="text-[12px]" style={{ color: "#a8a29e" }}>{timeAgo(post.createdAt)}</p>
                        </div>
                    </div>
                    {isOwner && (
                        <div className="flex items-center gap-3">
                            <button onClick={() => { setEditing(true); setEditName(post.themeName); setEditDesc(post.description ?? ""); }}
                                className="text-[12px] font-medium transition-opacity hover:opacity-60"
                                style={{ color: "#a8a29e" }}>
                                수정
                            </button>
                            <button onClick={handleDeletePost}
                                className="text-[12px] transition-opacity hover:opacity-60"
                                style={{ color: "#FF3B30" }}>
                                삭제
                            </button>
                        </div>
                    )}
                </div>

                {/* 이미지 슬라이더 */}
                <div className="relative rounded-2xl overflow-hidden mb-6" style={{ background: "#e7e5e4" }}>
                    <div className="relative w-full" style={{ paddingBottom: "75%" }}>
                        <Image src={post.images[imgIndex]} alt={post.themeName} fill className="object-cover" />
                    </div>
                    {post.images.length > 1 && (
                        <>
                            {imgIndex > 0 && (
                                <button onClick={() => setImgIndex((v) => v - 1)}
                                    className="absolute left-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M15 18l-6-6 6-6"/></svg>
                                </button>
                            )}
                            {imgIndex < post.images.length - 1 && (
                                <button onClick={() => setImgIndex((v) => v + 1)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                </button>
                            )}
                            <div className="absolute bottom-3 left-1/2 -translate-x-1/2 flex gap-1.5">
                                {post.images.map((_, i) => (
                                    <button key={i} onClick={() => setImgIndex(i)}
                                        className="rounded-full transition-all"
                                        style={{ width: i === imgIndex ? 16 : 6, height: 6, background: i === imgIndex ? "#fff" : "rgba(255,255,255,0.5)" }} />
                                ))}
                            </div>
                        </>
                    )}
                </div>

                {/* 제목 + 설명 (수정 모드) */}
                <div className="mb-6" style={{ borderBottom: "1px solid #e7e5e4", paddingBottom: 20 }}>
                    {editing ? (
                        <div className="flex flex-col gap-4">
                            <input value={editName} onChange={(e) => setEditName(e.target.value)} maxLength={50}
                                className="text-[20px] font-bold outline-none bg-transparent w-full"
                                style={{ color: "#1c1917", borderBottom: "1.5px solid rgb(74,123,247)", paddingBottom: 6 }} />
                            <div className="flex flex-col gap-1">
                                <textarea value={editDesc} onChange={(e) => setEditDesc(e.target.value)} maxLength={200} rows={3}
                                    placeholder="소개 (선택)"
                                    className="text-[14px] outline-none bg-transparent resize-none leading-relaxed w-full placeholder:text-[#d6d3d1]"
                                    style={{ color: "#78716c", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }} />
                                <span className="text-[11px] text-right" style={{ color: "#d6d3d1" }}>{editDesc.length}/200</span>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => setEditing(false)}
                                    className="px-4 py-2 rounded-full text-[13px] transition-opacity hover:opacity-60"
                                    style={{ background: "rgba(0,0,0,0.05)", color: "#78716c" }}>취소</button>
                                <button onClick={handleSaveEdit} disabled={editSaving || !editName.trim()}
                                    className="px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {editSaving ? "저장 중…" : "저장"}
                                </button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <h1 className="text-[22px] font-bold tracking-tight mb-2" style={{ color: "#1c1917" }}>{post.themeName}</h1>
                            {post.description && <p className="text-[14px] leading-relaxed" style={{ color: "#78716c" }}>{post.description}</p>}
                            {(post.themeId || post.storeLink) && (
                                <Link href={post.themeId ? `/store/${post.themeId}` : (post.storeLink ?? "#")}
                                    className="inline-flex items-center gap-1.5 mt-3 text-[13px] font-medium transition-opacity hover:opacity-70"
                                    style={{ color: "rgb(74,123,247)" }}>
                                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/>
                                        <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/>
                                    </svg>
                                    스토어에서 보기
                                </Link>
                            )}
                        </>
                    )}
                </div>

                {/* 좋아요 (하트만) */}
                <div className="flex items-center gap-3 mb-8">
                    <button onClick={handleLike}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-full text-[13px] font-medium transition-all"
                        style={{
                            background: post.liked ? "rgba(255,59,48,0.08)" : "rgba(0,0,0,0.04)",
                            color: post.liked ? "#FF3B30" : "#78716c",
                        }}>
                        <svg width="14" height="14" viewBox="0 0 24 24"
                            fill={post.liked ? "currentColor" : "none"}
                            stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                        </svg>
                        좋아요 {post.likeCount}
                    </button>
                </div>

                {/* 댓글 */}
                <div style={{ borderTop: "1px solid #e7e5e4" }}>
                    <p className="text-[11px] font-semibold tracking-wide uppercase py-4" style={{ color: "#a8a29e" }}>
                        댓글 {visibleCount}
                    </p>

                    {topComments.map((c) => (
                        <CommentItem
                            key={c.id}
                            comment={c}
                            myId={myId}
                            isPostOwner={isOwner}
                            depth={0}
                            onDelete={handleDeleteComment}
                            onReport={handleReportComment}
                            onReply={(parentId, parentName) => {
                                setReplyTo({ parentId, parentName });
                                setTimeout(() => document.getElementById("comment-input")?.focus(), 50);
                            }}
                            replies={getReplies(c.id)}
                        />
                    ))}

                    {/* 댓글 입력 */}
                    {myId ? (
                        <form onSubmit={handleComment} className="flex flex-col gap-2 pt-5">
                            {/* 답글 대상 표시 */}
                            {replyTo && (
                                <div className="flex items-center gap-2 px-3 py-2 rounded-lg"
                                    style={{ background: "rgba(74,123,247,0.06)" }}>
                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="rgb(74,123,247)" strokeWidth="2" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                    <span className="text-[12px]" style={{ color: "rgb(74,123,247)" }}>
                                        <b>{replyTo.parentName}</b>에게 답글
                                    </span>
                                    <button type="button" onClick={() => setReplyTo(null)} className="ml-auto transition-opacity hover:opacity-60">
                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="2.5" strokeLinecap="round"><path d="M18 6L6 18M6 6l12 12"/></svg>
                                    </button>
                                </div>
                            )}
                            <div className="flex items-end gap-3">
                                <textarea
                                    id="comment-input"
                                    value={commentText}
                                    onChange={(e) => setCommentText(e.target.value)}
                                    placeholder={replyTo ? `${replyTo.parentName}에게 답글 달기…` : "댓글을 입력하세요…"}
                                    rows={2} maxLength={200}
                                    className="flex-1 text-[14px] outline-none bg-transparent resize-none leading-relaxed placeholder:text-[#d6d3d1]"
                                    style={{ color: "#1c1917", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }}
                                    onKeyDown={(e) => {
                                        if (e.key === "Enter" && !e.shiftKey) {
                                            e.preventDefault();
                                            if (commentText.trim()) handleComment(e as unknown as React.FormEvent);
                                        }
                                    }}
                                />
                                <button type="submit" disabled={submitting || !commentText.trim()}
                                    className="shrink-0 px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {submitting ? "…" : "등록"}
                                </button>
                            </div>
                        </form>
                    ) : (
                        <p className="text-[13px] py-4" style={{ color: "#a8a29e" }}>
                            <Link href="/api/auth/kakao" className="underline hover:opacity-70">로그인</Link> 후 댓글을 작성할 수 있어요.
                        </p>
                    )}
                </div>
            </div>

            {toast && <Toast msg={toast} />}
            <Footer />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";

// ── 타입 ──────────────────────────────────────────
type GalleryPost = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null;
    createdAt: string; liked: boolean; likeCount: number; commentCount: number;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function Avatar({ avatar, image, name, size = 32 }: { avatar: string | null; image: string | null; name: string; size?: number }) {
    const src = avatar ?? image ?? null;
    if (src) return <Image src={src} alt={name} width={size} height={size} className="rounded-full object-cover" style={{ width: size, height: size }} />;
            src={fallbackSrc} alt={name} width={size} height={size}
            className="rounded-full object-cover"
            style={{ width: size, height: size, cursor: onClick ? "pointer" : "default" }}
            onClick={onClick}
        />
    );
}

// ── 게시글 카드 ──────────────────────────────────
function PostCard({ post, myId, onLike, onNavigate }: {
    post: GalleryPost; myId: string | null;
    onLike: (id: string) => void;
    onNavigate: (id: string) => void;
}) {
    const displayName = post.userNickname ?? post.userName;

    return (
        <div
        <div className="rounded-full flex items-center justify-center text-white font-bold"
            style={{ width: size, height: size, background: "linear-gradient(135deg,#FF9500,#FF6B00)", fontSize: size * 0.38 }}>
            {name.slice(0, 1)}
        </div>
                {post.images[0] && (
function PostCard({ post, myId, onLike }: {
                )}
                {post.images.length > 1 && (
                        style={{ background: "rgba(0,0,0,0.45)" }}>
        <Link href={`/gallery/${post.id}`} className="block group">
            <div className="rounded-2xl overflow-hidden transition-all duration-200 hover:shadow-md"
                style={{ background: "#fff", border: "1px solid rgba(0,0,0,0.06)" }}>
                {/* 이미지 */}
                <div className="relative w-full" style={{ paddingBottom: "100%", background: "#f5f5f5" }}>
                    {post.images[0] && (
                        <Image src={post.images[0]} alt={post.themeName} fill className="object-cover" />
                    )}
                    {post.images.length > 1 && (
                        <div className="absolute top-2 right-2 w-5 h-5 rounded-full flex items-center justify-center"
                            style={{ background: "rgba(0,0,0,0.45)" }}>
                            <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/>
                            </svg>
                        </div>
                    )}
                </div>
                </div>
                {/* 좋아요 + 댓글 */}
                {/* 하단 정보 */}
                <div className="px-3 py-2.5 flex items-center justify-between gap-2">
                    {/* 프사 + 닉네임 + 시간 */}
                    <div className="flex items-center gap-2 min-w-0">
                        <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} size={22} />
                        <span className="text-[12px] font-medium truncate" style={{ color: "#78716c" }}>{displayName}</span>
                        <span className="text-[11px] shrink-0" style={{ color: "#d6d3d1" }}>{timeAgo(post.createdAt)}</span>
                    </div>
                    {/* 좋아요 + 댓글 */}
                    <div className="flex items-center gap-2.5 shrink-0">
                        <button
                            onClick={(e) => { e.preventDefault(); if (myId) onLike(post.id); }}
                            className="flex items-center gap-0.5 transition-opacity hover:opacity-60"
                            style={{ color: post.liked ? "#FF3B30" : "#c8c4c0" }}>
                            <svg width="13" height="13" viewBox="0 0 24 24" fill={post.liked ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                            </svg>
                            <span className="text-[11px]">{post.likeCount}</span>
                        </button>
                        <div className="flex items-center gap-0.5" style={{ color: "#c8c4c0" }}>
                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
                            </svg>
                            <span className="text-[11px]">{post.commentCount}</span>
                        </div>
                    </div>
                </div>
            </div>
        </Link>
        } finally {
            setLoading(false);
        }
    }, [sort]);

    useEffect(() => {
        setPage(1);
        fetchPosts(1, sort);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [sort]);

    const handleLike = async (postId: string) => {
        if (!myId) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPosts((prev) => prev.map((p) =>
            p.id === postId ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p
        ));
    };

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[1200px] mx-auto w-full px-5 pt-12 pb-24">
                {/* 헤더 */}
                <div className="flex items-end justify-between mb-10">
                    <div>
                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-2" style={{ color: "#a8a29e" }}>Gallery</p>
                        <h1 className="text-[28px] font-bold tracking-tight" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>꾸미 갤러리</h1>
                        <p className="text-[14px] mt-1" style={{ color: "#78716c" }}>카꾸미로 만든 테마를 소개해보세요!</p>
                    </div>
                    {isLoggedIn && (
                        <button
                            onClick={() => router.push("/gallery/new")}
                            className="flex items-center gap-1.5 px-5 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70"
                            style={{ background: "#1c1917", color: "#fafaf9" }}>
                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
                            테마 소개하기
                        </button>
                    )}
                </div>

                {/* 정렬 탭 */}
                <div className="flex items-center gap-1.5 mb-8">
                    {(["latest", "likes"] as const).map((s) => (
                        <button key={s} onClick={() => setSort(s)}
                            className="px-4 py-1.5 rounded-full text-[13px] font-medium transition-all duration-150"
                            style={{
                                backgroundColor: sort === s ? "rgb(74,123,247)" : "transparent",
                                color: sort === s ? "#fff" : "#78716c",
                                border: `1px solid ${sort === s ? "rgb(74,123,247)" : "#e7e5e4"}`,
                            }}>
                            {s === "latest" ? "최신순" : "좋아요순"}
                        </button>
                    ))}
                </div>

                {/* 그리드 */}
                {loading && posts.length === 0 ? (
                    <div className="flex justify-center items-center py-32">
                        <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                    </div>
                ) : posts.length === 0 ? (
                    <div className="flex flex-col items-center gap-4 py-32">
                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/>
                        </svg>
                        <p className="text-[14px]" style={{ color: "#a8a29e" }}>아직 게시글이 없어요. 첫 번째로 소개해보세요!</p>
                    </div>
                ) : (
                    <div className="grid gap-4" style={{ gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))" }}>
                        {posts.map((post) => (
                            <PostCard key={post.id} post={post} myId={myId} onLike={handleLike} />
                            <PostCard key={post.id} post={post} myId={myId} onLike={handleLike} onNavigate={(id) => router.push(`/gallery/${id}`)} />
                        ))}
                    </div>
                )}

                {/* 더보기 */}
                {posts.length < total && !loading && (
                    <div className="flex justify-center mt-10">
                        <button onClick={() => { const next = page + 1; setPage(next); fetchPosts(next); }}
                            className="px-6 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-60"
                            style={{ border: "1px solid #e7e5e4", color: "#78716c" }}>
                            더 보기
                        </button>
                    </div>
                )}
            </div>
            <Footer />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";

// ── 타입 ──────────────────────────────────────────
type GalleryPost = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null;
    createdAt: string; liked: boolean; likeCount: number; commentCount: number;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
    userRole: string;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function getAvatarSrc(role: string, avatarUrl: string | null): string {
    // 커스텀 업로드 사진 (PRO 유저 - '/'로 시작하지 않는 data URL 등)
    if (avatarUrl && !avatarUrl.startsWith("/")) return avatarUrl;
    // 역할별 기본 이미지
    if (role === "CREATOR" || role === "ADMIN") return "/creator.png";
    return "/user.png";
}

function Avatar({ avatar, name, role, size = 32, onClick }: { avatar: string | null; image?: string | null; name: string; role: string; size?: number; onClick?: (e: React.MouseEvent) => void }) {
    const src = getAvatarSrc(role, avatar);
    return (
        <Image
            src={src} alt={name} width={size} height={size}
            className="rounded-full object-cover"
            style={{ width: size, height: size, cursor: onClick ? "pointer" : "default" }}
            onClick={onClick}
            unoptimized={!!avatar && !avatar.startsWith("/")}
        />
    );
}

// ── 게시글 카드 ──────────────────────────────────
function PostCard({ post, myId, onLike, onNavigate }: {
    post: GalleryPost; myId: string | null;
    onLike: (id: string) => void;
    onNavigate: (id: string) => void;
}) {
    const displayName = post.userNickname ?? post.userName;

    return (
        <div
            className="group rounded-2xl overflow-hidden transition-all duration-200 hover:shadow-md cursor-pointer"
            style={{ background: "#fff", border: "1px solid rgba(0,0,0,0.06)" }}
            onClick={() => onNavigate(post.id)}
        >
            {/* 이미지 */}
            <div className="relative w-full" style={{ paddingBottom: "100%", background: "#f5f5f5" }}>
                {post.images[0] && (
                    <Image src={post.images[0]} alt={post.themeName} fill className="object-cover" />
                )}
                {post.images.length > 1 && (
                    <div className="absolute top-2 right-2 w-5 h-5 rounded-full flex items-center justify-center"
                        style={{ background: "rgba(0,0,0,0.45)" }}>
                        <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/>
                        </svg>
                    </div>
                )}
            </div>

            {/* 하단 정보 */}
            <div className="px-3 py-2.5 flex items-center justify-between gap-2">
                {/* 프사 + 닉네임 + 시간 */}
                <div className="flex items-center gap-2 min-w-0">
                    <Link href={`/creator/${post.userId}`} onClick={(e) => e.stopPropagation()} className="shrink-0">
                        <Avatar avatar={post.userAvatar} name={displayName} role={post.userRole} size={22} />
                    </Link>
                    <Link
                        href={`/creator/${post.userId}`}
                        onClick={(e) => e.stopPropagation()}
                        className="text-[12px] font-medium truncate hover:underline"
                        style={{ color: "#78716c" }}
                    >
                        {displayName}
                    </Link>
                    <span className="text-[11px] shrink-0" style={{ color: "#d6d3d1" }}>{timeAgo(post.createdAt)}</span>
                </div>
                {/* 좋아요 + 댓글 */}
                <div className="flex items-center gap-2.5 shrink-0">
                    <button
                        onClick={(e) => { e.stopPropagation(); if (myId) onLike(post.id); }}
                        className="flex items-center gap-0.5 transition-opacity hover:opacity-60"
                        style={{ color: post.liked ? "#FF3B30" : "#c8c4c0" }}>
                        <svg width="13" height="13" viewBox="0 0 24 24" fill={post.liked ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                        </svg>
                        <span className="text-[11px]">{post.likeCount}</span>
                    </button>
                    <div className="flex items-center gap-0.5" style={{ color: "#c8c4c0" }}>
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
                        </svg>
                        <span className="text-[11px]">{post.commentCount}</span>
                    </div>
                </div>
            </div>
        </div>
    );
}

// ── 메인 페이지 ──────────────────────────────────
export default function GalleryPage() {
    const router = useRouter();
    const [posts, setPosts] = useState<GalleryPost[]>([]);
    const [sort, setSort] = useState<"latest" | "likes">("latest");
    const [loading, setLoading] = useState(true);
    const [myId, setMyId] = useState<string | null>(null);
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [page, setPage] = useState(1);
    const [total, setTotal] = useState(0);

    useEffect(() => {
        fetch("/api/auth/session").then((r) => r.json()).then((d) => {
            if (d?.session) { setIsLoggedIn(true); setMyId(d.session.dbId ?? null); }
        }).catch(() => {});
    }, []);

    const fetchPosts = useCallback(async (p = 1, s = sort) => {
        setLoading(true);
        try {
            const res = await fetch(`/api/gallery?sort=${s}&page=${p}`);
            const data = await res.json() as { posts: GalleryPost[]; total: number };
            setPosts(p === 1 ? data.posts : (prev) => [...prev, ...data.posts]);
            setTotal(data.total);
        } finally {
            setLoading(false);
        }
    }, [sort]);

    useEffect(() => {
        setPage(1);
        fetchPosts(1, sort);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [sort]);

    const handleLike = async (postId: string) => {
        if (!myId) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPosts((prev) => prev.map((p) =>
            p.id === postId ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p
        ));
    };

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[1200px] mx-auto w-full px-5 pt-12 pb-24">
                {/* 헤더 */}
                <div className="flex items-end justify-between mb-10">
                    <div>
                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-2" style={{ color: "#a8a29e" }}>Gallery</p>
                        <h1 className="text-[28px] font-bold tracking-tight" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>꾸미 갤러리</h1>
                        <p className="text-[14px] mt-1" style={{ color: "#78716c" }}>카꾸미로 만든 테마를 소개해보세요!</p>
                    </div>
                    {isLoggedIn && (
                        <button
                            onClick={() => router.push("/gallery/new")}
                            className="flex items-center gap-1.5 px-5 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70"
                            style={{ background: "#1c1917", color: "#fafaf9" }}>
                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
                            테마 소개하기
                        </button>
                    )}
                </div>

                {/* 정렬 탭 */}
                <div className="flex items-center gap-1.5 mb-8">
                    {(["latest", "likes"] as const).map((s) => (
                        <button key={s} onClick={() => setSort(s)}
                            className="px-4 py-1.5 rounded-full text-[13px] font-medium transition-all duration-150"
                            style={{
                                backgroundColor: sort === s ? "rgb(74,123,247)" : "transparent",
                                color: sort === s ? "#fff" : "#78716c",
                                border: `1px solid ${sort === s ? "rgb(74,123,247)" : "#e7e5e4"}`,
                            }}>
                            {s === "latest" ? "최신순" : "좋아요순"}
                        </button>
                    ))}
                </div>

                {/* 그리드 */}
                {loading && posts.length === 0 ? (
                    <div className="flex justify-center items-center py-32">
                        <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                    </div>
                ) : posts.length === 0 ? (
                    <div className="flex flex-col items-center gap-4 py-32">
                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/>
                        </svg>
                        <p className="text-[14px]" style={{ color: "#a8a29e" }}>아직 게시글이 없어요. 첫 번째로 소개해보세요!</p>
                    </div>
                ) : (
                    <div className="grid gap-4" style={{ gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))" }}>
                        {posts.map((post) => (
                            <PostCard key={post.id} post={post} myId={myId} onLike={handleLike} onNavigate={(id) => router.push(`/gallery/${id}`)} />
                        ))}
                    </div>
                )}

                {/* 더보기 */}
                {posts.length < total && !loading && (
                    <div className="flex justify-center mt-10">
                        <button onClick={() => { const next = page + 1; setPage(next); fetchPosts(next); }}
                            className="px-6 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-60"
                            style={{ border: "1px solid #e7e5e4", color: "#78716c" }}>
                            더 보기
                        </button>
                    </div>
                )}
            </div>
            <Footer />
        </div>
    );
}

'use client';

import { useState, useRef, useEffect } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import Image from "next/image";
import ThemeVaultTabs from "./ThemeVaultTabs";
import CreditPage from "./CreditPage";
import RefundPage from "./RefundPage";
import OrderPage from "./OrderPage";
import LikePage from "./LikePage";
import SalesStatsPage from "./SalesStatsPage";
import SettlementPage from "./SettlementPage";
import BankAccountPage from "./BankAccountPage";
import MyReviewsPage from "./MyReviewsPage";
import ReviewablePage from "./ReviewablePage";
import SubscriptionInfoPage from "./SubscriptionInfoPage";
import SubscriptionPaymentsPage from "./SubscriptionPaymentsPage";
import { formatKST } from "@/lib/date";
import { validateNickname } from "@/lib/nickname";
import { WITHDRAW_CONFIRM_TEXT, AVATAR_MAX_SIZE_MB } from "@/lib/constants";

type SidebarMenu = {
    category: string;
    items: { label: string; href?: string }[];
};

type Tab = "mine" | "purchased";

const THEME_TAB_MAP: Record<string, Tab> = {
    "업로드 테마": "mine",
    "구매 테마": "purchased",
};

type Props = {
    session: {
        name?: string | null;
        nickname?: string | null;
        image?: string | null;
        avatarUrl?: string | null;
        id?: string | null;
        dbId?: string | null;
        email?: string | null;
        role?: string | null;
    } | null;
    purchasedCount: number;
    sidebarMenus: SidebarMenu[];
    createdAt?: string | null;
    credit?: number;
};

export default function MyPageClient({ session, purchasedCount: _purchasedCount, sidebarMenus, createdAt, credit: _credit = 0 }: Props) {
    const router = useRouter();
    const searchParams = useSearchParams();
    const menuFromUrl = searchParams.get("menu") ?? "";
    const [activeMenu, setActiveMenu] = useState<string>(menuFromUrl || "회원 정보");
    const [themeTab, setThemeTab] = useState<Tab>(() => THEME_TAB_MAP[menuFromUrl] ?? "purchased");

    // URL menu 파라미터가 바뀌면 activeMenu, themeTab 동기화
    useEffect(() => {
        if (!menuFromUrl) return;
        setActiveMenu(menuFromUrl);
        const tab = THEME_TAB_MAP[menuFromUrl];
        if (tab) setThemeTab(tab);
    }, [menuFromUrl]);

    // 구독 상태 클라이언트에서 재확인 (서버 캐시 우회)
    const [nickInput, setNickInput] = useState(currentNickname);
    const [nickError, setNickError] = useState("");
    const [nickCheckStatus, setNickCheckStatus] = useState<"idle" | "checking" | "available" | "taken">("idle");
    const [nickSaving, setNickSaving] = useState(false);
    const [nickSuccess, setNickSuccess] = useState(false);

    // 프로필 이미지 상태
    const [avatarPreview, setAvatarPreview] = useState<string | null>(session?.avatarUrl ?? null);
    const [avatarError, setAvatarError] = useState("");
    const [avatarSaving, setAvatarSaving] = useState(false);
    const [avatarSuccess, setAvatarSuccess] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // 알림 설정 상태
    type NotifKey = "purchaseComplete" | "newReview" | "inquiryReply" | "newTheme" | "promotionEvent" | "serviceBroadcast" | "followAlert" | "creditExpiry" | "priceDropAlert";
    type NotifSettings = Record<NotifKey, boolean>;
    const isCreatorOrAdmin = session?.role === "CREATOR" || session?.role === "ADMIN";
    const NOTIFICATION_GROUPS: { category: string; items: { key: NotifKey; label: string; desc: string }[] }[] = [
        { category: "구매 / 다운로드", items: [{ key: "purchaseComplete", label: "구매 완료 알림", desc: "테마 결제가 완료되면 알려드립니다." }] },
        { category: "리뷰 & 문의", items: [
            { key: "newReview", label: "새 리뷰 알림", desc: "내 테마에 리뷰가 등록되면 알려드립니다." },
            { key: "inquiryReply", label: "문의 답변 알림", desc: "1:1 문의에 답변이 등록되면 알려드립니다." },
        ]},
        { category: "테마 스토어", items: [
            { key: "newTheme", label: "신규 테마 알림", desc: "팔로우한 크리에이터가 새 테마를 등록하면 알려드립니다." },
            { key: "promotionEvent", label: "할인 / 이벤트 알림", desc: "관심 테마의 가격 변동이나 이벤트를 알려드립니다." },
            { key: "priceDropAlert", label: "찜한 테마 가격 인하 알림", desc: "좋아요한 테마의 가격이 내려가면 알려드립니다." },
        ]},
        { category: "적립금", items: [
            { key: "creditExpiry", label: "적립금 만료 알림", desc: "적립금 만료 7일·1일 전에 미리 알려드립니다." },
        ]},
        ...(isCreatorOrAdmin ? [{ category: "크리에이터", items: [
            { key: "followAlert" as NotifKey, label: "팔로우 알림", desc: "누군가 나를 팔로우하면 알려드립니다." },
        ]}] : []),
        { category: "서비스", items: [{ key: "serviceBroadcast", label: "공지 및 서비스 알림", desc: "카꾸미의 공지사항과 업데이트 소식을 알려드립니다." }] },
    ];
    const [notifSettings, setNotifSettings] = useState<NotifSettings>({ purchaseComplete: true, newReview: true, inquiryReply: true, newTheme: false, promotionEvent: false, serviceBroadcast: true, followAlert: true, creditExpiry: true, priceDropAlert: false });
    const [notifSaving, setNotifSaving] = useState(false);
    const [notifSaveSuccess, setNotifSaveSuccess] = useState(false);
    const [notifLoaded, setNotifLoaded] = useState(false);

    // 알림 설정 메뉴 진입 시 서버에서 불러오기
    useEffect(() => {
        if (activeMenu !== "알림 설정" || notifLoaded) return;
        const load = async () => {
            try {
                const res = await fetch("/api/user/notif-settings");
                const data = await res.json() as { settings: NotifSettings };
                if (data.settings) setNotifSettings(data.settings);
            } catch { /* 기본값 유지 */ } finally {
                setNotifLoaded(true);
            }
        };
        void load();
    }, [activeMenu, notifLoaded]);

    const toggleNotif = (key: NotifKey) => { setNotifSettings((prev) => ({ ...prev, [key]: !prev[key] })); setNotifSaveSuccess(false); };
    const handleNotifSaveAll = async () => {
        setNotifSaving(true);
        try {
            const res = await fetch("/api/user/notif-settings", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(notifSettings),
            });
            if (res.ok) {
                setNotifSaveSuccess(true);
                setTimeout(() => setNotifSaveSuccess(false), 3000);
            }
        } catch { /* ignore */ } finally {
            setNotifSaving(false);
        }
    };

    // 회원 탈퇴 상태
    const CHECKLIST = [
        "구매한 테마는 탈퇴 후 사용할 수 없으며 환불되지 않습니다.",
        "등록한 테마, 리뷰, 문의 내역이 모두 삭제됩니다.",
        "삭제된 계정과 데이터는 복구할 수 없습니다.",
        "같은 카카오 계정으로 재가입하면 새 계정으로 처음부터 시작합니다.",
        "탈퇴 후 3일이 지나야 동일 카카오 계정으로 재가입할 수 있습니다.",
    ];
    const [withdrawChecked, setWithdrawChecked] = useState<boolean[]>(CHECKLIST.map(() => false));
    const [withdrawConfirmInput, setWithdrawConfirmInput] = useState("");
    const [withdrawLoading, setWithdrawLoading] = useState(false);
    const [withdrawError, setWithdrawError] = useState("");
    const withdrawAllChecked = withdrawChecked.every(Boolean);
    const withdrawConfirmMatch = withdrawConfirmInput === WITHDRAW_CONFIRM_TEXT;
    const canWithdraw = withdrawAllChecked && withdrawConfirmMatch && !withdrawLoading;
    const toggleWithdrawCheck = (idx: number) => { setWithdrawChecked((prev) => prev.map((v, i) => (i === idx ? !v : v))); };
    const handleWithdraw = async () => {
        if (!canWithdraw) return;
        setWithdrawLoading(true);
        setWithdrawError("");
        const res = await fetch("/api/auth/withdraw", { method: "DELETE", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ confirm: WITHDRAW_CONFIRM_TEXT }) });
        const data = await res.json() as { ok?: boolean; error?: string };
        if (!res.ok) { setWithdrawError(data.error ?? "탈퇴 처리 중 오류가 발생했습니다."); setWithdrawLoading(false); return; }
        router.push("/?withdrawn=1");
    };

    const handleNickCheck = async () => {
        const trimmed = nickInput.trim();
        if (!trimmed || trimmed === currentNickname) {
            setNickError("현재 닉네임과 동일합니다.");
            setNickCheckStatus("idle");
            return;
        }
        const validationError = validateNickname(trimmed);
        if (validationError) {
            setNickError(validationError);
            setNickCheckStatus("idle");
            return;
        }
        setNickError("");
        setNickCheckStatus("checking");
        try {
            const res = await fetch(`/api/user/nickname/check?nickname=${encodeURIComponent(trimmed)}`);
            const data = await res.json() as { available: boolean; error?: string };
            if (data.error) {
                setNickError(data.error);
                setNickCheckStatus("idle");
            } else {
                setNickCheckStatus(data.available ? "available" : "taken");
                if (!data.available) setNickError("이미 사용 중인 닉네임입니다.");
            }
        } catch {
            setNickCheckStatus("idle");
        }
    };

    const handleNickSave = async () => {
        if (nickSaving) return;
        const trimmed = nickInput.trim();
        if (trimmed === currentNickname) {
            setNickError("현재 닉네임과 동일합니다.");
            return;
        }
        if (nickCheckStatus !== "available") return;
        setNickSaving(true);
        setNickError("");
        const res = await fetch("/api/user/nickname", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ nickname: trimmed }),
        });
        const data = await res.json() as { nickname?: string; error?: string };
        setNickSaving(false);
        if (!res.ok) {
            setNickError(data.error ?? "저장 실패");
        } else {
            setNickSuccess(true);
            setTimeout(() => setNickSuccess(false), 3000);
            router.refresh();
        }
    };

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        if (!file.type.startsWith("image/")) {
            setAvatarError("이미지 파일만 업로드할 수 있습니다.");
            return;
        }
        if (file.size > AVATAR_MAX_SIZE_MB * 1024 * 1024) {
            setAvatarError(`이미지 크기는 ${AVATAR_MAX_SIZE_MB}MB 이하여야 합니다.`);
            return;
        }
        setAvatarError("");
        const reader = new FileReader();
        reader.onload = (ev) => { setAvatarPreview(ev.target?.result as string); };
        reader.readAsDataURL(file);
    };

    const handleAvatarSave = async (url: string | null) => {
        setAvatarSaving(true);
        setAvatarError("");
        try {
            const res = await fetch("/api/user/avatar", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ avatarUrl: url }),
            });
            let data: { avatarUrl?: string | null; error?: string } = {};
            try { data = await res.json() as typeof data; } catch { /* non-JSON response */ }
            if (!res.ok) {
                setAvatarError(data.error ?? "저장 실패");
            } else {
                setAvatarPreview(url);
                setAvatarSuccess(true);
        const res = await fetch("/api/user/avatar", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ avatarUrl: url }),
        });
        const data = await res.json() as { avatarUrl?: string | null; error?: string };
        setAvatarSaving(false);
        if (!res.ok) {
            setAvatarError(data.error ?? "저장 실패");
        } else {
            setAvatarPreview(url);
            setAvatarSuccess(true);
            setTimeout(() => setAvatarSuccess(false), 3000);
            router.refresh();
    const isWithdrawMenu = activeMenu === "회원 탈퇴";
    const isFollowMenu = activeMenu === "팔로우";
    const isReviewMenu = activeMenu === "리뷰";
    const isReviewableMenu = activeMenu === "작성 가능한 후기";
    const isSubInfoMenu = activeMenu === "결제 정보";
    const isSubPaymentsMenu = activeMenu === "결제 내역";

    type FollowingUser = { id: string; nickname: string | null; name: string; avatarUrl: string | null; role: string; themeCount: number };
    const [followingList, setFollowingList] = useState<FollowingUser[]>([]);
    const [followingLoading, setFollowingLoading] = useState(false);
    const [unfollowingId, setUnfollowingId] = useState<string | null>(null);

    useEffect(() => {
        if (!isFollowMenu) return;
        const load = async () => {
            setFollowingLoading(true);
            try {
                const r = await fetch("/api/mypage/following");
                const d = await r.json() as { following: FollowingUser[]; error?: string };
                if (d.error) console.error("[following]", d.error);
                setFollowingList(d.following ?? []);
            } catch {
                //
            } finally {
                setFollowingLoading(false);
            }
    type FollowingUser = { id: string; nickname: string | null; name: string; avatarUrl: string | null; themeCount: number };
        void load();
    }, [isFollowMenu]);

    const handleUnfollow = async (targetId: string) => {
        setUnfollowingId(targetId);
        await fetch("/api/follow", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ creatorId: targetId }),
        });
        setFollowingList(prev => prev.filter(u => u.id !== targetId));
        setUnfollowingId(null);
    };

    const handleMenuClick = (label: string) => {
        if (THEME_TAB_MAP[label] !== undefined) {
            setThemeTab(THEME_TAB_MAP[label]);
        }
        setActiveMenu(label);
    };

    return (
        <div className="flex w-full" style={{ maxWidth: 1400, margin: "0 auto" }}>

            {/* ── 사이드바 ── */}
            <aside className="fixed w-[160px] flex flex-col gap-1 px-5 pt-12" style={{ zIndex: 10 }}>
                {sidebarMenus.map((group, index) => (
                    <div key={group.category} className="flex flex-col gap-0.5">
                        <span className="text-[10.5px] font-bold tracking-[0.15em] uppercase px-2 mb-1" style={{ color: "#8e8e93" }}>
                            {group.category}
                        </span>
                        {group.items.map((item) => {
                            const isActive = activeMenu === item.label;
                            const isWithdrawItem = item.label === "회원 탈퇴";
                            return (
                                <button
                                    key={item.label}
                                    onClick={() => handleMenuClick(item.label)}
                                    className="text-left px-2 py-[7px] rounded-xl text-[12.5px] font-medium transition-all"
                                    style={{
                                        color: isWithdrawItem
                                            ? (isActive ? "#c0392b" : "#ff3b30")
                                            : isActive ? "#FF9500" : "#3a3a3c",
                                        fontWeight: isActive ? 700 : 500,
                                    }}
                                >
                                    {item.label}
                                </button>
                            );
                        })}
                        {index < sidebarMenus.length - 1 && (
                            <div className="my-2.5 h-[1px]" style={{ background: "rgba(0,0,0,0.18)" }} />
                        )}
                    </div>
                ))}
            </aside>

            {/* ── 메인 콘텐츠 ── */}
            <main className="flex-1 flex flex-col min-w-0 px-8 pt-12 pb-24" style={{ marginLeft: 200 }}>
                {session ? (
                    <>
                        {isThemeMenu ? (
                            <ThemeVaultTabs key={activeMenu} initialTab={themeTab} />
                        ) : isCreditMenu ? (
                            <CreditPage />
                        ) : isOrderMenu ? (
                            <OrderPage />
                        ) : isRefundMenu ? (
                            <RefundPage />
                        ) : isLikeMenu ? (
                            <LikePage />
                        ) : isSalesStatsMenu ? (
                            <SalesStatsPage />
                        ) : isSettlementMenu ? (
                            <SettlementPage role={session?.role} />
                        ) : isBankMenu ? (
                            <BankAccountPage role={session?.role} />
                        ) : isReviewMenu ? (
                            <MyReviewsPage />
                        ) : isReviewableMenu ? (
                            <ReviewablePage />
                        ) : isSubInfoMenu ? (
                            <SubscriptionInfoPage />
                        ) : isSubPaymentsMenu ? (
                            <SubscriptionPaymentsPage />
                        ) : isFollowMenu ? (
                            <>
                                {/* 섹션 헤더 */}
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Following</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>팔로우</h2>
                                    </div>
                                </div>
                                <p className="text-[13px] mb-8" style={{ color: "#78716c" }}>내가 팔로우한 크리에이터 목록입니다.</p>
                                <div className="flex flex-col">
                                    {followingLoading ? (
                                        <div className="flex items-center justify-center py-20">
                                            <span className="text-[14px]" style={{ color: "#a8a29e" }}>불러오는 중...</span>
                                        </div>
                                    ) : followingList.length === 0 ? (
                                        <div className="flex flex-col items-center justify-center py-24 gap-3">
                                            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                                <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/>
                                            </svg>
                                            <p className="text-[14px]" style={{ color: "#a8a29e" }}>아직 팔로우한 크리에이터가 없어요.</p>
                                        </div>
                                    ) : (
                                        followingList.map((user, idx) => (
                                            <div key={user.id}>
                                                <div className="flex items-center gap-4 py-4">
                                                    {/* 프로필 이미지 */}
                                                    <button onClick={() => router.push(`/creator/${user.id}`)} className="shrink-0 w-10 h-10 rounded-full overflow-hidden flex items-center justify-center transition-all hover:opacity-75" style={{ background: "#e7e5e4" }}>
                                                        <Image
                                                            src={
                                                                user.role === "CREATOR" || user.role === "ADMIN"
                                                                    ? "/creator.png"
                                                                    : (user.avatarUrl ?? "/user.png")
                                                            }
                                                            alt={user.nickname ?? user.name}
                                                            width={40} height={40}
                                                            className="w-full h-full object-cover"
                                                        />
                                                        {user.avatarUrl ? (
                                                            <Image src={user.avatarUrl} alt={user.nickname ?? user.name} width={40} height={40} className="w-full h-full object-cover" unoptimized />
                                                        ) : (
                                                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#78716c" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                                                <circle cx="12" cy="8" r="4"/><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7"/>
                                                            </svg>
                                                        )}
                                                    {/* 언팔로우 버튼 */}
                                                    <button
                                                        onClick={() => handleUnfollow(user.id)}
                                                        disabled={unfollowingId === user.id}
                                                        className="text-[12px] font-medium transition-opacity hover:opacity-50 disabled:opacity-30 shrink-0"
                                                        style={{ color: "#78716c" }}
                                                    >
                                                        {unfollowingId === user.id ? "처리 중..." : "팔로우 취소"}
                                                    </button>
                                                </div>
                                                {idx < followingList.length - 1 && (
                                                    <div className="h-px" style={{ background: "#f5f5f4" }} />
                                                )}
                                            </div>
                                        ))
                                    )}
                                </div>
                            </>
                        ) : isSettingsMenu ? (
                            /* ── 회원 정보 ── */
                            <>
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Account</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>회원 정보</h2>
                                    </div>
                                </div>

                                {/* 프로필 이미지 */}
                                <div className="flex flex-col gap-4 pb-8">
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>프로필 이미지</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    {isPro ? (
                                        /* PRO / ADMIN: 자유롭게 변경 가능 */
                                        <div className="flex items-center gap-6">
                                            <button
                                                type="button"
                                                onClick={() => fileInputRef.current?.click()}
                                                className="relative group shrink-0 rounded-full overflow-hidden flex items-center justify-center transition-opacity hover:opacity-80"
                                                style={{ width: 72, height: 72, background: "#e7e5e4" }}
                                            >
                                                <Image
                                                    src={avatarPreview ?? "/user.png"}
                                    <div className="flex items-center gap-6">
                                        <button
                                            type="button"
                                            onClick={() => fileInputRef.current?.click()}
                                            className="relative group shrink-0 rounded-full overflow-hidden flex items-center justify-center transition-opacity hover:opacity-80"
                                            style={{ width: 72, height: 72, background: avatarPreview ? "transparent" : "#e7e5e4" }}
                                        >
                                            {avatarPreview ? (
                                                <Image src={avatarPreview} alt={displayNickname} width={72} height={72} className="w-full h-full object-cover" unoptimized />
                                            ) : (
                                                <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                                    <circle cx="12" cy="8" r="4" />
                                                    <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                                                </svg>
                                            )}
                                            <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity rounded-full" style={{ background: "rgba(0,0,0,0.3)" }}>
                                                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                    <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                                                    <polyline points="17 8 12 3 7 8" />
                                                    <line x1="12" y1="3" x2="12" y2="15" />
                                                </svg>
                                            </div>
                                        </button>
                                        <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
                                        <div className="flex flex-col gap-2">
                                            <div className="flex items-center gap-2">
                                                <button type="button" onClick={() => fileInputRef.current?.click()} className="text-[12px] font-medium transition-opacity hover:opacity-60" style={{ color: "#78716c" }}>
                                                    사진 선택
                                                </button>
                                                {avatarPreview && avatarPreview !== (session?.avatarUrl ?? null) && (
                                                    <>
                                                        <span style={{ color: "#e7e5e4" }}>·</span>
                                                        <button type="button" onClick={() => handleAvatarSave(avatarPreview)} disabled={avatarSaving} className="text-[12px] font-semibold transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#FF9500" }}>
                                                            {avatarSaving ? "저장 중..." : "저장"}
                                                        </button>
                                                    </>
                                                )}
                                                {(avatarPreview ?? session?.avatarUrl) && (
                                                    <>
                                                        <span style={{ color: "#e7e5e4" }}>·</span>
                                                        <button type="button" onClick={() => { setAvatarPreview(null); if (fileInputRef.current) fileInputRef.current.value = ""; handleAvatarSave(null); }} disabled={avatarSaving} className="text-[12px] font-medium transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#ff3b30" }}>
                                                            사진 제거
                                                        </button>
                                                    </>
                                                )}
                                            </div>
                                            {avatarSuccess && <p className="text-[11px]" style={{ color: "#34c759" }}>✓ 프로필 사진이 저장되었습니다.</p>}
                                            {avatarError && <p className="text-[11px]" style={{ color: "#ff3b30" }}>{avatarError}</p>}
                                            {!avatarSuccess && !avatarError && <p className="text-[11px]" style={{ color: "#a8a29e" }}>JPG, PNG, GIF · 최대 2MB</p>}
                                            </div>
                                        </div>
                                    ) : (
                                        /* 일반 유저 (FREE): user.png 고정 */
                                        <div className="flex items-center gap-6">
                                            <div className="relative shrink-0 rounded-full overflow-hidden" style={{ width: 72, height: 72, background: "#e7e5e4" }}>
                                    </div>
                                                    className="text-[14px] px-0 py-2 outline-none pr-7 bg-transparent"
                                                    style={{
                                                        borderBottom: `1.5px solid ${nickCheckStatus === "available" ? "#34c759" : nickCheckStatus === "taken" || nickError ? "#ff3b30" : "#d6d3d1"}`,
                                                        color: "#1c1917",
                                                        width: 220,
                                                    }}
                                                />
                                                <div className="absolute right-0 top-1/2 -translate-y-1/2">
                                                    {nickCheckStatus === "checking" && <div className="w-3.5 h-3.5 rounded-full border-2 border-black/20 border-t-black/60 animate-spin" />}
                                                    {nickCheckStatus === "available" && (
                                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#34c759" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5" /></svg>
                                                    )}
                                                    {nickCheckStatus === "taken" && (
                                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
                                                    )}
                                                </div>
                                            </div>
                                            <button onClick={handleNickCheck} disabled={nickCheckStatus === "checking" || !nickInput.trim()} className="text-[12px] font-medium transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#4a7bf7" }}>
                                                {nickCheckStatus === "checking" ? "확인 중..." : "중복 확인"}
                                            </button>
                                            <button onClick={handleNickSave} disabled={nickSaving || nickCheckStatus !== "available" || nickInput.trim() === currentNickname} className="text-[12px] font-semibold transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#FF9500" }}>
                                                {nickSaving ? "저장 중..." : "저장"}
                                            </button>
                                        </div>
                                        <div className="flex items-center justify-between">
                                            <p className="text-[11px]" style={{ color: nickSuccess ? "#34c759" : nickCheckStatus === "available" && !nickError ? "#34c759" : nickError ? "#ff3b30" : "#a8a29e" }}>
                                                {nickSuccess ? "✓ 닉네임이 저장되었습니다." : nickCheckStatus === "available" && !nickError ? "✓ 사용 가능한 닉네임입니다." : nickError ? nickError : "한글, 영문, 숫자 2~10자 (특수문자 불가, 숫자만 불가)"}
                                            </p>
                                            <p className="text-[11px]" style={{ color: "#a8a29e" }}>{nickInput.trim().length} / 10</p>
                                        </div>
                                    </div>
                                </div>

                                {/* 이메일 */}
                                <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>이메일</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <span className="text-[14px]" style={{ color: session.email ? "#1c1917" : "#a8a29e" }}>
                                            {session.email ?? "이메일 정보 없음"}
                                        </span>
                                        {session.email && (
                                            <span className="text-[11px] font-semibold px-2 py-0.5 rounded-full" style={{ background: "rgba(52,199,89,0.1)", color: "#34c759" }}>인증됨</span>
                                        )}
                                    </div>
                                    <p className="text-[11px]" style={{ color: "#a8a29e" }}>이메일은 카카오 계정과 연동되어 있습니다. 변경을 원하시면 카카오 계정에서 수정해주세요.</p>
                                </div>

                                {/* 계정 등급 */}
                                <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>계정 등급</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <div>
                                        <span className="text-[12px] font-semibold px-2.5 py-1 rounded-full" style={{ background: session.role === "ADMIN" ? "rgba(255,59,48,0.1)" : session.role === "CREATOR" ? "rgba(255,149,0,0.1)" : "rgba(74,123,247,0.1)", color: session.role === "ADMIN" ? "#ff3b30" : session.role === "CREATOR" ? "#FF9500" : "#4a7bf7" }}>
                                            {session.role === "ADMIN" ? "관리자" : session.role === "CREATOR" ? "크리에이터" : "일반 회원"}
                                        </span>
                                    </div>
                                    <p className="text-[11px]" style={{ color: "#a8a29e" }}>현재 서비스 이용 등급입니다.</p>
                                </div>

                                {/* 가입일 */}
                                <div className="flex flex-col gap-2 pt-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>가입일</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <span className="text-[14px]" style={{ color: "#78716c" }}>{createdAt ? formatKST(createdAt, false) : "-"}</span>
                                </div>
                            </>
                        ) : isNotifMenu ? (
                            /* ── 알림 설정 ── */
                            <>
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Notifications</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>알림 설정</h2>
                                    </div>
                                    <div className="flex items-center gap-4 pb-1">
                                        {notifSaveSuccess && <span className="text-[12px]" style={{ color: "#34c759" }}>✓ 저장되었습니다.</span>}
                                        <button onClick={handleNotifSaveAll} disabled={notifSaving} className="text-[13px] font-semibold transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#FF9500" }}>
                                            {notifSaving ? "저장 중..." : "변경사항 저장"}
                                        </button>
                                    </div>
                                </div>
                                <p className="text-[13px] mb-10" style={{ color: "#78716c" }}>받고 싶은 알림을 직접 선택하세요.</p>

                                {NOTIFICATION_GROUPS.map((group, gi) => (
                                    <div key={group.category}>
                                        <div className={`flex items-center gap-3 ${gi > 0 ? "mt-10" : ""} mb-1`}>
                                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>
                                                {group.category}
                                            </span>
                                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                        </div>
                                        <div className="flex flex-col">
                                            {group.items.map((item, idx) => (
                                                <div key={item.key}>
                                                    <div className="flex items-center justify-between py-4">
                                                        <div className="flex flex-col gap-0.5">
                                                            <span className="text-[14px]" style={{ color: "#1c1917", fontWeight: notifSettings[item.key] ? 600 : 400 }}>{item.label}</span>
                                                            <span className="text-[12px]" style={{ color: "#a8a29e" }}>{item.desc}</span>
                                                        </div>
                                                        <button type="button" onClick={() => toggleNotif(item.key)} className="relative shrink-0 transition-all active:scale-95" style={{ width: 44, height: 24 }} aria-label={notifSettings[item.key] ? "끄기" : "켜기"}>
                                                            <div className="absolute inset-0 rounded-full transition-colors duration-200" style={{ background: notifSettings[item.key] ? "#FF9500" : "#e7e5e4" }} />
                                                            <div className="absolute top-[3px] w-[18px] h-[18px] rounded-full bg-white transition-all duration-200" style={{ left: notifSettings[item.key] ? 23 : 3, boxShadow: "0 1px 3px rgba(0,0,0,0.15)" }} />
                                                        </button>
                                                    </div>
                                                    {idx < group.items.length - 1 && <div className="h-px" style={{ background: "#f5f5f4" }} />}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}

                                <div className="mt-12 flex items-start gap-3 pt-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#4a7bf7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0 mt-0.5">
                                        <circle cx="12" cy="12" r="10" /><line x1="12" y1="8" x2="12" y2="12" /><line x1="12" y1="16" x2="12.01" y2="16" />
                                    </svg>
                                    <p className="text-[12px] leading-relaxed" style={{ color: "#78716c" }}>알림은 서비스 내 알림으로 제공됩니다. 이메일·푸시 알림은 추후 지원 예정입니다. 법적 필수 공지(이용약관 변경 등)는 설정과 관계없이 발송될 수 있습니다.</p>
                                </div>
                            </>
                        ) : isWithdrawMenu ? (
                            /* ── 회원 탈퇴 ── */
                            <>
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Account</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>회원 탈퇴</h2>
                                    </div>
                                </div>
                                <p className="text-[13px] mb-10" style={{ color: "#78716c" }}>탈퇴 전 아래 내용을 꼭 확인해주세요.</p>

                                {/* 프로필 확인 */}
                                <div className="flex items-center gap-4 py-5" style={{ borderBottom: "1px solid #e7e5e4" }}>
                                    <div className="w-10 h-10 rounded-full overflow-hidden flex items-center justify-center shrink-0" style={{ background: "#ffe500" }}>
                                        {session.avatarUrl ? (
                                            <Image src={session.avatarUrl} alt={displayNickname} width={40} height={40} className="w-full h-full object-cover" unoptimized />
                                        ) : (
                                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#3A1D1D" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" /></svg>
                                        )}
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-[14px] font-semibold" style={{ color: "#1c1917" }}>{displayNickname}</p>
                                        <p className="text-[12px]" style={{ color: "#a8a29e" }}>{session.email ?? "이메일 없음"}</p>
                                    </div>
                                    <span className="text-[11px] font-semibold px-2.5 py-1 rounded-full" style={{ background: "rgba(255,59,48,0.08)", color: "#ff3b30" }}>탈퇴 예정</span>
                                </div>

                                {/* 주의사항 체크리스트 */}
                                <div className="mt-8 mb-2">
                                    <div className="flex items-center gap-3 mb-6">
                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z" /><line x1="12" y1="9" x2="12" y2="13" /><line x1="12" y1="17" x2="12.01" y2="17" /></svg>
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#ff3b30" }}>탈퇴 전 반드시 확인하세요</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "rgba(255,59,48,0.15)" }} />
                                    </div>
                                    <div className="flex flex-col gap-1">
                                        {CHECKLIST.map((text, idx) => (
                                            <button key={idx} type="button" onClick={() => toggleWithdrawCheck(idx)} className="flex items-start gap-3 text-left py-3 transition-opacity hover:opacity-70">
                                                <div className="shrink-0 w-4 h-4 rounded mt-0.5 flex items-center justify-center transition-all" style={{ background: withdrawChecked[idx] ? "#ff3b30" : "transparent", border: `1.5px solid ${withdrawChecked[idx] ? "#ff3b30" : "#d6d3d1"}` }}>
                                                    {withdrawChecked[idx] && <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5" /></svg>}
                                                </div>
                                                <span className="text-[13px] leading-relaxed" style={{ color: "#78716c" }}>{text}</span>
                                            </button>
                                        ))}
                                    </div>
                                    {!withdrawAllChecked && <p className="mt-3 text-[11px]" style={{ color: "#a8a29e" }}>위 항목을 모두 체크해야 탈퇴를 진행할 수 있습니다.</p>}
                                </div>

                                {/* 확인 문구 입력 */}
                                <div className="mt-8 flex flex-col gap-3" style={{ opacity: withdrawAllChecked ? 1 : 0.4, pointerEvents: withdrawAllChecked ? "auto" : "none" }}>
                                    <div className="flex items-center gap-3 mb-2">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>탈퇴 확인</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <p className="text-[12px]" style={{ color: "#78716c" }}>아래 입력창에 <span className="font-bold" style={{ color: "#ff3b30" }}>{WITHDRAW_CONFIRM_TEXT}</span> 를 입력하세요.</p>
                                    <input type="text" value={withdrawConfirmInput} onChange={(e) => setWithdrawConfirmInput(e.target.value)} placeholder={WITHDRAW_CONFIRM_TEXT} className="px-0 py-2.5 text-[14px] outline-none bg-transparent w-full max-w-[280px]" style={{ borderBottom: `1.5px solid ${withdrawConfirmMatch ? "#ff3b30" : "#d6d3d1"}`, color: "#1c1917" }} />
                                </div>

                                {withdrawError && <p className="mt-4 text-[13px]" style={{ color: "#ff3b30" }}>{withdrawError}</p>}

                                <div className="flex gap-3 mt-10">
                                    <button onClick={() => setActiveMenu("회원 정보")} className="flex-1 py-3 rounded-xl text-[14px] font-medium transition-opacity hover:opacity-60" style={{ border: "1px solid #e7e5e4", color: "#78716c", background: "transparent" }}>취소</button>
                                    <button onClick={handleWithdraw} disabled={!canWithdraw} className="flex-1 py-3 rounded-xl text-[14px] font-semibold transition-opacity disabled:opacity-30" style={{ background: canWithdraw ? "#ff3b30" : "#ff3b30", color: "#fff" }}>
                                        {withdrawLoading ? "탈퇴 처리 중..." : "탈퇴하기"}
                                    </button>
                                </div>
                            </>
                        ) : null}
                    </>
                ) : (
                    <div className="flex flex-col items-center justify-center py-32 gap-4">
                        <div className="w-12 h-12 rounded-full flex items-center justify-center" style={{ background: "#f5f5f4" }}>
                            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                <circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                            </svg>
                        </div>
                        <div className="flex flex-col gap-1.5 text-center">
                            <h2 className="text-[20px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>로그인이 필요해요</h2>
                            <p className="text-[13px]" style={{ color: "#a8a29e" }}>마이페이지를 이용하려면 카카오 로그인을 해주세요.</p>
                        </div>
                        <a href="/api/auth/kakao" className="mt-2">
                            <button className="px-7 py-3 rounded-xl text-[14px] font-bold transition-opacity hover:opacity-80 active:scale-95" style={{ background: "rgba(255,231,58,0.95)", color: "#3A1D1D" }}>
                                카카오 로그인
                            </button>
                        </a>
                    </div>
                )}
            </main>
        </div>
    );
}

'use client';

import { useState, useRef, useEffect } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import Image from "next/image";
import ThemeVaultTabs from "./ThemeVaultTabs";
import CreditPage from "./CreditPage";
import RefundPage from "./RefundPage";
import OrderPage from "./OrderPage";
import LikePage from "./LikePage";
import SalesStatsPage from "./SalesStatsPage";
import SettlementPage from "./SettlementPage";
import BankAccountPage from "./BankAccountPage";
import MyReviewsPage from "./MyReviewsPage";
import ReviewablePage from "./ReviewablePage";
import SubscriptionInfoPage from "./SubscriptionInfoPage";
import SubscriptionPaymentsPage from "./SubscriptionPaymentsPage";
import { formatKST } from "@/lib/date";
import { validateNickname } from "@/lib/nickname";
import { WITHDRAW_CONFIRM_TEXT, AVATAR_MAX_SIZE_MB } from "@/lib/constants";

type SidebarMenu = {
    category: string;
    items: { label: string; href?: string }[];
};

type Tab = "mine" | "purchased";

const THEME_TAB_MAP: Record<string, Tab> = {
    "업로드 테마": "mine",
    "구매 테마": "purchased",
};

type Props = {
    session: {
        name?: string | null;
        nickname?: string | null;
        image?: string | null;
        avatarUrl?: string | null;
        id?: string | null;
        dbId?: string | null;
        email?: string | null;
        role?: string | null;
    } | null;
    purchasedCount: number;
    sidebarMenus: SidebarMenu[];
    createdAt?: string | null;
    credit?: number;
    isPro?: boolean;
};

export default function MyPageClient({ session, purchasedCount: _purchasedCount, sidebarMenus, createdAt, credit: _credit = 0, isPro: isProProp = false }: Props) {
    const router = useRouter();
    const searchParams = useSearchParams();
    const menuFromUrl = searchParams.get("menu") ?? "";
    const [activeMenu, setActiveMenu] = useState<string>(menuFromUrl || "회원 정보");
    const [themeTab, setThemeTab] = useState<Tab>(() => THEME_TAB_MAP[menuFromUrl] ?? "purchased");

    // URL menu 파라미터가 바뀌면 activeMenu, themeTab 동기화
    useEffect(() => {
        if (!menuFromUrl) return;
        setActiveMenu(menuFromUrl);
        const tab = THEME_TAB_MAP[menuFromUrl];
        if (tab) setThemeTab(tab);
    }, [menuFromUrl]);

    // 구독 상태 클라이언트에서 재확인 (서버 캐시 우회)
    const [isPro, setIsPro] = useState<boolean>(isProProp);
    useEffect(() => {
        if (session?.role === "ADMIN") { setIsPro(true); return; }
        fetch("/api/subscription")
            .then(r => r.json())
            .then((d: { subscription?: { status: string } | null }) => {
                const status = d?.subscription?.status;
                const active = !!status && status.toUpperCase() === "ACTIVE";
                // 서버 prop이 true인 경우 클라이언트 일시적 오류로 false로 강등되지 않도록 함
                setIsPro(prev => prev || active);
            })
            .catch(() => { /* 기본값(서버 prop) 유지 */ });
    }, [session?.role]);

    // 닉네임 상태
    const currentNickname = session?.nickname ?? session?.name ?? "";
    const [nickInput, setNickInput] = useState(currentNickname);
    const [nickError, setNickError] = useState("");
    const [nickCheckStatus, setNickCheckStatus] = useState<"idle" | "checking" | "available" | "taken">("idle");
    const [nickSaving, setNickSaving] = useState(false);
    const [nickSuccess, setNickSuccess] = useState(false);

    // 프로필 이미지 상태
    const [avatarPreview, setAvatarPreview] = useState<string | null>(session?.avatarUrl ?? null);
    const [avatarError, setAvatarError] = useState("");
    const [avatarSaving, setAvatarSaving] = useState(false);
    const [avatarSuccess, setAvatarSuccess] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // 알림 설정 상태
    type NotifKey = "purchaseComplete" | "newReview" | "inquiryReply" | "newTheme" | "promotionEvent" | "serviceBroadcast" | "followAlert" | "creditExpiry" | "priceDropAlert";
    type NotifSettings = Record<NotifKey, boolean>;
    const isCreatorOrAdmin = session?.role === "CREATOR" || session?.role === "ADMIN";
    const NOTIFICATION_GROUPS: { category: string; items: { key: NotifKey; label: string; desc: string }[] }[] = [
        { category: "구매 / 다운로드", items: [{ key: "purchaseComplete", label: "구매 완료 알림", desc: "테마 결제가 완료되면 알려드립니다." }] },
        { category: "리뷰 & 문의", items: [
            { key: "newReview", label: "새 리뷰 알림", desc: "내 테마에 리뷰가 등록되면 알려드립니다." },
            { key: "inquiryReply", label: "문의 답변 알림", desc: "1:1 문의에 답변이 등록되면 알려드립니다." },
        ]},
        { category: "테마 스토어", items: [
            { key: "newTheme", label: "신규 테마 알림", desc: "팔로우한 크리에이터가 새 테마를 등록하면 알려드립니다." },
            { key: "promotionEvent", label: "할인 / 이벤트 알림", desc: "관심 테마의 가격 변동이나 이벤트를 알려드립니다." },
            { key: "priceDropAlert", label: "찜한 테마 가격 인하 알림", desc: "좋아요한 테마의 가격이 내려가면 알려드립니다." },
        ]},
        { category: "적립금", items: [
            { key: "creditExpiry", label: "적립금 만료 알림", desc: "적립금 만료 7일·1일 전에 미리 알려드립니다." },
        ]},
        ...(isCreatorOrAdmin ? [{ category: "크리에이터", items: [
            { key: "followAlert" as NotifKey, label: "팔로우 알림", desc: "누군가 나를 팔로우하면 알려드립니다." },
        ]}] : []),
        { category: "서비스", items: [{ key: "serviceBroadcast", label: "공지 및 서비스 알림", desc: "카꾸미의 공지사항과 업데이트 소식을 알려드립니다." }] },
    ];
    const [notifSettings, setNotifSettings] = useState<NotifSettings>({ purchaseComplete: true, newReview: true, inquiryReply: true, newTheme: false, promotionEvent: false, serviceBroadcast: true, followAlert: true, creditExpiry: true, priceDropAlert: false });
    const [notifSaving, setNotifSaving] = useState(false);
    const [notifSaveSuccess, setNotifSaveSuccess] = useState(false);
    const [notifLoaded, setNotifLoaded] = useState(false);

    // 알림 설정 메뉴 진입 시 서버에서 불러오기
    useEffect(() => {
        if (activeMenu !== "알림 설정" || notifLoaded) return;
        const load = async () => {
            try {
                const res = await fetch("/api/user/notif-settings");
                const data = await res.json() as { settings: NotifSettings };
                if (data.settings) setNotifSettings(data.settings);
            } catch { /* 기본값 유지 */ } finally {
                setNotifLoaded(true);
            }
        };
        void load();
    }, [activeMenu, notifLoaded]);

    const toggleNotif = (key: NotifKey) => { setNotifSettings((prev) => ({ ...prev, [key]: !prev[key] })); setNotifSaveSuccess(false); };
    const handleNotifSaveAll = async () => {
        setNotifSaving(true);
        try {
            const res = await fetch("/api/user/notif-settings", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(notifSettings),
            });
            if (res.ok) {
                setNotifSaveSuccess(true);
                setTimeout(() => setNotifSaveSuccess(false), 3000);
            }
        } catch { /* ignore */ } finally {
            setNotifSaving(false);
        }
    };

    // 회원 탈퇴 상태
    const CHECKLIST = [
        "구매한 테마는 탈퇴 후 사용할 수 없으며 환불되지 않습니다.",
        "등록한 테마, 리뷰, 문의 내역이 모두 삭제됩니다.",
        "삭제된 계정과 데이터는 복구할 수 없습니다.",
        "같은 카카오 계정으로 재가입하면 새 계정으로 처음부터 시작합니다.",
        "탈퇴 후 3일이 지나야 동일 카카오 계정으로 재가입할 수 있습니다.",
    ];
    const [withdrawChecked, setWithdrawChecked] = useState<boolean[]>(CHECKLIST.map(() => false));
    const [withdrawConfirmInput, setWithdrawConfirmInput] = useState("");
    const [withdrawLoading, setWithdrawLoading] = useState(false);
    const [withdrawError, setWithdrawError] = useState("");
    const withdrawAllChecked = withdrawChecked.every(Boolean);
    const withdrawConfirmMatch = withdrawConfirmInput === WITHDRAW_CONFIRM_TEXT;
    const canWithdraw = withdrawAllChecked && withdrawConfirmMatch && !withdrawLoading;
    const toggleWithdrawCheck = (idx: number) => { setWithdrawChecked((prev) => prev.map((v, i) => (i === idx ? !v : v))); };
    const handleWithdraw = async () => {
        if (!canWithdraw) return;
        setWithdrawLoading(true);
        setWithdrawError("");
        const res = await fetch("/api/auth/withdraw", { method: "DELETE", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ confirm: WITHDRAW_CONFIRM_TEXT }) });
        const data = await res.json() as { ok?: boolean; error?: string };
        if (!res.ok) { setWithdrawError(data.error ?? "탈퇴 처리 중 오류가 발생했습니다."); setWithdrawLoading(false); return; }
        router.push("/?withdrawn=1");
    };

    const handleNickCheck = async () => {
        const trimmed = nickInput.trim();
        if (!trimmed || trimmed === currentNickname) {
            setNickError("현재 닉네임과 동일합니다.");
            setNickCheckStatus("idle");
            return;
        }
        const validationError = validateNickname(trimmed);
        if (validationError) {
            setNickError(validationError);
            setNickCheckStatus("idle");
            return;
        }
        setNickError("");
        setNickCheckStatus("checking");
        try {
            const res = await fetch(`/api/user/nickname/check?nickname=${encodeURIComponent(trimmed)}`);
            const data = await res.json() as { available: boolean; error?: string };
            if (data.error) {
                setNickError(data.error);
                setNickCheckStatus("idle");
            } else {
                setNickCheckStatus(data.available ? "available" : "taken");
                if (!data.available) setNickError("이미 사용 중인 닉네임입니다.");
            }
        } catch {
            setNickCheckStatus("idle");
        }
    };

    const handleNickSave = async () => {
        if (nickSaving) return;
        const trimmed = nickInput.trim();
        if (trimmed === currentNickname) {
            setNickError("현재 닉네임과 동일합니다.");
            return;
        }
        if (nickCheckStatus !== "available") return;
        setNickSaving(true);
        setNickError("");
        const res = await fetch("/api/user/nickname", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ nickname: trimmed }),
        });
        const data = await res.json() as { nickname?: string; error?: string };
        setNickSaving(false);
        if (!res.ok) {
            setNickError(data.error ?? "저장 실패");
        } else {
            setNickSuccess(true);
            setTimeout(() => setNickSuccess(false), 3000);
            router.refresh();
        }
    };

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        if (!file.type.startsWith("image/")) {
            setAvatarError("이미지 파일만 업로드할 수 있습니다.");
            return;
        }
        if (file.size > AVATAR_MAX_SIZE_MB * 1024 * 1024) {
            setAvatarError(`이미지 크기는 ${AVATAR_MAX_SIZE_MB}MB 이하여야 합니다.`);
            return;
        }
        setAvatarError("");
        const reader = new FileReader();
        reader.onload = (ev) => { setAvatarPreview(ev.target?.result as string); };
        reader.readAsDataURL(file);
    };

    const handleAvatarSave = async (url: string | null) => {
        setAvatarSaving(true);
        setAvatarError("");
        try {
            const res = await fetch("/api/user/avatar", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ avatarUrl: url }),
            });
            let data: { avatarUrl?: string | null; error?: string } = {};
            try { data = await res.json() as typeof data; } catch { /* non-JSON response */ }
            if (!res.ok) {
                setAvatarError(data.error ?? "저장 실패");
            } else {
                setAvatarPreview(url);
                setAvatarSuccess(true);
                setTimeout(() => setAvatarSuccess(false), 3000);
                // 헤더 등 사이트 전체 프로필 사진 즉시 갱신
                window.dispatchEvent(new CustomEvent("avatar-updated"));
                router.refresh();
                // refresh 이후에도 한 번 더 발생시켜 타이밍 문제 방지
                setTimeout(() => window.dispatchEvent(new CustomEvent("avatar-updated")), 400);
            }
        } catch {
            setAvatarError("네트워크 오류가 발생했습니다.");
        } finally {
            setAvatarSaving(false);
        }
    };

    const displayNickname = session?.nickname ?? session?.name ?? "사용자";
    const isThemeMenu = activeMenu !== null && THEME_TAB_MAP[activeMenu] !== undefined;
    const isCreditMenu = activeMenu === "적립금";
    const isRefundMenu = activeMenu === "취소/환불 내역";
    const isOrderMenu = activeMenu === "주문 내역";
    const isLikeMenu = activeMenu === "좋아요";
    const isSalesStatsMenu = activeMenu === "판매 통계";
    const isSettlementMenu = activeMenu === "정산 내역";
    const isBankMenu = activeMenu === "정산 계좌";
    const isSettingsMenu = activeMenu === "회원 정보";
    const isNotifMenu = activeMenu === "알림 설정";
    const isWithdrawMenu = activeMenu === "회원 탈퇴";
    const isFollowMenu = activeMenu === "팔로우";
    const isReviewMenu = activeMenu === "리뷰";
    const isReviewableMenu = activeMenu === "작성 가능한 후기";
    const isSubInfoMenu = activeMenu === "결제 정보";
    const isSubPaymentsMenu = activeMenu === "결제 내역";

    type FollowingUser = { id: string; nickname: string | null; name: string; avatarUrl: string | null; role: string; themeCount: number };
    const [followingList, setFollowingList] = useState<FollowingUser[]>([]);
    const [followingLoading, setFollowingLoading] = useState(false);
    const [unfollowingId, setUnfollowingId] = useState<string | null>(null);

    useEffect(() => {
        if (!isFollowMenu) return;
        const load = async () => {
            setFollowingLoading(true);
            try {
                const r = await fetch("/api/mypage/following");
                const d = await r.json() as { following: FollowingUser[]; error?: string };
                if (d.error) console.error("[following]", d.error);
                setFollowingList(d.following ?? []);
            } catch {
                //
            } finally {
                setFollowingLoading(false);
            }
        };
        void load();
    }, [isFollowMenu]);

    const handleUnfollow = async (targetId: string) => {
        setUnfollowingId(targetId);
        await fetch("/api/follow", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ creatorId: targetId }),
        });
        setFollowingList(prev => prev.filter(u => u.id !== targetId));
        setUnfollowingId(null);
    };

    const handleMenuClick = (label: string) => {
        if (THEME_TAB_MAP[label] !== undefined) {
            setThemeTab(THEME_TAB_MAP[label]);
        }
        setActiveMenu(label);
    };

    return (
        <div className="flex w-full" style={{ maxWidth: 1400, margin: "0 auto" }}>

            {/* ── 사이드바 ── */}
            <aside className="fixed w-[160px] flex flex-col gap-1 px-5 pt-12" style={{ zIndex: 10 }}>
                {sidebarMenus.map((group, index) => (
                    <div key={group.category} className="flex flex-col gap-0.5">
                        <span className="text-[10.5px] font-bold tracking-[0.15em] uppercase px-2 mb-1" style={{ color: "#8e8e93" }}>
                            {group.category}
                        </span>
                        {group.items.map((item) => {
                            const isActive = activeMenu === item.label;
                            const isWithdrawItem = item.label === "회원 탈퇴";
                            return (
                                <button
                                    key={item.label}
                                    onClick={() => handleMenuClick(item.label)}
                                    className="text-left px-2 py-[7px] rounded-xl text-[12.5px] font-medium transition-all"
                                    style={{
                                        color: isWithdrawItem
                                            ? (isActive ? "#c0392b" : "#ff3b30")
                                            : isActive ? "#FF9500" : "#3a3a3c",
                                        fontWeight: isActive ? 700 : 500,
                                    }}
                                >
                                    {item.label}
                                </button>
                            );
                        })}
                        {index < sidebarMenus.length - 1 && (
                            <div className="my-2.5 h-[1px]" style={{ background: "rgba(0,0,0,0.18)" }} />
                        )}
                    </div>
                ))}
            </aside>

            {/* ── 메인 콘텐츠 ── */}
            <main className="flex-1 flex flex-col min-w-0 px-8 pt-12 pb-24" style={{ marginLeft: 200 }}>
                {session ? (
                    <>
                        {isThemeMenu ? (
                            <ThemeVaultTabs key={activeMenu} initialTab={themeTab} />
                        ) : isCreditMenu ? (
                            <CreditPage />
                        ) : isOrderMenu ? (
                            <OrderPage />
                        ) : isRefundMenu ? (
                            <RefundPage />
                        ) : isLikeMenu ? (
                            <LikePage />
                        ) : isSalesStatsMenu ? (
                            <SalesStatsPage />
                        ) : isSettlementMenu ? (
                            <SettlementPage role={session?.role} />
                        ) : isBankMenu ? (
                            <BankAccountPage role={session?.role} />
                        ) : isReviewMenu ? (
                            <MyReviewsPage />
                        ) : isReviewableMenu ? (
                            <ReviewablePage />
                        ) : isSubInfoMenu ? (
                            <SubscriptionInfoPage />
                        ) : isSubPaymentsMenu ? (
                            <SubscriptionPaymentsPage />
                        ) : isFollowMenu ? (
                            <>
                                {/* 섹션 헤더 */}
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Following</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>팔로우</h2>
                                    </div>
                                </div>
                                <p className="text-[13px] mb-8" style={{ color: "#78716c" }}>내가 팔로우한 크리에이터 목록입니다.</p>
                                <div className="flex flex-col">
                                    {followingLoading ? (
                                        <div className="flex items-center justify-center py-20">
                                            <span className="text-[14px]" style={{ color: "#a8a29e" }}>불러오는 중...</span>
                                        </div>
                                    ) : followingList.length === 0 ? (
                                        <div className="flex flex-col items-center justify-center py-24 gap-3">
                                            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                                <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/>
                                            </svg>
                                            <p className="text-[14px]" style={{ color: "#a8a29e" }}>아직 팔로우한 크리에이터가 없어요.</p>
                                        </div>
                                    ) : (
                                        followingList.map((user, idx) => (
                                            <div key={user.id}>
                                                <div className="flex items-center gap-4 py-4">
                                                    {/* 프로필 이미지 */}
                                                    <button onClick={() => router.push(`/creator/${user.id}`)} className="shrink-0 w-10 h-10 rounded-full overflow-hidden flex items-center justify-center transition-all hover:opacity-75" style={{ background: "#e7e5e4" }}>
                                                        <Image
                                                            src={
                                                                (user.avatarUrl && !user.avatarUrl.startsWith("/"))
                                                                    ? user.avatarUrl
                                                                    : (user.role === "CREATOR" || user.role === "ADMIN" ? "/creator.png" : "/user.png")
                                                            }
                                                            alt={user.nickname ?? user.name}
                                                            width={40} height={40}
                                                            className="w-full h-full object-cover"
                                                            unoptimized={!!user.avatarUrl && !user.avatarUrl.startsWith("/")}
                                                        />
                                                    </button>
                                                    {/* 이름 + 테마 수 */}
                                                    <div className="flex flex-col gap-0.5 flex-1 min-w-0">
                                                        <button onClick={() => router.push(`/creator/${user.id}`)} className="text-left text-[14px] font-semibold hover:opacity-60 transition-opacity truncate" style={{ color: "#1c1917" }}>
                                                            {user.nickname ?? user.name}
                                                        </button>
                                                        <span className="text-[12px]" style={{ color: "#a8a29e" }}>테마 {user.themeCount}개</span>
                                                    </div>
                                                    {/* 언팔로우 버튼 */}
                                                    <button
                                                        onClick={() => handleUnfollow(user.id)}
                                                        disabled={unfollowingId === user.id}
                                                        className="text-[12px] font-medium transition-opacity hover:opacity-50 disabled:opacity-30 shrink-0"
                                                        style={{ color: "#78716c" }}
                                                    >
                                                        {unfollowingId === user.id ? "처리 중..." : "팔로우 취소"}
                                                    </button>
                                                </div>
                                                {idx < followingList.length - 1 && (
                                                    <div className="h-px" style={{ background: "#f5f5f4" }} />
                                                )}
                                            </div>
                                        ))
                                    )}
                                </div>
                            </>
                        ) : isSettingsMenu ? (
                            /* ── 회원 정보 ── */
                            <>
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Account</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>회원 정보</h2>
                                    </div>
                                </div>

                                {/* 프로필 이미지 */}
                                <div className="flex flex-col gap-4 pb-8">
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>프로필 이미지</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    {isPro ? (
                                        /* PRO / ADMIN: 자유롭게 변경 가능 */
                                        (() => {
                                            // 역할에 따른 기본 이미지
                                            const defaultImg = isCreatorOrAdmin ? "/creator.png" : "/user.png";
                                            // 커스텀 사진: 사용자가 업로드한 data URL 또는 기본 경로가 아닌 외부 URL
                                            const isCustomPhoto = !!avatarPreview && !avatarPreview.startsWith("/");
                                            const displaySrc = avatarPreview ?? defaultImg;
                                            return (
                                                <div className="flex items-center gap-6">
                                                    <button
                                                        type="button"
                                                        onClick={() => fileInputRef.current?.click()}
                                                        className="relative group shrink-0 rounded-full overflow-hidden flex items-center justify-center transition-opacity hover:opacity-80"
                                                        style={{ width: 72, height: 72, background: "#e7e5e4" }}
                                                    >
                                                        <Image
                                                            src={displaySrc}
                                                            alt={displayNickname}
                                                            width={72} height={72}
                                                            className="w-full h-full object-cover"
                                                            unoptimized={isCustomPhoto}
                                                        />
                                                        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity rounded-full" style={{ background: "rgba(0,0,0,0.3)" }}>
                                                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                                                <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                                                                <polyline points="17 8 12 3 7 8" />
                                                                <line x1="12" y1="3" x2="12" y2="15" />
                                                            </svg>
                                                        </div>
                                                    </button>
                                                    <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
                                                    <div className="flex flex-col gap-2">
                                                        <div className="flex items-center gap-2">
                                                            <button type="button" onClick={() => fileInputRef.current?.click()} className="text-[12px] font-medium transition-opacity hover:opacity-60" style={{ color: "#78716c" }}>
                                                                사진 선택
                                                            </button>
                                                            {avatarPreview && avatarPreview !== (session?.avatarUrl ?? defaultImg) && (
                                                                <>
                                                                    <span style={{ color: "#e7e5e4" }}>·</span>
                                                                    <button type="button" onClick={() => handleAvatarSave(avatarPreview)} disabled={avatarSaving} className="text-[12px] font-semibold transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#FF9500" }}>
                                                                        {avatarSaving ? "저장 중..." : "저장"}
                                                                    </button>
                                                                </>
                                                            )}
                                                            {isCustomPhoto && (
                                                                <>
                                                                    <span style={{ color: "#e7e5e4" }}>·</span>
                                                                    <button type="button" onClick={() => { setAvatarPreview(null); if (fileInputRef.current) fileInputRef.current.value = ""; handleAvatarSave(null); }} disabled={avatarSaving} className="text-[12px] font-medium transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#ff3b30" }}>
                                                                        사진 제거
                                                                    </button>
                                                                </>
                                                            )}
                                                        </div>
                                                        {avatarSuccess && <p className="text-[11px]" style={{ color: "#34c759" }}>✓ 프로필 사진이 저장되었습니다.</p>}
                                                        {avatarError && <p className="text-[11px]" style={{ color: "#ff3b30" }}>{avatarError}</p>}
                                                        {!avatarSuccess && !avatarError && <p className="text-[11px]" style={{ color: "#a8a29e" }}>JPG, PNG, GIF · 최대 2MB</p>}
                                                    </div>
                                                </div>
                                            );
                                        })()
                                    ) : session?.role === "CREATOR" ? (
                                        /* 크리에이터: creator.png 고정 */
                                        <div className="flex items-center gap-6">
                                            <div className="relative shrink-0 rounded-full overflow-hidden" style={{ width: 72, height: 72, background: "#e7e5e4" }}>
                                                <Image src="/creator.png" alt="크리에이터 프로필" width={72} height={72} className="w-full h-full object-cover" />
                                            </div>
                                            <div className="flex flex-col gap-1">
                                                <p className="text-[13px] font-medium" style={{ color: "#1c1917" }}>크리에이터 기본 이미지</p>
                                                <p className="text-[12px] leading-relaxed" style={{ color: "#a8a29e" }}>크리에이터는 기본 이미지가 적용됩니다.</p>
                                            </div>
                                        </div>
                                    ) : (
                                        /* 일반 유저 (FREE): user.png 고정 */
                                        <div className="flex items-center gap-6">
                                            <div className="relative shrink-0 rounded-full overflow-hidden" style={{ width: 72, height: 72, background: "#e7e5e4" }}>
                                                <Image src="/user.png" alt="기본 프로필" width={72} height={72} className="w-full h-full object-cover" />
                                            </div>
                                            <div className="flex flex-col gap-1">
                                                <p className="text-[13px] font-medium" style={{ color: "#1c1917" }}>기본 프로필 이미지</p>
                                                <p className="text-[12px] leading-relaxed" style={{ color: "#a8a29e" }}>
                                                    <a href="/pricing" className="font-semibold" style={{ color: "#FF9500" }}>PRO 구독</a> 시 프로필 사진을 자유롭게 변경할 수 있습니다.
                                                </p>
                                            </div>
                                        </div>
                                    )}
                                </div>

                                {/* 닉네임 */}
                                <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>닉네임</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <div className="flex flex-col gap-2">
                                        <div className="flex items-center gap-3">
                                            <div className="relative">
                                                <input
                                                    value={nickInput}
                                                    onChange={(e) => { setNickInput(e.target.value); setNickSuccess(false); setNickCheckStatus("idle"); setNickError(""); }}
                                                    onKeyDown={(e) => { if (e.key === "Enter") handleNickCheck(); }}
                                                    maxLength={10}
                                                    placeholder="닉네임을 입력하세요"
                                                    className="text-[14px] px-0 py-2 outline-none pr-7 bg-transparent"
                                                    style={{
                                                        borderBottom: `1.5px solid ${nickCheckStatus === "available" ? "#34c759" : nickCheckStatus === "taken" || nickError ? "#ff3b30" : "#d6d3d1"}`,
                                                        color: "#1c1917",
                                                        width: 220,
                                                    }}
                                                />
                                                <div className="absolute right-0 top-1/2 -translate-y-1/2">
                                                    {nickCheckStatus === "checking" && <div className="w-3.5 h-3.5 rounded-full border-2 border-black/20 border-t-black/60 animate-spin" />}
                                                    {nickCheckStatus === "available" && (
                                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#34c759" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5" /></svg>
                                                    )}
                                                    {nickCheckStatus === "taken" && (
                                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
                                                    )}
                                                </div>
                                            </div>
                                            <button onClick={handleNickCheck} disabled={nickCheckStatus === "checking" || !nickInput.trim()} className="text-[12px] font-medium transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#4a7bf7" }}>
                                                {nickCheckStatus === "checking" ? "확인 중..." : "중복 확인"}
                                            </button>
                                            <button onClick={handleNickSave} disabled={nickSaving || nickCheckStatus !== "available" || nickInput.trim() === currentNickname} className="text-[12px] font-semibold transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#FF9500" }}>
                                                {nickSaving ? "저장 중..." : "저장"}
                                            </button>
                                        </div>
                                        <div className="flex items-center justify-between">
                                            <p className="text-[11px]" style={{ color: nickSuccess ? "#34c759" : nickCheckStatus === "available" && !nickError ? "#34c759" : nickError ? "#ff3b30" : "#a8a29e" }}>
                                                {nickSuccess ? "✓ 닉네임이 저장되었습니다." : nickCheckStatus === "available" && !nickError ? "✓ 사용 가능한 닉네임입니다." : nickError ? nickError : "한글, 영문, 숫자 2~10자 (특수문자 불가, 숫자만 불가)"}
                                            </p>
                                            <p className="text-[11px]" style={{ color: "#a8a29e" }}>{nickInput.trim().length} / 10</p>
                                        </div>
                                    </div>
                                </div>

                                {/* 이메일 */}
                                <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>이메일</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <span className="text-[14px]" style={{ color: session.email ? "#1c1917" : "#a8a29e" }}>
                                            {session.email ?? "이메일 정보 없음"}
                                        </span>
                                        {session.email && (
                                            <span className="text-[11px] font-semibold px-2 py-0.5 rounded-full" style={{ background: "rgba(52,199,89,0.1)", color: "#34c759" }}>인증됨</span>
                                        )}
                                    </div>
                                    <p className="text-[11px]" style={{ color: "#a8a29e" }}>이메일은 카카오 계정과 연동되어 있습니다. 변경을 원하시면 카카오 계정에서 수정해주세요.</p>
                                </div>

                                {/* 계정 등급 */}
                                <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>계정 등급</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <div>
                                        <span className="text-[12px] font-semibold px-2.5 py-1 rounded-full" style={{ background: session.role === "ADMIN" ? "rgba(255,59,48,0.1)" : session.role === "CREATOR" ? "rgba(255,149,0,0.1)" : "rgba(74,123,247,0.1)", color: session.role === "ADMIN" ? "#ff3b30" : session.role === "CREATOR" ? "#FF9500" : "#4a7bf7" }}>
                                            {session.role === "ADMIN" ? "관리자" : session.role === "CREATOR" ? "크리에이터" : "일반 회원"}
                                        </span>
                                    </div>
                                    <p className="text-[11px]" style={{ color: "#a8a29e" }}>현재 서비스 이용 등급입니다.</p>
                                </div>

                                {/* 가입일 */}
                                <div className="flex flex-col gap-2 pt-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <div className="flex items-center gap-3 mb-1">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>가입일</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <span className="text-[14px]" style={{ color: "#78716c" }}>{createdAt ? formatKST(createdAt, false) : "-"}</span>
                                </div>
                            </>
                        ) : isNotifMenu ? (
                            /* ── 알림 설정 ── */
                            <>
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Notifications</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>알림 설정</h2>
                                    </div>
                                    <div className="flex items-center gap-4 pb-1">
                                        {notifSaveSuccess && <span className="text-[12px]" style={{ color: "#34c759" }}>✓ 저장되었습니다.</span>}
                                        <button onClick={handleNotifSaveAll} disabled={notifSaving} className="text-[13px] font-semibold transition-opacity hover:opacity-60 disabled:opacity-30" style={{ color: "#FF9500" }}>
                                            {notifSaving ? "저장 중..." : "변경사항 저장"}
                                        </button>
                                    </div>
                                </div>
                                <p className="text-[13px] mb-10" style={{ color: "#78716c" }}>받고 싶은 알림을 직접 선택하세요.</p>

                                {NOTIFICATION_GROUPS.map((group, gi) => (
                                    <div key={group.category}>
                                        <div className={`flex items-center gap-3 ${gi > 0 ? "mt-10" : ""} mb-1`}>
                                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>
                                                {group.category}
                                            </span>
                                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                        </div>
                                        <div className="flex flex-col">
                                            {group.items.map((item, idx) => (
                                                <div key={item.key}>
                                                    <div className="flex items-center justify-between py-4">
                                                        <div className="flex flex-col gap-0.5">
                                                            <span className="text-[14px]" style={{ color: "#1c1917", fontWeight: notifSettings[item.key] ? 600 : 400 }}>{item.label}</span>
                                                            <span className="text-[12px]" style={{ color: "#a8a29e" }}>{item.desc}</span>
                                                        </div>
                                                        <button type="button" onClick={() => toggleNotif(item.key)} className="relative shrink-0 transition-all active:scale-95" style={{ width: 44, height: 24 }} aria-label={notifSettings[item.key] ? "끄기" : "켜기"}>
                                                            <div className="absolute inset-0 rounded-full transition-colors duration-200" style={{ background: notifSettings[item.key] ? "#FF9500" : "#e7e5e4" }} />
                                                            <div className="absolute top-[3px] w-[18px] h-[18px] rounded-full bg-white transition-all duration-200" style={{ left: notifSettings[item.key] ? 23 : 3, boxShadow: "0 1px 3px rgba(0,0,0,0.15)" }} />
                                                        </button>
                                                    </div>
                                                    {idx < group.items.length - 1 && <div className="h-px" style={{ background: "#f5f5f4" }} />}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}

                                <div className="mt-12 flex items-start gap-3 pt-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#4a7bf7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0 mt-0.5">
                                        <circle cx="12" cy="12" r="10" /><line x1="12" y1="8" x2="12" y2="12" /><line x1="12" y1="16" x2="12.01" y2="16" />
                                    </svg>
                                    <p className="text-[12px] leading-relaxed" style={{ color: "#78716c" }}>알림은 서비스 내 알림으로 제공됩니다. 이메일·푸시 알림은 추후 지원 예정입니다. 법적 필수 공지(이용약관 변경 등)는 설정과 관계없이 발송될 수 있습니다.</p>
                                </div>
                            </>
                        ) : isWithdrawMenu ? (
                            /* ── 회원 탈퇴 ── */
                            <>
                                <div className="flex items-end justify-between mb-8">
                                    <div>
                                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Account</p>
                                        <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>회원 탈퇴</h2>
                                    </div>
                                </div>
                                <p className="text-[13px] mb-10" style={{ color: "#78716c" }}>탈퇴 전 아래 내용을 꼭 확인해주세요.</p>

                                {/* 프로필 확인 */}
                                <div className="flex items-center gap-4 py-5" style={{ borderBottom: "1px solid #e7e5e4" }}>
                                    <div className="w-10 h-10 rounded-full overflow-hidden flex items-center justify-center shrink-0" style={{ background: "#ffe500" }}>
                                        {session.avatarUrl ? (
                                            <Image src={session.avatarUrl} alt={displayNickname} width={40} height={40} className="w-full h-full object-cover" unoptimized />
                                        ) : (
                                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#3A1D1D" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" /></svg>
                                        )}
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-[14px] font-semibold" style={{ color: "#1c1917" }}>{displayNickname}</p>
                                        <p className="text-[12px]" style={{ color: "#a8a29e" }}>{session.email ?? "이메일 없음"}</p>
                                    </div>
                                    <span className="text-[11px] font-semibold px-2.5 py-1 rounded-full" style={{ background: "rgba(255,59,48,0.08)", color: "#ff3b30" }}>탈퇴 예정</span>
                                </div>

                                {/* 주의사항 체크리스트 */}
                                <div className="mt-8 mb-2">
                                    <div className="flex items-center gap-3 mb-6">
                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z" /><line x1="12" y1="9" x2="12" y2="13" /><line x1="12" y1="17" x2="12.01" y2="17" /></svg>
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#ff3b30" }}>탈퇴 전 반드시 확인하세요</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "rgba(255,59,48,0.15)" }} />
                                    </div>
                                    <div className="flex flex-col gap-1">
                                        {CHECKLIST.map((text, idx) => (
                                            <button key={idx} type="button" onClick={() => toggleWithdrawCheck(idx)} className="flex items-start gap-3 text-left py-3 transition-opacity hover:opacity-70">
                                                <div className="shrink-0 w-4 h-4 rounded mt-0.5 flex items-center justify-center transition-all" style={{ background: withdrawChecked[idx] ? "#ff3b30" : "transparent", border: `1.5px solid ${withdrawChecked[idx] ? "#ff3b30" : "#d6d3d1"}` }}>
                                                    {withdrawChecked[idx] && <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5" /></svg>}
                                                </div>
                                                <span className="text-[13px] leading-relaxed" style={{ color: "#78716c" }}>{text}</span>
                                            </button>
                                        ))}
                                    </div>
                                    {!withdrawAllChecked && <p className="mt-3 text-[11px]" style={{ color: "#a8a29e" }}>위 항목을 모두 체크해야 탈퇴를 진행할 수 있습니다.</p>}
                                </div>

                                {/* 확인 문구 입력 */}
                                <div className="mt-8 flex flex-col gap-3" style={{ opacity: withdrawAllChecked ? 1 : 0.4, pointerEvents: withdrawAllChecked ? "auto" : "none" }}>
                                    <div className="flex items-center gap-3 mb-2">
                                        <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>탈퇴 확인</span>
                                        <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                                    </div>
                                    <p className="text-[12px]" style={{ color: "#78716c" }}>아래 입력창에 <span className="font-bold" style={{ color: "#ff3b30" }}>{WITHDRAW_CONFIRM_TEXT}</span> 를 입력하세요.</p>
                                    <input type="text" value={withdrawConfirmInput} onChange={(e) => setWithdrawConfirmInput(e.target.value)} placeholder={WITHDRAW_CONFIRM_TEXT} className="px-0 py-2.5 text-[14px] outline-none bg-transparent w-full max-w-[280px]" style={{ borderBottom: `1.5px solid ${withdrawConfirmMatch ? "#ff3b30" : "#d6d3d1"}`, color: "#1c1917" }} />
                                </div>

                                {withdrawError && <p className="mt-4 text-[13px]" style={{ color: "#ff3b30" }}>{withdrawError}</p>}

                                <div className="flex gap-3 mt-10">
                                    <button onClick={() => setActiveMenu("회원 정보")} className="flex-1 py-3 rounded-xl text-[14px] font-medium transition-opacity hover:opacity-60" style={{ border: "1px solid #e7e5e4", color: "#78716c", background: "transparent" }}>취소</button>
                                    <button onClick={handleWithdraw} disabled={!canWithdraw} className="flex-1 py-3 rounded-xl text-[14px] font-semibold transition-opacity disabled:opacity-30" style={{ background: canWithdraw ? "#ff3b30" : "#ff3b30", color: "#fff" }}>
                                        {withdrawLoading ? "탈퇴 처리 중..." : "탈퇴하기"}
                                    </button>
                                </div>
                            </>
                        ) : null}
                    </>
                ) : (
                    <div className="flex flex-col items-center justify-center py-32 gap-4">
                        <div className="w-12 h-12 rounded-full flex items-center justify-center" style={{ background: "#f5f5f4" }}>
                            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                <circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                            </svg>
                        </div>
                        <div className="flex flex-col gap-1.5 text-center">
                            <h2 className="text-[20px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>로그인이 필요해요</h2>
                            <p className="text-[13px]" style={{ color: "#a8a29e" }}>마이페이지를 이용하려면 카카오 로그인을 해주세요.</p>
                        </div>
                        <a href="/api/auth/kakao" className="mt-2">
                            <button className="px-7 py-3 rounded-xl text-[14px] font-bold transition-opacity hover:opacity-80 active:scale-95" style={{ background: "rgba(255,231,58,0.95)", color: "#3A1D1D" }}>
                                카카오 로그인
                            </button>
                        </a>
                    </div>
                )}
            </main>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";

type Subscription = {
    id: string;
    status: string;
    amount: number;
    cardCompany?: string | null;
    cardNumber?: string | null;
    startedAt: string;
    nextBillingAt: string | null;
    cancelledAt: string | null;
};

function formatDate(dateStr: string | null) {
    if (!dateStr) return "-";
    const d = new Date(dateStr);
    return `${d.getFullYear()}. ${String(d.getMonth() + 1).padStart(2, "0")}. ${String(d.getDate()).padStart(2, "0")}`;
}

export default function SubscriptionInfoPage() {
    const router = useRouter();
    const [sub, setSub] = useState<Subscription | null>(null);
    const [loading, setLoading] = useState(true);
    const [cancelConfirm, setCancelConfirm] = useState(false);
    const [cancelling, setCancelling] = useState(false);
    const [toast, setToast] = useState("");

    const showToast = (msg: string) => {
        setToast(msg);
        setTimeout(() => setToast(""), 3000);
    };

    useEffect(() => {
        const load = async () => {
            try {
                const res = await fetch("/api/subscription");
                const data = await res.json() as { subscription: Subscription | null; payments?: unknown[]; role?: string | null };
                setSub(data.subscription);
            } catch { /* ignore */ } finally {
                setLoading(false);
            }
        };
        void load();
    }, []);

    const handleCancel = async () => {
        setCancelling(true);
        try {
            const res = await fetch("/api/subscription", { method: "DELETE" });
            const data = await res.json() as { ok?: boolean; error?: string };
            if (!res.ok) {
                showToast(data.error ?? "해지 처리 중 오류가 발생했습니다.");
            } else {
                showToast("구독이 해지됐어요. 기간 만료 전까지 Pro 혜택은 유지돼요.");
                setCancelConfirm(false);
                // 상태 갱신
                setSub(prev => prev ? { ...prev, status: "CANCELLED", cancelledAt: new Date().toISOString() } : prev);
                setTimeout(() => router.refresh(), 1000);
            }
        } finally {
            setCancelling(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center py-20">
                <div className="w-8 h-8 rounded-full border-4 border-orange-200 border-t-orange-400 animate-spin" />
            </div>
        );
    }

    return (
        <>
            {toast && (
                <div className="fixed top-5 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-xl text-[13px] font-medium shadow-lg"
                    style={{ background: "#18181b", color: "#fff" }}>
                    {toast}
                </div>
            )}

            <div className="flex items-end justify-between mb-8">
                <div>
                    <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Subscription</p>
                    <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>결제 정보</h2>
                </div>
            </div>

            {!sub || sub.status?.toUpperCase() !== "ACTIVE" ? (
                /* 구독 없음 */
                <div className="flex flex-col items-center justify-center py-24 gap-5">
                    <div className="w-14 h-14 rounded-full flex items-center justify-center" style={{ background: "rgba(255,149,0,0.08)" }}>
                        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#FF9500" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="1" y="4" width="22" height="16" rx="2" ry="2"/><line x1="1" y1="10" x2="23" y2="10"/>
                        </svg>
                    </div>
                    <div className="text-center">
                        <p className="text-[16px] font-semibold mb-1" style={{ color: "#1c1917" }}>현재 구독 중인 요금제가 없어요</p>
                        <p className="text-[13px]" style={{ color: "#a8a29e" }}>Pro 플랜을 구독하면 더 많은 기능을 이용할 수 있어요.</p>
                    </div>
                    <button
                        onClick={() => router.push("/pricing")}
                        className="px-6 py-2.5 rounded-xl text-[13px] font-bold transition-all hover:brightness-110"
                        style={{ background: "linear-gradient(135deg, #FF9500, #FF6B00)", color: "#fff" }}>
                        Pro 구독하기
                    </button>
                </div>
            ) : (
                <div className="flex flex-col gap-0">
                    {/* 현재 요금제 */}
                    <div className="flex flex-col gap-4 pb-8">
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>사용 중인 요금제</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        <div className="flex items-center gap-3">
                            <span className="text-[15px] font-bold" style={{ color: "#1c1917" }}>Pro</span>
                            <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "rgba(255,149,0,0.1)", color: "#FF9500" }}>구독 중</span>
                        </div>
                        <p className="text-[13px]" style={{ color: "#78716c" }}>월 {sub.amount.toLocaleString()}원 · 자동 결제</p>
                    </div>

                    {/* 결제 수단 */}
                    <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>결제 수단</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        {sub.cardCompany || sub.cardNumber ? (
                            <div className="flex items-center gap-3">
                                <div className="flex items-center justify-center w-9 h-6 rounded-md" style={{ background: "rgba(0,0,0,0.06)" }}>
                                    <svg width="16" height="12" viewBox="0 0 24 16" fill="none">
                                        <rect x="0" y="0" width="24" height="16" rx="2" fill="#1c1c1e"/>
                                        <rect x="1" y="5" width="22" height="3" fill="rgba(255,255,255,0.15)"/>
                                    </svg>
                                </div>
                                <div>
                                    <p className="text-[14px] font-medium" style={{ color: "#1c1917" }}>
                                        {sub.cardCompany ?? "카드"} {sub.cardNumber ? `**** **** **** ${sub.cardNumber.slice(-4)}` : ""}
                                    </p>
                                </div>
                            </div>
                        ) : (
                            <p className="text-[13px]" style={{ color: "#a8a29e" }}>등록된 카드 정보가 없습니다.</p>
                        )}
                    </div>

                    {/* 등록일 / 다음 결제일 */}
                    <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>구독 정보</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        <div className="flex flex-col gap-3">
                            <div className="flex items-center justify-between">
                                <span className="text-[13px]" style={{ color: "#78716c" }}>구독 시작일</span>
                                <span className="text-[13px] font-medium" style={{ color: "#1c1917" }}>{formatDate(sub.startedAt)}</span>
                            </div>
                            <div className="flex items-center justify-between">
                                <span className="text-[13px]" style={{ color: "#78716c" }}>다음 결제일</span>
                                <span className="text-[13px] font-medium" style={{ color: "#1c1917" }}>{formatDate(sub.nextBillingAt)}</span>
                            </div>
                        </div>
                    </div>

                    {/* 구독 해지 */}
                    <div className="flex flex-col gap-4 pt-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>구독 관리</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>

                        {!cancelConfirm ? (
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-[14px] font-medium" style={{ color: "#1c1917" }}>구독 해지</p>
                                    <p className="text-[12px] mt-0.5" style={{ color: "#a8a29e" }}>해지해도 기간 만료 전까지 Pro 혜택은 유지돼요.</p>
                                </div>
                                <button
                                    onClick={() => setCancelConfirm(true)}
                                    className="text-[12px] font-medium px-4 py-2 rounded-xl transition-opacity hover:opacity-70"
                                    style={{ background: "rgba(255,59,48,0.08)", color: "#ff3b30" }}>
                                    해지하기
                                </button>
                            </div>
                        ) : (
                            <div className="rounded-2xl p-5 flex flex-col gap-4" style={{ background: "rgba(255,59,48,0.05)", border: "1px solid rgba(255,59,48,0.1)" }}>
                                <p className="text-[13px] font-medium" style={{ color: "#ff3b30" }}>정말 구독을 해지하시겠어요?</p>
                                <p className="text-[12px]" style={{ color: "#78716c" }}>
                                    해지 후에도 <strong>{formatDate(sub.nextBillingAt)}</strong>까지는 Pro 혜택이 유지됩니다.
                                    이후에는 무료 플랜으로 전환됩니다.
                                </p>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => setCancelConfirm(false)}
                                        className="flex-1 py-2.5 rounded-xl text-[13px] font-medium transition-opacity hover:opacity-70"
                                        style={{ background: "rgba(0,0,0,0.06)", color: "#78716c" }}>
                                        취소
                                    </button>
                                    <button
                                        onClick={handleCancel}
                                        disabled={cancelling}
                                        className="flex-1 py-2.5 rounded-xl text-[13px] font-semibold transition-opacity hover:opacity-70 disabled:opacity-40"
                                        style={{ background: "rgba(255,59,48,0.12)", color: "#ff3b30" }}>
                                        {cancelling ? "처리 중..." : "해지 확인"}
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";

type Subscription = {
    id: string;
    status: string;
    amount: number;
    cardCompany?: string | null;
    cardNumber?: string | null;
    startedAt: string;
    nextBillingAt: string | null;
    cancelledAt: string | null;
};

function formatDate(dateStr: string | null) {
    if (!dateStr) return "-";
    const d = new Date(dateStr);
    return `${d.getFullYear()}. ${String(d.getMonth() + 1).padStart(2, "0")}. ${String(d.getDate()).padStart(2, "0")}`;
}

export default function SubscriptionInfoPage() {
    const router = useRouter();
    const [sub, setSub] = useState<Subscription | null>(null);
    const [loading, setLoading] = useState(true);
    const [cancelConfirm, setCancelConfirm] = useState(false);
    const [cancelling, setCancelling] = useState(false);
    const [toast, setToast] = useState("");

    const showToast = (msg: string) => {
        setToast(msg);
        setTimeout(() => setToast(""), 3000);
    };

    useEffect(() => {
        const load = async () => {
            try {
                const res = await fetch("/api/subscription");
                const data = await res.json() as { subscription: Subscription | null; payments?: unknown[]; role?: string | null };
                setSub(data.subscription);
            } catch { /* ignore */ } finally {
                setLoading(false);
            }
        };
        void load();
    }, []);

    const handleCancel = async () => {
        setCancelling(true);
        try {
            const res = await fetch("/api/subscription", { method: "DELETE" });
            const data = await res.json() as { ok?: boolean; error?: string };
            if (!res.ok) {
                showToast(data.error ?? "해지 처리 중 오류가 발생했습니다.");
            } else {
                showToast("구독이 해지됐어요. 기간 만료 전까지 Pro 혜택은 유지돼요.");
                setCancelConfirm(false);
                // 상태 갱신
                setSub(prev => prev ? { ...prev, status: "CANCELLED", cancelledAt: new Date().toISOString() } : prev);
                // 헤더 등 사이트 전체 프로필 사진 기본값으로 즉시 갱신
                window.dispatchEvent(new CustomEvent("avatar-updated"));
                setTimeout(() => router.refresh(), 1000);
                setTimeout(() => window.dispatchEvent(new CustomEvent("avatar-updated")), 1200);
            }
        } finally {
            setCancelling(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center py-20">
                <div className="w-8 h-8 rounded-full border-4 border-orange-200 border-t-orange-400 animate-spin" />
            </div>
        );
    }

    return (
        <>
            {toast && (
                <div className="fixed top-5 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-xl text-[13px] font-medium shadow-lg"
                    style={{ background: "#18181b", color: "#fff" }}>
                    {toast}
                </div>
            )}

            <div className="flex items-end justify-between mb-8">
                <div>
                    <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Subscription</p>
                    <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>결제 정보</h2>
                </div>
            </div>

            {!sub || sub.status?.toUpperCase() !== "ACTIVE" ? (
                /* 구독 없음 */
                <div className="flex flex-col items-center justify-center py-24 gap-5">
                    <div className="w-14 h-14 rounded-full flex items-center justify-center" style={{ background: "rgba(255,149,0,0.08)" }}>
                        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#FF9500" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="1" y="4" width="22" height="16" rx="2" ry="2"/><line x1="1" y1="10" x2="23" y2="10"/>
                        </svg>
                    </div>
                    <div className="text-center">
                        <p className="text-[16px] font-semibold mb-1" style={{ color: "#1c1917" }}>현재 구독 중인 요금제가 없어요</p>
                        <p className="text-[13px]" style={{ color: "#a8a29e" }}>Pro 플랜을 구독하면 더 많은 기능을 이용할 수 있어요.</p>
                    </div>
                    <button
                        onClick={() => router.push("/pricing")}
                        className="px-6 py-2.5 rounded-xl text-[13px] font-bold transition-all hover:brightness-110"
                        style={{ background: "linear-gradient(135deg, #FF9500, #FF6B00)", color: "#fff" }}>
                        Pro 구독하기
                    </button>
                </div>
            ) : (
                <div className="flex flex-col gap-0">
                    {/* 현재 요금제 */}
                    <div className="flex flex-col gap-4 pb-8">
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>사용 중인 요금제</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        <div className="flex items-center gap-3">
                            <span className="text-[15px] font-bold" style={{ color: "#1c1917" }}>Pro</span>
                            <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "rgba(255,149,0,0.1)", color: "#FF9500" }}>구독 중</span>
                        </div>
                        <p className="text-[13px]" style={{ color: "#78716c" }}>월 {sub.amount.toLocaleString()}원 · 자동 결제</p>
                    </div>

                    {/* 결제 수단 */}
                    <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>결제 수단</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        {sub.cardCompany || sub.cardNumber ? (
                            <div className="flex items-center gap-3">
                                <div className="flex items-center justify-center w-9 h-6 rounded-md" style={{ background: "rgba(0,0,0,0.06)" }}>
                                    <svg width="16" height="12" viewBox="0 0 24 16" fill="none">
                                        <rect x="0" y="0" width="24" height="16" rx="2" fill="#1c1c1e"/>
                                        <rect x="1" y="5" width="22" height="3" fill="rgba(255,255,255,0.15)"/>
                                    </svg>
                                </div>
                                <div>
                                    <p className="text-[14px] font-medium" style={{ color: "#1c1917" }}>
