                    <div className="flex flex-col gap-1.5">
                        <label className="text-[12px] font-semibold flex items-center gap-1" style={{ color: "#3a3a3c" }}>
                            추천인 닉네임
                            <span className="text-[11px] font-normal" style={{ color: "#8e8e93" }}>(선택 · 입력 시 500원 적립)</span>
                        </label>
                        <input
                            type="text"
                            value={referralCode}
                            onChange={e => { setReferralCode(e.target.value); setReferralMsg(null); }}
                            placeholder="추천인의 카꾸미 닉네임을 입력해주세요"
                            maxLength={10}
                            className="w-full px-4 py-3 rounded-xl text-[14px] outline-none"
                            style={{
                                background: "rgba(255,255,255,0.9)",
                                border: `1.5px solid ${referralMsg?.ok === false ? "#ff3b30" : referralMsg?.ok === true ? "#34c759" : "rgba(0,0,0,0.12)"}`,
                                color: "#1c1c1e",
                                transition: "border-color 0.15s",
                            }}
                        />
                        {referralMsg && (
                            <p className="text-[11px]" style={{ color: referralMsg.ok ? "#34c759" : "#ff3b30" }}>{referralMsg.text}</p>
                        )}
                    </div>

                    <button
                        type="submit"
                        disabled={checkStatus !== "available" || saving}
                        className="w-full py-3.5 rounded-xl text-[15px] font-bold transition-all hover:brightness-105 active:scale-[0.98] disabled:opacity-40"
                        style={{ background: "rgba(255,231,58,0.95)", color: "#3A1D1D", boxShadow: "0 4px 16px rgba(255,200,0,0.25)" }}
                    >
                        {saving ? "저장 중..." : "시작하기"}
                    </button>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { validateNickname } from "@/lib/nickname";
import Image from "next/image";

export default function OnboardingPage() {
    const router = useRouter();
    const [nickname, setNickname] = useState("");
    const [error, setError] = useState("");
    const [checkStatus, setCheckStatus] = useState<"idle" | "checking" | "available" | "taken">("idle");
    const [saving, setSaving] = useState(false);
    const [referralCode, setReferralCode] = useState("");
    const [referralMsg, setReferralMsg] = useState<{ ok: boolean; text: string } | null>(null);
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);


    // 입력할 때마다 실시간 중복 체크 (debounce)
    useEffect(() => {
        if (debounceRef.current) clearTimeout(debounceRef.current);

        debounceRef.current = setTimeout(() => {
            const validationError = validateNickname(nickname);
            if (validationError) {
                setError(validationError);
                setCheckStatus("idle");
                return;
            }

            setError("");
            setCheckStatus("checking");

            fetch(`/api/user/nickname/check?nickname=${encodeURIComponent(nickname)}`)
                .then((res) => res.json())
                .then((data: { available: boolean; error?: string }) => {
                    if (data.error) {
                        setError(data.error);
                        setCheckStatus("idle");
                    } else {
                        setCheckStatus(data.available ? "available" : "taken");
                        if (!data.available) setError("이미 사용 중인 닉네임입니다.");
                    }
                })
                .catch(() => setCheckStatus("idle"));
        }, 500);
    }, [nickname]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (checkStatus !== "available" || saving) return;

        setSaving(true);

        // 닉네임 + 추천인 코드 저장
        const res = await fetch("/api/user/nickname", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ nickname, referralCode: referralCode.trim() || null }),
        });
        const data = await res.json() as { nickname?: string; error?: string };

        if (!res.ok) {
            const errorMsg = data.error ?? "저장 실패";
            if (errorMsg.includes("닉네임")) {
                setReferralMsg({ ok: false, text: errorMsg });
            } else {
                setError(errorMsg);
            }
            setSaving(false);
            return;
        }


        setSaving(false);
        router.push("/");
    };

    return (
        <div
            className="min-h-screen flex flex-col items-center justify-center px-4"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <div
                className="w-full max-w-[440px] flex flex-col gap-7 p-10 rounded-[28px]"
                style={{
                    background: "rgba(255,255,255,0.85)",
                    backdropFilter: "blur(20px)",
                    boxShadow: "0 8px 40px rgba(0,0,0,0.08)",
                    border: "1px solid rgba(255,255,255,0.9)",
                }}
            >
                {/* 로고 */}
                <div className="flex flex-col items-center gap-3">
                    <Image src="/카꾸미.png" alt="카꾸미" width={52} height={52} className="rounded-[14px]" />
                    <div className="flex flex-col items-center gap-1">
                        <h1 className="text-[22px] font-extrabold" style={{ color: "#1c1c1e", fontFamily: "'ChosunIlboMyungjo', serif" }}>
                            카꾸미에 오신 걸 환영해요!
                        </h1>
                        <p className="text-[13px] text-center leading-relaxed" style={{ color: "#8e8e93" }}>
                            프로필을 설정하고 시작해보세요.
                        </p>
                    </div>
                </div>

                {/* 입력 폼 */}
                <form onSubmit={handleSubmit} className="flex flex-col gap-6">

                    {/* 닉네임 */}
                    <div className="flex flex-col gap-3">
                        {/* 규칙 안내 */}
                        <div
                            className="flex flex-col gap-1.5 px-4 py-3 rounded-[12px] text-[12px] leading-relaxed"
                            style={{ background: "rgba(74,123,247,0.07)", color: "#3a5a8a" }}
                        >
                            <p className="font-semibold">닉네임 규칙</p>
                            <ul className="flex flex-col gap-0.5 list-disc list-inside" style={{ color: "#48484a" }}>
                                <li>2~10자 이내</li>
                                <li>한글, 영문, 숫자 사용 가능</li>
                                <li>특수문자 불가</li>
                                <li>숫자만으로는 설정 불가</li>
                            </ul>
                        </div>

                        <div className="flex flex-col gap-1.5">
                            <label className="text-[12px] font-semibold" style={{ color: "#3a3a3c" }}>
                                닉네임 <span style={{ color: "#FF3B30" }}>*</span>
                            </label>
                            <div className="relative">
                                <input
                                    type="text"
                                    value={nickname}
                                    onChange={(e) => setNickname(e.target.value)}
                                    placeholder="닉네임을 입력해주세요"
                                    maxLength={10}
                                    autoFocus
                                    className="w-full px-4 py-3 rounded-xl text-[14px] outline-none pr-10"
                                    style={{
                                        background: "rgba(255,255,255,0.9)",
                                        border: `1.5px solid ${
                                            checkStatus === "available" ? "#34c759"
                                            : checkStatus === "taken" || error ? "#ff3b30"
                                            : "rgba(0,0,0,0.12)"
                                        }`,
                                        color: "#1c1c1e",
                                        transition: "border-color 0.15s",
                                    }}
                                />
                                {/* 상태 아이콘 */}
                                <div className="absolute right-3 top-1/2 -translate-y-1/2">
                                    {checkStatus === "checking" && (
                                        <div className="w-4 h-4 rounded-full border-2 border-black/20 border-t-black/60 animate-spin" />
                                    )}
                                    {checkStatus === "available" && (
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#34c759" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <path d="M20 6L9 17l-5-5" />
                                        </svg>
                                    )}
                                    {checkStatus === "taken" && (
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
                                        </svg>
                                    )}
                                </div>
                            </div>

                            {/* 상태 메시지 */}
                            <div className="flex items-center justify-between">
                                <p className="text-[11px]" style={{ color: checkStatus === "available" ? "#34c759" : "#ff3b30", minHeight: 16 }}>
                                    {checkStatus === "available" ? "사용 가능한 닉네임입니다." : error}
                                </p>
                                <p className="text-[11px]" style={{ color: "#8e8e93" }}>{nickname.length} / 10</p>
                            </div>
                        </div>
                    </div>

                    {/* 추천인 닉네임 (선택) */}
                    <div className="flex flex-col gap-1.5">
                        <label className="text-[12px] font-semibold flex items-center gap-1" style={{ color: "#3a3a3c" }}>
                            추천인 닉네임
                            <span className="text-[11px] font-normal" style={{ color: "#8e8e93" }}>(선택 · 입력 시 500원 적립)</span>
                        </label>
                        <input
                            type="text"
                            value={referralCode}
                            onChange={e => { setReferralCode(e.target.value); setReferralMsg(null); }}
                            placeholder="추천인의 카꾸미 닉네임을 입력해주세요"
                            maxLength={10}
                            className="w-full px-4 py-3 rounded-xl text-[14px] outline-none"
                            style={{
                                background: "rgba(255,255,255,0.9)",
                                border: `1.5px solid ${referralMsg?.ok === false ? "#ff3b30" : referralMsg?.ok === true ? "#34c759" : "rgba(0,0,0,0.12)"}`,
                                color: "#1c1c1e",
                                transition: "border-color 0.15s",
                            }}
                        />
                        {referralMsg && (
                            <p className="text-[11px]" style={{ color: referralMsg.ok ? "#34c759" : "#ff3b30" }}>{referralMsg.text}</p>
                        )}
                    </div>

                    <button
                        type="submit"
                        disabled={checkStatus !== "available" || saving}
                        className="w-full py-3.5 rounded-xl text-[15px] font-bold transition-all hover:brightness-105 active:scale-[0.98] disabled:opacity-40"
                        style={{ background: "rgba(255,231,58,0.95)", color: "#3A1D1D", boxShadow: "0 4px 16px rgba(255,200,0,0.25)" }}
                    >
                        {saving ? "저장 중..." : "시작하기"}
                    </button>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Script from "next/script";
import LoginRequiredModal from "@/app/components/LoginRequiredModal";

type Props = {
    isLoggedIn: boolean;
    isSubscribed: boolean;
    subscriptionStatus: string | null;
    role: string | null;
};

const FREE_FEATURES = [
    { label: "테마 에디터 기본 기능", included: true },
    { label: "내 테마 저장 (최대 5개)", included: true },
    { label: "테마 스토어 이용", included: true },
    { label: "꾸미 갤러리 이용", included: true },
    { label: "무료 테마 다운로드", included: true },
    { label: "테마 복사/복제", included: false },
    { label: "내 테마 저장 무제한", included: false },
    { label: "Pro 전용 프리셋 팔레트", included: false },
    { label: "Pro 전용 프로필 뱃지 ✦", included: false },
    { label: "광고 없는 UI (추후 적용)", included: false },
];

const PRO_FEATURES = [
    { label: "테마 에디터 기본 기능", included: true },
    { label: "내 테마 저장 무제한", included: true },
    { label: "테마 스토어 이용", included: true },
    { label: "꾸미 갤러리 이용", included: true },
    { label: "무료 테마 다운로드", included: true },
    { label: "테마 복사/복제", included: true },
    { label: "Pro 전용 프리셋 팔레트", included: true },
    { label: "Pro 전용 프로필 뱃지 ✦", included: true },
    { label: "광고 없는 UI (추후 적용)", included: true },
];

export default function PricingClient({ isLoggedIn, isSubscribed }: Props) {
    const router = useRouter();
    const [loginModal, setLoginModal] = useState(false);
    const [loading, setLoading] = useState(false);
    const [toast, setToast] = useState("");

    const showToast = (msg: string) => {
        setToast(msg);
        setTimeout(() => setToast(""), 3000);
    };

    const handleSubscribe = async () => {
        if (!isLoggedIn) { setLoginModal(true); return; }
        if (isSubscribed) { showToast("이미 구독 중입니다."); return; }

        setLoading(true);
        try {
            const clientKey = process.env.NEXT_PUBLIC_TOSSPAYMENTS_CLIENT_KEY;
            if (!clientKey) {
                showToast("결제 설정 오류입니다.");
                setLoading(false);
                return;
            }

            const win = window as unknown as Record<string, unknown>;
            const TossPayments = win["TossPayments"] as ((key: string) => { requestPayment: (method: string, opts: Record<string, unknown>) => Promise<void> }) | undefined;
            if (!TossPayments) {
                showToast("결제 모듈 로딩 중입니다. 잠시 후 다시 시도해주세요.");
                setLoading(false);
                return;
            }

            const toss = TossPayments(clientKey);
            const orderId = `sub_${Date.now().toString(36)}`;

            await toss.requestPayment("카드", {
                amount: 4900,
                orderId,
                orderName: "카꾸미 Pro 구독 (1개월)",
                customerName: "카꾸미 고객",
                successUrl: `${window.location.origin}/payment/subscription/success`,
                failUrl: `${window.location.origin}/pricing?fail=1`,
            });
            // requestPayment는 페이지 리다이렉트됨 — 이후 코드 실행 안 됨
        } catch (e: unknown) {
            if (e && typeof e === "object" && "code" in e && (e as { code: string }).code === "USER_CANCEL") {
                showToast("결제가 취소되었습니다.");
