                <h2 className="text-[20px] font-bold mb-8 text-center" style={{ color: "#1c1c1e" }}>상세 기능 비교</h2>
                <div className="rounded-3xl overflow-hidden" style={{ border: "1.5px solid rgba(0,0,0,0.07)" }}>
                    {/* 테이블 헤더 */}
                    <div className="grid grid-cols-3 px-6 py-4" style={{ background: "#f7f7f8", borderBottom: "1px solid rgba(0,0,0,0.07)" }}>
                        <div className="text-[12px] font-bold" style={{ color: "#aeaeb2" }}>기능</div>
                        <div className="text-[13px] font-bold text-center" style={{ color: "#aeaeb2" }}>Free</div>
                        <div className="text-[13px] font-bold text-center" style={{ color: "#FF9500" }}>Pro</div>
                    </div>

                    {[
                        { category: "테마 에디터", rows: [
                            { label: "테마 에디터 기본 이용", free: "✓", pro: "✓" },
                            { label: "내 테마 저장", free: "최대 5개", pro: "무제한" },
                            { label: "테마 복사/복제", free: "✗", pro: "✓" },
                            { label: "Pro 전용 프리셋 팔레트", free: "✗", pro: "✓" },
                        ]},
                        { category: "스토어 & 커뮤니티", rows: [
                            { label: "테마 스토어 이용", free: "✓", pro: "✓" },
                            { label: "무료 테마 다운로드", free: "✓", pro: "✓" },
                            { label: "유료 테마 구매", free: "✓", pro: "✓" },
                            { label: "꾸미 갤러리 이용", free: "✓", pro: "✓" },
                        ]},
                        { category: "혜택", rows: [
                            { label: "프로필 사진 자유 변경", free: "✗", pro: "✓" },
                            { label: "광고 없는 UI", free: "✗", pro: "✓ (추후 적용)" },
                        ]},
                    ].map((section) => (
                        <div key={section.category}>
                            <div className="px-6 py-3" style={{ background: "rgba(255,149,0,0.04)", borderBottom: "1px solid rgba(0,0,0,0.05)" }}>
                                <span className="text-[11px] font-bold tracking-widest uppercase" style={{ color: "#FF9500" }}>{section.category}</span>
                            </div>
                            {section.rows.map((row, i) => (
                                <div key={row.label} className="grid grid-cols-3 px-6 py-4 items-center"
                                    style={{ borderBottom: i < section.rows.length - 1 ? "1px solid rgba(0,0,0,0.04)" : "none", background: "#fff" }}>
                                    <span className="text-[13px]" style={{ color: "#3a3a3c" }}>{row.label}</span>
                                    <span className="text-[13px] text-center font-medium"
                                        style={{ color: row.free === "✗" ? "#e5e5ea" : row.free === "✓" ? "#34c759" : "#3a3a3c" }}>
                                        {row.free}
                                    </span>
                                    <span className="text-[13px] text-center font-semibold"
                                        style={{ color: row.pro === "✗" ? "#e5e5ea" : "#FF9500" }}>
                                        {row.pro}
                                    </span>
                                </div>
                            ))}
                        </div>
                    ))}
                </div>
            </div>

            {/* 하단 CTA */}
            {!isSubscribed && (
                <div className="text-center mt-16">
                    <button onClick={handleSubscribe} disabled={loading}
                        className="px-10 py-4 rounded-2xl text-[15px] font-bold transition-all hover:brightness-110 active:scale-[0.98] disabled:opacity-50"
                        style={{ background: "linear-gradient(135deg, #FF9500, #FF6B00)", color: "#fff", boxShadow: "0 8px 30px rgba(255,149,0,0.3)" }}>
                        {loading ? "처리 중..." : "지금 Pro 시작하기 — 월 4,900원"}
                    </button>
                    <p className="text-[12px] mt-3" style={{ color: "#aeaeb2" }}>언제든지 해지 가능 · 해지 후 기간 만료까지 혜택 유지</p>
                </div>
            )}

            {/* 토스페이먼츠 SDK */}
            <Script src="https://js.tosspayments.com/v1/payment" strategy="beforeInteractive" />
        </main>
    );
}

"use client";

import { useState, useEffect } from "react";
import Image from "next/image";
import { useRouter } from "next/navigation";
import { THEME_COLORS } from "@/app/store/data";
import { getPreviewSlots } from "./ThemeImageViewer";
import ThemeActionButtons from "./ThemeActionButtons";
import CreatorInquiryModal from "./CreatorInquiryModal";

function getPurchaseCredit(price: number): number {
    if (price === 0) return 0;
    if (price <= 500) return 10;
    if (price <= 1000) return 20;
    if (price <= 1500) return 30;
    if (price <= 2000) return 40;
    return 50;
}

function getReviewCredit(price: number): number {
    if (price === 0) return 0;
    if (price <= 500) return 30;
    if (price <= 1000) return 70;
    if (price <= 1500) return 120;
    if (price <= 2000) return 180;
    return 250;
}

type Stats = {
    sales: number;
    createdAt: string;
    likes: number;
    rating: number;
    reviews: number;
};

type ThemeVersion = { id: string; version: string; kthemeFileUrl: string | null; apkFileUrl: string | null };

type Props = {
    images: string[];
    previews: string[];
    name: string;
    tag?: string;
    themeId?: number;
    price: string;
    priceNum: number;
    author: string;
    creatorId: string;
    description: string;
    category: string[];
    stats: Stats;
    dbId: string;
    isLoggedIn: boolean;
    userId?: string;
    isOwned?: boolean;
    ownedVersionIds?: string[];
    versions?: ThemeVersion[];
    isSelling?: boolean;
};

export default function ThemeDetailLayout({
    images, previews, name, tag, themeId,
    price, priceNum, author, creatorId, description, category,
    stats, dbId, isLoggedIn, userId, isOwned, ownedVersionIds = [], versions = [],
    isSelling = true,
}: Props) {
    const router = useRouter();
    const colors = themeId ? THEME_COLORS[themeId] : undefined;
    const realImages = [...(images ?? []), ...(previews ?? [])].filter((s) => s && s !== "/back.jpg");
    const useColor = realImages.length === 0 && !!colors;
    const [activeIdx, setActiveIdx] = useState(0);
    const [likeCount, setLikeCount] = useState(stats.likes);
    const [showInquiryModal, setShowInquiryModal] = useState(false);

    const { slots } = getPreviewSlots(themeId, images, previews);

    // 좋아요 수 초기 로드
    useEffect(() => {
        fetch(`/api/themes/${dbId}/like`)
            .then(r => r.json())
            .then((d: { liked: boolean; count: number }) => {
                setLikeCount(d.count);
            })
            .catch(() => {});
    }, [dbId, setLikeCount]);

    const mainBg = useColor ? (slots[activeIdx] as string) ?? colors!.main : undefined;
    const mainSrc = useColor ? null : (realImages[activeIdx] ?? null);

    return (
        <div className="grid grid-cols-1 lg:grid-cols-[580px_1fr] gap-16">
            {/* 왼쪽: 메인 이미지 */}
            <div
                className="rounded-[28px] overflow-hidden relative shrink-0"
                style={{
                    width: "580px",
                    height: "580px",
                    background: mainBg ?? "rgba(0,0,0,0.06)",
                    boxShadow: "0 8px 40px rgba(0,0,0,0.10)",
                    border: "1px solid rgba(0,0,0,0.06)",
                    transition: "background 0.25s ease",
                }}
            >
                {mainSrc && (
                    <Image src={mainSrc} alt={name} fill className="object-cover transition-opacity duration-200" />
                )}
                {useColor && (
                    <div className="absolute inset-0 flex items-center justify-center">
                        <span className="text-white/50 text-[15px] font-semibold tracking-wide">{name}</span>
                    </div>
                )}
                {tag && (
                    <span
                        className="absolute top-5 left-5 text-[12px] font-bold px-3 py-1 rounded-full backdrop-blur-md"
                        style={{
                            background: tag === "무료" ? "rgba(255, 239, 154, 0.92)" : "rgba(170, 189, 232, 0.92)",
                            color: "#1c1c1e",
                        }}
                    >
                        {tag}
                    </span>
                )}
            </div>

            {/* 오른쪽: 상세 정보 */}
            <div className="flex flex-col justify-between py-2 min-w-0">
                {/* 상단 */}
                <div>
                    <div className="mb-6">
                        <div className="flex items-start justify-between gap-4 mt-1">
                            <h1 className="text-[28px] font-extrabold leading-tight text-gray-900 break-words min-w-0" style={{ fontFamily: "'ChosunIlboMyungjo', serif" }}>
                                {name}
                            </h1>
                            <div className="flex flex-col items-end shrink-0 pt-1">
                                <span className="text-[28px] font-bold text-gray-900">{price}</span>
                                {priceNum > 0 && priceNum < 2000 && (
                                    <p className="text-[12px] text-red-400 font-medium mt-0.5">✨ 출시 기념 할인 중</p>
                                )}
                            </div>
                        </div>
                        <p className="text-[14px] text-gray-400 mt-2">
                            by{" "}
                            <button
                                onClick={() => router.push(`/creator/${creatorId}`)}
                                className="text-gray-600 font-semibold hover:underline transition-all"
                            >
                                {author}
                            </button>
                        </p>
                    </div>

                    {/* 카테고리 태그 */}
                    <div className="flex flex-wrap gap-2 mb-6">
                        {category.map((cat) => (
                            <span
                                key={cat}
                                className="text-[12px] font-medium px-3 py-1 rounded-full bg-gray-100 text-gray-500 hover:bg-gray-200 transition-colors cursor-default"
                            >
                                # {cat}
                            </span>
                        ))}
                    </div>
                </div>

                {/* 하단 */}
                <div className="flex flex-col gap-6">
                    {/* 미니 프리뷰 — 설명 텍스트 위 */}
                    <div className="grid grid-cols-5 gap-2">
                        {slots.slice(0, 5).map((slot, i) => (
                            <button
                                key={i}
                                onMouseEnter={() => setActiveIdx(i)}
                                onClick={() => setActiveIdx(i)}
                                className="aspect-square rounded-[10px] overflow-hidden relative"
                                style={{
                                    background: useColor ? (slot as string) : "rgba(0,0,0,0.06)",
                                    border: activeIdx === i ? "2px solid #4A7BF7" : "1px solid rgba(0,0,0,0.08)",
                                    opacity: activeIdx === i ? 1 : 0.6,
                                    transition: "opacity 0.15s, border 0.15s",
                                }}
                            >
                                {!useColor && (
                                    <Image src={slot as string} alt={`preview-${i + 1}`} fill className="object-cover" />
                                )}
                            </button>
                        ))}
                    </div>

                    {/* 설명 */}
                    <p className="text-[15px] leading-relaxed text-gray-500 break-words overflow-hidden">{description}</p>

                    {/* 통계 */}
                    <div className="flex items-center gap-12">
                        <div className="flex flex-col gap-0.5">
                            <span className="text-[11px] text-gray-400 font-medium uppercase tracking-wider">Sales</span>
                            <span className="text-[16px] font-bold text-gray-800">{stats.sales.toLocaleString()}</span>
                        </div>
                        <div className="flex flex-col gap-0.5">
                            <span className="text-[11px] text-gray-400 font-medium uppercase tracking-wider">Published</span>
                            <span className="text-[16px] font-bold text-gray-800">{stats.createdAt}</span>
                        </div>
                        <div className="flex flex-col gap-0.5">
                                <span className="text-[11px] text-gray-400 font-medium uppercase tracking-wider">Likes</span>
                                <span className="text-[16px] font-bold text-gray-800">{likeCount}</span>
                            </div>
                        <div className="flex flex-col gap-0.5">
                            <span className="text-[11px] text-gray-400 font-medium uppercase tracking-wider">Rating</span>
                            <div className="flex items-center gap-1">
                                <svg width="13" height="13" viewBox="0 0 24 24" fill="#FFB800" stroke="#FFB800" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                    <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
                                </svg>
                                <span className="text-[16px] font-bold text-gray-800">{stats.rating}</span>
                            </div>
                        </div>
                        <div className="flex flex-col gap-0.5">
                            <span className="text-[11px] text-gray-400 font-medium uppercase tracking-wider">Reviews</span>
                            <span className="text-[16px] font-bold text-gray-800 underline cursor-pointer hover:text-blue-500">{stats.reviews.toLocaleString()}개</span>
                        </div>
                    </div>

                    {/* 액션 버튼 */}
                    <ThemeActionButtons
                        themeId={dbId}
                        priceNum={priceNum}
                        priceName={price}
                        isLoggedIn={isLoggedIn}
                        userId={userId}
                        isOwned={isOwned}
                        ownedVersionIds={ownedVersionIds}
                        versions={versions}
                        onInquiryAction={() => setShowInquiryModal(true)}
                        isSelling={isSelling}
                    />

                    {/* 포인트 혜택 */}
                    {priceNum > 0 && (() => {
                        const purchaseCredit = getPurchaseCredit(priceNum);
                        const reviewCredit = getReviewCredit(priceNum);
                        return (
                            <div className="flex flex-col gap-3 p-4 rounded-[16px]"
                                style={{ background: "rgba(74,123,247,0.04)", border: "1px solid rgba(74,123,247,0.12)" }}>
                                <p className="text-[12px] font-bold" style={{ color: "#4A7BF7" }}>포인트 혜택</p>
                                <div className="flex flex-col gap-2">
                                    <div className="flex items-center justify-between">
                                        <span className="text-[12px]" style={{ color: "#8e8e93" }}>구매 완료 적립</span>
                                        <span className="text-[13px] font-bold" style={{ color: "#4A7BF7" }}>+{purchaseCredit}원</span>
                                    </div>
                                    <div className="flex items-center justify-between">
                                        <span className="text-[12px]" style={{ color: "#8e8e93" }}>리뷰 작성 적립</span>
                                        <span className="text-[13px] font-bold" style={{ color: "#FF9500" }}>+{reviewCredit}원</span>
                                    </div>
                                    <div className="h-[1px]" style={{ background: "rgba(0,0,0,0.06)" }} />
                                    <div className="flex items-center justify-between">
                                        <span className="text-[12px] font-semibold" style={{ color: "#3a3a3c" }}>예상 총 적립</span>
                                        <span className="text-[14px] font-extrabold" style={{ color: "#34c759" }}>+{(purchaseCredit + reviewCredit).toLocaleString()}원</span>
                                    </div>
                                </div>
                            </div>
                        );
                    })()}
                </div>
            </div>

            {/* 크리에이터 문의 모달 */}
            {showInquiryModal && (
                <CreatorInquiryModal
                    creatorId={creatorId}
                    creatorName={author}
                    themeId={dbId}
                    themeName={name}
                    onCloseAction={() => setShowInquiryModal(false)}
                />
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import Image from "next/image";
import { useRouter } from "next/navigation";
import { THEME_COLORS } from "@/app/store/data";
import { getPreviewSlots } from "./ThemeImageViewer";
import ThemeActionButtons from "./ThemeActionButtons";
import CreatorInquiryModal from "./CreatorInquiryModal";

function getPurchaseCredit(price: number): number {
    if (price === 0) return 0;
    if (price <= 500) return 10;
    if (price <= 1000) return 20;
    if (price <= 1500) return 30;
    if (price <= 2000) return 40;
    return 50;
}

function getReviewCredit(price: number): number {
    if (price === 0) return 0;
    if (price <= 500) return 30;
    if (price <= 1000) return 70;
    if (price <= 1500) return 120;
    if (price <= 2000) return 180;
    return 250;
}

type Stats = {
    sales: number;
    createdAt: string;
    likes: number;
    rating: number;
    reviews: number;
};

type ThemeVersion = { id: string; version: string; kthemeFileUrl: string | null; apkFileUrl: string | null };

type Props = {
    images: string[];
    previews: string[];
    name: string;
    tag?: string;
    themeId?: number;
    price: string;
    priceNum: number;
    author: string;
    creatorId: string;
    description: string;
    category: string[];
    stats: Stats;
    dbId: string;
    isLoggedIn: boolean;
    userId?: string;
    isOwned?: boolean;
    ownedVersionIds?: string[];
    versions?: ThemeVersion[];
    isSelling?: boolean;
};

export default function ThemeDetailLayout({
    images, previews, name, tag, themeId,
    price, priceNum, author, creatorId, description, category,
    stats, dbId, isLoggedIn, userId, isOwned, ownedVersionIds = [], versions = [],
    isSelling = true,
}: Props) {
    const router = useRouter();
    const colors = themeId ? THEME_COLORS[themeId] : undefined;
    const realImages = [...(images ?? []), ...(previews ?? [])].filter((s) => s && s !== "/back.jpg");
    const useColor = realImages.length === 0 && !!colors;
    const [activeIdx, setActiveIdx] = useState(0);
    const [likeCount, setLikeCount] = useState(stats.likes);
    const [showInquiryModal, setShowInquiryModal] = useState(false);

    const { slots } = getPreviewSlots(themeId, images, previews);

    // 좋아요 수 초기 로드
    useEffect(() => {
        fetch(`/api/themes/${dbId}/like`)
            .then(r => r.json())
            .then((d: { liked: boolean; count: number }) => {
                setLikeCount(d.count);
            })
            .catch(() => {});
    }, [dbId, setLikeCount]);

    const mainBg = useColor ? (slots[activeIdx] as string) ?? colors!.main : undefined;
    const mainSrc = useColor ? null : (realImages[activeIdx] ?? null);
    const purchaseCredit = getPurchaseCredit(priceNum);
    const reviewCredit = getReviewCredit(priceNum);

    return (
        <>
            {/* 메인 컨텐츠 카드 */}
            <div className="bg-white rounded-3xl overflow-hidden" style={{ boxShadow: "0 1px 3px rgba(0,0,0,0.06), 0 1px 0 rgba(0,0,0,0.04)" }}>
                <div className="grid grid-cols-1 lg:grid-cols-[1fr_1fr]">

                    {/* ── 왼쪽: 이미지 갤러리 ── */}
                    <div style={{ background: "#f5f5f7" }}>
                        {/* 메인 이미지 */}
                        <div
                            className="relative w-full"
                            style={{
                                aspectRatio: "1 / 1",
                                background: mainBg ?? "#f5f5f7",
                                transition: "background 0.3s ease",
                            }}
                        >
                            {mainSrc && (
                                <Image src={mainSrc} alt={name} fill className="object-cover" />
                            )}
                            {useColor && (
                                <div className="absolute inset-0 flex items-center justify-center">
                                    <span className="text-white/40 text-[14px] font-medium tracking-wide">{name}</span>
                                </div>
                            )}
                            {tag && (
                                <span
                                    className="absolute top-4 left-4 text-[11px] font-bold px-2.5 py-1 rounded-full"
                                    style={{
                                        background: tag === "무료" ? "#FFEF9A" : "rgb(74,123,247)",
                                        color: tag === "무료" ? "#1c1c1e" : "#fff",
                                        letterSpacing: "0.03em",
                                    }}
                                >
                                    {tag}
                                </span>
                            )}
                        </div>

                        {/* 썸네일 스트립 */}
                        {slots.length > 1 && (
                            <div className="flex gap-2 p-4" style={{ borderTop: "1px solid rgba(0,0,0,0.06)" }}>
                                {slots.slice(0, 5).map((slot, i) => (
                                    <button
                                        key={i}
                                        onMouseEnter={() => setActiveIdx(i)}
                                        onClick={() => setActiveIdx(i)}
                                        className="flex-1 rounded-xl overflow-hidden relative transition-all duration-150"
                                        style={{
                                            aspectRatio: "1 / 1",
                                            background: useColor ? (slot as string) : "#e5e5ea",
                                            outline: activeIdx === i ? "2px solid rgb(74,123,247)" : "2px solid transparent",
                                            outlineOffset: "1px",
                                            opacity: activeIdx === i ? 1 : 0.5,
                                        }}
                                    >
                                        {!useColor && (
                                            <Image src={slot as string} alt={`preview-${i + 1}`} fill className="object-cover" />
                                        )}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* ── 오른쪽: 정보 ── */}
                    <div className="flex flex-col p-10 gap-7">

                        {/* 이름 + 가격 */}
                        <div>
                            <div className="flex items-start justify-between gap-4 mb-2">
                                <h1 className="text-[26px] font-bold leading-tight" style={{ color: "#1c1c1e", letterSpacing: "-0.02em" }}>
                                    {name}
                                </h1>
                                <div className="text-right shrink-0">
                                    <p className="text-[26px] font-extrabold" style={{ color: priceNum === 0 ? "rgb(74,123,247)" : "#1c1c1e" }}>
                                        {price}
                                    </p>
                                    {priceNum > 0 && priceNum < 2000 && (
                                        <p className="text-[11px] font-semibold mt-0.5" style={{ color: "#FF3B30" }}>출시 기념 할인</p>
                                    )}
                                </div>
                            </div>

                            {/* 작가 */}
                            <button
                                onClick={() => router.push(`/creator/${creatorId}`)}
                                className="text-[13px] font-medium transition-opacity hover:opacity-60"
                                style={{ color: "#8e8e93" }}
                            >
                                by <span style={{ color: "#3a3a3c", fontWeight: 600 }}>{author}</span>
                            </button>
                        </div>

                        {/* 카테고리 태그 */}
                        {category.length > 0 && (
                            <div className="flex flex-wrap gap-1.5">
                                {category.map((cat) => (
                                    <span
                                        key={cat}
                                        className="text-[12px] font-medium px-3 py-1 rounded-full"
                                        style={{ background: "rgba(0,0,0,0.05)", color: "#636366" }}
                                    >
                                        {cat}
                                    </span>
                                ))}
                            </div>
                        )}

                        {/* 구분선 */}
                        <div style={{ height: "1px", background: "rgba(0,0,0,0.07)" }} />

                        {/* 설명 */}
                        {description && (
                            <p className="text-[14px] leading-relaxed" style={{ color: "#636366" }}>
                                {description}
                            </p>
                        )}

                        {/* 통계 */}
                        <div className="flex items-center gap-0" style={{ borderTop: "1px solid rgba(0,0,0,0.06)", paddingTop: 20 }}>
                            {[
                                { label: "판매", value: stats.sales.toLocaleString() },
                                { label: "등록", value: stats.createdAt },
                                { label: "좋아요", value: likeCount.toLocaleString() },
                                { label: "리뷰", value: `${stats.reviews}개` },
                            ].map((s, i, arr) => (
                                <div key={s.label} className="flex flex-col gap-0.5 text-center flex-1">
                                    <span className="text-[20px] font-bold" style={{ color: "#1c1c1e" }}>{s.value}</span>
                                    <span className="text-[11px]" style={{ color: "#aeaeb2" }}>{s.label}</span>
                                    {i < arr.length - 1 && (
                                        <div style={{
                                            position: "absolute",
                                            width: "1px",
                                            height: 28,
                                            background: "rgba(0,0,0,0.08)",
                                        }} />
                                    )}
                                </div>
                            ))}
                        </div>

                        {/* 액션 버튼 */}
                        <ThemeActionButtons
                            themeId={dbId}
                            priceNum={priceNum}
                            priceName={price}
                            isLoggedIn={isLoggedIn}
                            userId={userId}
                            isOwned={isOwned}
                            ownedVersionIds={ownedVersionIds}
                            versions={versions}
                            onInquiryAction={() => setShowInquiryModal(true)}
                            isSelling={isSelling}
                        />

                        {/* 적립금 혜택 — 박스 없이 심플하게 */}
                        {priceNum > 0 && (
                            <div style={{ borderTop: "1px solid rgba(0,0,0,0.06)", paddingTop: 16 }}>
                                <p className="text-[11px] font-semibold mb-2.5" style={{ color: "#aeaeb2", letterSpacing: "0.08em", textTransform: "uppercase" }}>
                                    적립 혜택
                                </p>
                                <div className="flex flex-col gap-1.5">
                                    <div className="flex justify-between items-center">
                                        <span className="text-[12px]" style={{ color: "#8e8e93" }}>구매 완료</span>
                                        <span className="text-[12px] font-semibold" style={{ color: "rgb(74,123,247)" }}>+{purchaseCredit}원</span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <span className="text-[12px]" style={{ color: "#8e8e93" }}>리뷰 작성</span>
                                        <span className="text-[12px] font-semibold" style={{ color: "rgb(255,149,0)" }}>+{reviewCredit}원</span>
                                    </div>
                                    <div className="flex justify-between items-center" style={{ borderTop: "1px solid rgba(0,0,0,0.06)", paddingTop: 8, marginTop: 4 }}>
                                        <span className="text-[12px] font-medium" style={{ color: "#3a3a3c" }}>예상 총 적립</span>
                                        <span className="text-[13px] font-bold" style={{ color: "#34c759" }}>+{(purchaseCredit + reviewCredit).toLocaleString()}원</span>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* 문의 모달 */}
            {showInquiryModal && (
                <CreatorInquiryModal
                    creatorId={creatorId}
                    creatorName={author}
                    themeId={dbId}
                    themeName={name}
                    onCloseAction={() => setShowInquiryModal(false)}
                />
            )}
        </>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Image from "next/image";
import ReviewModal from "@/app/components/ReviewModal";

type Review = {
    id: string;
    userId: string;
    rating: number;
    content: string | null;
    images: string[];
    createdAt: Date | string;
    nickname: string | null;
    name: string;
    avatarUrl: string | null;
};

export type ContentBlock = string; // HTML string

type OtherTheme = { id: string; title: string; thumbnailUrl: string | null; price: number };

export type Props = {
    themeId: string;
    themeName: string;
    thumbnailUrl?: string | null;
    isOwned?: boolean;
    userId?: string;
    contentBlocks?: ContentBlock;
    otherThemes?: OtherTheme[];
    creatorId?: string;
    creatorName?: string;
};

function StarRow({ rating, size = 14 }: { rating: number; size?: number }) {
    return (
        <div className="flex items-center gap-0.5">
            {[1, 2, 3, 4, 5].map(s => (
                <svg key={s} width={size} height={size} viewBox="0 0 24 24"
                    fill={rating >= s ? "#FFB800" : "none"}
                    stroke={rating >= s ? "#FFB800" : "#c8c8cd"}
                    strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                    <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
                </svg>
            ))}
        </div>
    );
}

function formatDate(d: Date | string) {
    const date = new Date(d);
    const y = date.getFullYear().toString().slice(2);
    const m = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    return `${y}.${m}.${day}`;
}

export default function ThemeDetailTabs({ themeId, themeName, thumbnailUrl, isOwned, userId, contentBlocks = "", otherThemes = [], creatorId, creatorName }: Props) {
    const [activeTab, setActiveTab] = useState<"detail" | "reviews" | "more">("detail");
    const [reviews, setReviews] = useState<Review[]>([]);
    const [myReview, setMyReview] = useState<Review | null>(null);
    const [avgRating, setAvgRating] = useState(0);
    const [reviewCount, setReviewCount] = useState(0);
    const [loading, setLoading] = useState(false);
    const [showModal, setShowModal] = useState(false);
    const [deleting, setDeleting] = useState(false);

    const fetchReviews = useCallback(async () => {
        setLoading(true);
        try {
            const res = await fetch(`/api/themes/${themeId}/review`);
            const data = await res.json() as { reviews: Review[]; myReview: Review | null; avgRating: number; reviewCount: number };
            setReviews(data.reviews ?? []);
            setMyReview(data.myReview ?? null);
            setAvgRating(data.avgRating ?? 0);
            setReviewCount(data.reviewCount ?? 0);
        } catch {
            //
        } finally {
            setLoading(false);
        }
    }, [themeId]);

    useEffect(() => {
        if (activeTab === "reviews") {
            fetchReviews();
        }
    }, [activeTab, fetchReviews]);

    const handleDeleteReview = async () => {
        if (!confirm("리뷰를 삭제할까요?")) return;
        setDeleting(true);
        await fetch(`/api/themes/${themeId}/review`, { method: "DELETE" });
        setDeleting(false);
        fetchReviews();
    };

    const tabs = [
        { key: "detail", label: "테마 정보" },
        { key: "reviews", label: `리뷰 (${reviewCount})` },
        { key: "more", label: "크리에이터 다른 테마" },
    ] as const;

    return (
        <div className="mt-20 border-t border-gray-100 pt-10">
            {/* 탭 헤더 */}
            <div className="flex items-center gap-6 mb-8">
                {tabs.map(tab => (
                    <button
                        key={tab.key}
                        onClick={() => setActiveTab(tab.key)}
                        className={`pb-3 border-b-2 font-${activeTab === tab.key ? "bold" : "medium"} text-[15px] transition-colors`}
                        style={{
                            borderColor: activeTab === tab.key ? "rgb(74,123,247)" : "transparent",
                            color: activeTab === tab.key ? "rgb(74,123,247)" : "#9ca3af",
                        }}
                    >
                        {tab.key === "reviews" ? `리뷰 (${reviewCount})` : tab.label}
                    </button>
                ))}
            </div>

            {/* 탭 콘텐츠 */}
            {activeTab === "detail" && (
                <div className="flex flex-col gap-6">
                    {!contentBlocks || contentBlocks === "<p></p>" || contentBlocks.trim() === "" ? (
                        <div className="bg-white rounded-2xl p-10 min-h-[200px] flex items-center justify-center border border-gray-100">
                            <p className="text-[14px] text-gray-400">등록된 테마 정보가 없어요.</p>
                        </div>
                    ) : (
                        <div
                            className="theme-detail-content prose prose-sm max-w-none px-1"
                            dangerouslySetInnerHTML={{ __html: contentBlocks }}
                        />
                    )}
                    <style>{`
                        .theme-detail-content h2 { font-size: 20px; font-weight: 700; margin: 16px 0 8px; color: #1a1a1a; }
                        .theme-detail-content h3 { font-size: 16px; font-weight: 600; margin: 12px 0 6px; color: #1a1a1a; }
                        .theme-detail-content p { margin: 6px 0; color: #3a3a3c; font-size: 15px; line-height: 1.8; }
                        .theme-detail-content ul { list-style: disc; padding-left: 22px; margin: 8px 0; }
                        .theme-detail-content ol { list-style: decimal; padding-left: 22px; margin: 8px 0; }
                        .theme-detail-content li { margin: 3px 0; color: #3a3a3c; font-size: 15px; }
                        .theme-detail-content blockquote { border-left: 3px solid rgba(255,149,0,0.5); padding-left: 14px; margin: 10px 0; color: #6e6e73; font-style: italic; }
                        .theme-detail-content hr { border: none; border-top: 1.5px solid rgba(0,0,0,0.1); margin: 18px 0; }
                        .theme-detail-content img { max-width: 100%; border-radius: 12px; margin: 12px 0; display: block; }
                        .theme-detail-content strong { font-weight: 700; }
                        .theme-detail-content em { font-style: italic; }
                        .theme-detail-content s { text-decoration: line-through; }
                        .theme-detail-content u { text-decoration: underline; }
                    `}</style>
                </div>
            )}

            {activeTab === "reviews" && (
                <div className="flex flex-col gap-6">
                    {/* 평점 요약 */}
                    <div className="flex items-center gap-6 p-6 rounded-2xl bg-white border border-gray-100">
                        <div className="flex flex-col items-center gap-1">
                            <span className="text-[40px] font-extrabold" style={{ color: "#1c1c1e" }}>
                                {reviewCount > 0 ? avgRating.toFixed(1) : "-"}
                            </span>
                            <StarRow rating={Math.round(avgRating)} size={16} />
                            <span className="text-[12px]" style={{ color: "#8e8e93" }}>리뷰 {reviewCount}개</span>
                        </div>
                    </div>

                    {/* 내 리뷰 / 작성 유도 */}
                    {isOwned && (
                        <div className="p-5 rounded-2xl border border-dashed flex flex-col gap-3"
                            style={{ borderColor: myReview ? "rgba(255,149,0,0.3)" : "rgba(0,0,0,0.1)", background: myReview ? "rgba(255,149,0,0.04)" : "rgba(0,0,0,0.02)" }}>
                            <div className="flex items-center justify-between">
                                <span className="text-[13px] font-bold" style={{ color: "#1c1c1e" }}>
                                    {myReview ? "내 리뷰" : "이 테마를 보유하고 있어요!"}
                                </span>
                                <div className="flex items-center gap-2">
                                    <button
                                        onClick={() => setShowModal(true)}
                                        className="px-3 py-1.5 rounded-xl text-[12px] font-medium transition-all hover:opacity-70"
                                        style={{ background: "rgb(255,149,0)", color: "#fff" }}
                                    >
                                        {myReview ? "수정" : "리뷰 작성"}
                                    </button>
                                    {myReview && (
                                        <button
                                            onClick={handleDeleteReview}
                                            disabled={deleting}
                                            className="px-3 py-1.5 rounded-xl text-[12px] font-medium transition-all hover:opacity-70 disabled:opacity-40"
                                            style={{ border: "1px solid rgba(255,59,48,0.3)", color: "#ff3b30" }}
                                        >
                                            삭제
                                        </button>
                                    )}
                                </div>
                            </div>
                            {myReview ? (
                                <div className="flex flex-col gap-1.5">
                                    <StarRow rating={myReview.rating} />
                                    {myReview.content && (
                                        <p className="text-[13px] leading-relaxed" style={{ color: "#3a3a3c" }}>{myReview.content}</p>
                                    )}
                                    {myReview.images?.length > 0 && (
                                        <div className="flex flex-wrap gap-2 mt-1">
                                            {myReview.images.map((url, i) => (
                                                <div key={i} className="relative w-[64px] h-[64px] rounded-lg overflow-hidden" style={{ border: "1px solid rgba(0,0,0,0.08)" }}>
                                                    <Image src={url} alt={`리뷰 이미지 ${i + 1}`} fill className="object-cover" unoptimized />
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                    <span className="text-[11px]" style={{ color: "#8e8e93" }}>{formatDate(myReview.createdAt)}</span>
                                </div>
                            ) : (
                                <p className="text-[13px]" style={{ color: "#8e8e93" }}>리뷰를 작성하고 적립금을 받아보세요.</p>
                            )}
                        </div>
                    )}

                    {/* 전체 리뷰 목록 */}
                    {loading ? (
                        <div className="flex items-center justify-center py-16">
                            <span className="text-[14px]" style={{ color: "#8e8e93" }}>불러오는 중...</span>
                        </div>
                    ) : reviews.filter(r => r.userId !== userId).length === 0 && !myReview ? (
                        <div className="flex flex-col items-center justify-center py-16 gap-3 bg-white rounded-2xl border border-gray-100">
                            <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="#c8c8cd" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                            </svg>
                            <p className="text-[14px]" style={{ color: "#8e8e93" }}>아직 리뷰가 없어요. 첫 번째 리뷰를 남겨보세요!</p>
                        </div>
                    ) : (
                        <div className="flex flex-col gap-4">
                            {reviews.filter(r => r.userId !== userId).map((review, idx) => (
                                <div key={review.id}>
                                    <div className="flex items-start gap-3 bg-white p-5 rounded-2xl border border-gray-100">
                                        <div className="w-9 h-9 rounded-full overflow-hidden shrink-0 flex items-center justify-center" style={{ background: "rgba(195,195,195,0.4)" }}>
                                            {review.avatarUrl ? (
                                                <Image src={review.avatarUrl} alt={review.nickname ?? review.name} width={36} height={36} className="w-full h-full object-cover" unoptimized />
                                            ) : (
                                                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#888" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                                                    <circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                                                </svg>
                                            )}
                                        </div>
                                        <div className="flex flex-col gap-1.5 flex-1 min-w-0">
                                            <div className="flex items-center justify-between gap-2">
                                                <span className="text-[13px] font-bold truncate" style={{ color: "#1c1c1e" }}>
                                                    {review.nickname ?? review.name}
                                                </span>
                                                <span className="text-[11px] shrink-0" style={{ color: "#8e8e93" }}>{formatDate(review.createdAt)}</span>
                                            </div>
                                            <StarRow rating={review.rating} />
                                            {review.content && (
                                                <p className="text-[13px] leading-relaxed" style={{ color: "#3a3a3c" }}>{review.content}</p>
                                            )}
                                            {review.images?.length > 0 && (
                                                <div className="flex flex-wrap gap-2 mt-1">
                                                    {review.images.map((url, i) => (
                                                        <div key={i} className="relative w-[64px] h-[64px] rounded-lg overflow-hidden" style={{ border: "1px solid rgba(0,0,0,0.08)" }}>
                                                            <Image src={url} alt={`리뷰 이미지 ${i + 1}`} fill className="object-cover" unoptimized />
                                                        </div>
                                                    ))}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                    {idx < reviews.filter(r => r.userId !== userId).length - 1 && (
                                        <div className="h-[1px] mt-1" style={{ background: "transparent" }} />
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}

            {activeTab === "more" && (
                <div className="flex flex-col gap-5">
                    {otherThemes.length === 0 ? (
                        <div className="bg-white rounded-2xl p-10 min-h-[200px] flex items-center justify-center border border-gray-100">
                            <p className="text-[14px] text-gray-400">등록된 다른 테마가 없어요.</p>
                        </div>
                    ) : (
                        <>
                            <div className="grid gap-3" style={{ gridTemplateColumns: 'repeat(5, 1fr)' }}>
                                {otherThemes.map(t => (
                                    <a key={t.id} href={`/store/${t.id}`} className="flex flex-col gap-2 group">
                                        <div className="w-full overflow-hidden rounded-xl" style={{ background: '#e5e5ea', aspectRatio: '1 / 1' }}>
                                            {t.thumbnailUrl
                                                ? <img src={t.thumbnailUrl} alt={t.title} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
                                                : <div className="w-full h-full flex items-center justify-center">
                                                    <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#c7c7cc" strokeWidth="1.5" strokeLinecap="round"><rect x="3" y="3" width="18" height="18" rx="3"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg>
                                                  </div>
                                            }
                                        </div>
                                        <div className="flex flex-col gap-0.5 px-0.5">
                                            <p className="text-[12px] font-medium truncate transition-colors group-hover:text-orange-500" style={{ color: '#1a1a1a' }}>{t.title}</p>
                                            <p className="text-[11px]" style={{ color: '#aeaeb2' }}>{t.price === 0 ? '무료' : `${t.price.toLocaleString()}원`}</p>
                                        </div>
                                    </a>
                                ))}
                            </div>
                            {creatorId && (
                                <div className="flex justify-center mt-2">
                                    <a
                                        href={`/creator/${creatorId}`}
                                        className="flex items-center gap-1.5 px-5 py-2.5 rounded-xl text-[13px] font-medium transition-all hover:opacity-70"
                                        style={{ background: 'rgba(255,149,0,0.08)', color: 'rgb(190,100,0)' }}
                                    >
                                        {creatorName ?? '크리에이터'}의 모든 테마 보기
                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M5 12h14"/><path d="M12 5l7 7-7 7"/></svg>
                                    </a>
                                </div>
                            )}
                        </>
                    )}
                </div>
            )}

            {/* 리뷰 작성/수정 모달 */}
            {showModal && (
                <ReviewModal
                    themeId={themeId}
                    themeName={themeName}
                    thumbnailUrl={thumbnailUrl}
                    onCloseAction={() => setShowModal(false)}
                    onSuccessAction={() => {
                        setShowModal(false);
                        fetchReviews();
                    }}
                    initialRating={myReview?.rating ?? 0}
                    initialContent={myReview?.content ?? ""}
                    initialImages={myReview?.images ?? []}
                    isEdit={!!myReview}
                />
            )}
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Image from "next/image";
import ReviewModal from "@/app/components/ReviewModal";

type Review = {
    id: string;
    userId: string;
    rating: number;
    content: string | null;
    images: string[];
    createdAt: Date | string;
    nickname: string | null;
    name: string;
    avatarUrl: string | null;
};

export type ContentBlock = string;
type OtherTheme = { id: string; title: string; thumbnailUrl: string | null; price: number };

export type Props = {
    themeId: string;
    themeName: string;
    thumbnailUrl?: string | null;
    isOwned?: boolean;
    userId?: string;
    contentBlocks?: ContentBlock;
    otherThemes?: OtherTheme[];
    creatorId?: string;
    creatorName?: string;
};

function StarRow({ rating, size = 13 }: { rating: number; size?: number }) {
    return (
        <div className="flex items-center gap-0.5">
            {[1, 2, 3, 4, 5].map(s => (
                <svg key={s} width={size} height={size} viewBox="0 0 24 24"
                    fill={rating >= s ? "#FFB800" : "none"}
                    stroke={rating >= s ? "#FFB800" : "#d6d3d1"}
                    strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                    <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
                </svg>
            ))}
        </div>
    );
}

function formatDate(d: Date | string) {
    const date = new Date(d);
    const y = date.getFullYear().toString().slice(2);
    const m = String(date.getMonth() + 1).padStart(2, "0");
    const day = String(date.getDate()).padStart(2, "0");
    return `${y}.${m}.${day}`;
}

export default function ThemeDetailTabs({ themeId, themeName, thumbnailUrl, isOwned, userId, contentBlocks = "", otherThemes = [], creatorId, creatorName }: Props) {
    const [activeTab, setActiveTab] = useState<"detail" | "reviews" | "more">("detail");
    const [reviews, setReviews] = useState<Review[]>([]);
    const [myReview, setMyReview] = useState<Review | null>(null);
    const [avgRating, setAvgRating] = useState(0);
    const [reviewCount, setReviewCount] = useState(0);
    const [loading, setLoading] = useState(false);
    const [showModal, setShowModal] = useState(false);
    const [deleting, setDeleting] = useState(false);

    const fetchReviews = useCallback(async () => {
        setLoading(true);
        try {
            const res = await fetch(`/api/themes/${themeId}/review`);
            const data = await res.json() as { reviews: Review[]; myReview: Review | null; avgRating: number; reviewCount: number };
            setReviews(data.reviews ?? []);
            setMyReview(data.myReview ?? null);
            setAvgRating(data.avgRating ?? 0);
            setReviewCount(data.reviewCount ?? 0);
        } catch { /**/ } finally {
            setLoading(false);
        }
    }, [themeId]);

    useEffect(() => {
        if (activeTab === "reviews") fetchReviews();
    }, [activeTab, fetchReviews]);

    const handleDeleteReview = async () => {
        if (!confirm("리뷰를 삭제할까요?")) return;
        setDeleting(true);
        await fetch(`/api/themes/${themeId}/review`, { method: "DELETE" });
        setDeleting(false);
        fetchReviews();
    };

    const tabs = [
        { key: "detail" as const, label: "테마 정보" },
        { key: "reviews" as const, label: `리뷰 ${reviewCount > 0 ? `(${reviewCount})` : ""}` },
        { key: "more" as const, label: "크리에이터의 다른 테마" },
    ];

    const otherReviews = reviews.filter(r => r.userId !== userId);

    return (
        <div className="mt-8 bg-white rounded-3xl overflow-hidden" style={{ boxShadow: "0 1px 3px rgba(0,0,0,0.06), 0 1px 0 rgba(0,0,0,0.04)" }}>
            {/* 탭 헤더 */}
            <div className="flex" style={{ borderBottom: "1px solid rgba(0,0,0,0.07)" }}>
                {tabs.map(tab => (
                    <button
                        key={tab.key}
                        onClick={() => setActiveTab(tab.key)}
                        className="relative px-7 py-5 text-[13px] font-medium transition-colors"
                        style={{ color: activeTab === tab.key ? "rgb(74,123,247)" : "#aeaeb2" }}
                    >
                        {tab.label}
                        {activeTab === tab.key && (
                            <span className="absolute bottom-0 left-0 right-0 h-[2px] rounded-full" style={{ background: "rgb(74,123,247)" }} />
                        )}
                    </button>
                ))}
            </div>

            {/* 탭 콘텐츠 */}
            <div className="p-8">

                {/* ── 테마 정보 ── */}
                {activeTab === "detail" && (
                    <>
                        {!contentBlocks || contentBlocks === "<p></p>" || contentBlocks.trim() === "" ? (
                            <div className="flex flex-col items-center justify-center py-20 gap-3">
                                <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/>
                                </svg>
                                <p className="text-[14px]" style={{ color: "#aeaeb2" }}>등록된 테마 정보가 없어요.</p>
                            </div>
                        ) : (
                            <div
                                className="theme-detail-content prose prose-sm max-w-none"
                                dangerouslySetInnerHTML={{ __html: contentBlocks }}
                            />
                        )}
                        <style>{`
                            .theme-detail-content h2 { font-size: 19px; font-weight: 700; margin: 20px 0 10px; color: #1c1c1e; letter-spacing: -0.01em; }
                            .theme-detail-content h3 { font-size: 16px; font-weight: 600; margin: 14px 0 6px; color: #3a3a3c; }
                            .theme-detail-content p { margin: 8px 0; color: #636366; font-size: 14px; line-height: 1.85; }
                            .theme-detail-content ul { list-style: disc; padding-left: 20px; margin: 8px 0; }
                            .theme-detail-content ol { list-style: decimal; padding-left: 20px; margin: 8px 0; }
                            .theme-detail-content li { margin: 4px 0; color: #636366; font-size: 14px; line-height: 1.7; }
                            .theme-detail-content blockquote { border-left: 2px solid rgb(255,149,0); padding-left: 14px; margin: 12px 0; color: #8e8e93; }
                            .theme-detail-content hr { border: none; border-top: 1px solid rgba(0,0,0,0.08); margin: 20px 0; }
                            .theme-detail-content img { max-width: 100%; border-radius: 14px; margin: 14px 0; display: block; }
                            .theme-detail-content strong { font-weight: 700; color: #3a3a3c; }
                            .theme-detail-content em { font-style: italic; }
                            .theme-detail-content s { text-decoration: line-through; }
                            .theme-detail-content u { text-decoration: underline; }
                        `}</style>
                    </>
                )}

                {/* ── 리뷰 ── */}
                {activeTab === "reviews" && (
                    <div className="flex flex-col gap-8">
                        {/* 평점 요약 */}
                        <div className="flex items-center gap-4">
                            <span className="text-[48px] font-extrabold leading-none" style={{ color: "#1c1c1e" }}>
                                {reviewCount > 0 ? avgRating.toFixed(1) : "—"}
                            </span>
                            <div className="flex flex-col gap-1">
                                <StarRow rating={Math.round(avgRating)} size={16} />
                                <span className="text-[12px]" style={{ color: "#aeaeb2" }}>리뷰 {reviewCount}개</span>
                            </div>
                        </div>

                        {/* 내 리뷰 섹션 */}
                        {isOwned && (
                            <div style={{ borderTop: "1px solid rgba(0,0,0,0.07)", paddingTop: 24 }}>
                                <div className="flex items-center justify-between mb-4">
                                    <span className="text-[13px] font-semibold" style={{ color: "#1c1c1e" }}>
                                        {myReview ? "내 리뷰" : "이 테마를 보유 중이에요"}
                                    </span>
                                    <div className="flex items-center gap-2">
                                        <button
                                            onClick={() => setShowModal(true)}
                                            className="px-4 py-1.5 rounded-full text-[12px] font-semibold transition-opacity hover:opacity-70"
                                            style={{ background: "rgb(255,149,0)", color: "#fff" }}
                                        >
                                            {myReview ? "수정" : "리뷰 작성"}
                                        </button>
                                        {myReview && (
                                            <button
                                                onClick={handleDeleteReview}
                                                disabled={deleting}
                                                className="px-4 py-1.5 rounded-full text-[12px] font-medium transition-opacity hover:opacity-60 disabled:opacity-30"
                                                style={{ color: "#ff3b30" }}
                                            >
                                                삭제
                                            </button>
                                        )}
                                    </div>
                                </div>
                                {myReview ? (
                                    <div className="flex flex-col gap-2">
                                        <StarRow rating={myReview.rating} />
                                        {myReview.content && (
                                            <p className="text-[13px] leading-relaxed" style={{ color: "#636366" }}>{myReview.content}</p>
                                        )}
                                        {myReview.images?.length > 0 && (
                                            <div className="flex flex-wrap gap-2 mt-1">
                                                {myReview.images.map((url, i) => (
                                                    <div key={i} className="relative w-16 h-16 rounded-xl overflow-hidden" style={{ border: "1px solid rgba(0,0,0,0.07)" }}>
                                                        <Image src={url} alt="" fill className="object-cover" unoptimized />
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                        <span className="text-[11px]" style={{ color: "#c8c8cd" }}>{formatDate(myReview.createdAt)}</span>
                                    </div>
                                ) : (
                                    <p className="text-[13px]" style={{ color: "#aeaeb2" }}>리뷰를 작성하고 적립금을 받아보세요.</p>
                                )}
                            </div>
                        )}

                        {/* 전체 리뷰 */}
                        <div style={{ borderTop: "1px solid rgba(0,0,0,0.07)", paddingTop: 24 }}>
                            {loading ? (
                                <div className="flex justify-center py-12">
                                    <div className="w-5 h-5 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                                </div>
                            ) : otherReviews.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-16 gap-3">
                                    <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
                                    </svg>
                                    <p className="text-[13px]" style={{ color: "#aeaeb2" }}>아직 작성된 리뷰가 없어요.</p>
                                </div>
                            ) : (
                                <div className="flex flex-col">
                                    {otherReviews.map((review, idx) => (
                                        <div key={review.id}>
                                            <div className="flex items-start gap-3 py-5">
                                                {/* 아바타 */}
                                                <div className="w-8 h-8 rounded-full overflow-hidden shrink-0 flex items-center justify-center" style={{ background: "#f2f2f7" }}>
                                                    {review.avatarUrl ? (
                                                        <Image src={review.avatarUrl} alt="" width={32} height={32} className="w-full h-full object-cover" unoptimized />
                                                    ) : (
                                                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#c8c8cd" strokeWidth="2" strokeLinecap="round">
                                                            <circle cx="12" cy="8" r="4" /><path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                                                        </svg>
                                                    )}
                                                </div>
                                                <div className="flex flex-col gap-1.5 flex-1 min-w-0">
                                                    <div className="flex items-center justify-between">
                                                        <span className="text-[13px] font-semibold" style={{ color: "#1c1c1e" }}>
                                                            {review.nickname ?? review.name}
                                                        </span>
                                                        <span className="text-[11px]" style={{ color: "#c8c8cd" }}>{formatDate(review.createdAt)}</span>
                                                    </div>
                                                    <StarRow rating={review.rating} />
                                                    {review.content && (
                                                        <p className="text-[13px] leading-relaxed" style={{ color: "#636366" }}>{review.content}</p>
                                                    )}
                                                    {review.images?.length > 0 && (
                                                        <div className="flex flex-wrap gap-2 mt-1">
                                                            {review.images.map((url, i) => (
                                                                <div key={i} className="relative w-16 h-16 rounded-xl overflow-hidden" style={{ border: "1px solid rgba(0,0,0,0.07)" }}>
                                                                    <Image src={url} alt="" fill className="object-cover" unoptimized />
                                                                </div>
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                            {idx < otherReviews.length - 1 && (
                                                <div style={{ height: "1px", background: "rgba(0,0,0,0.06)" }} />
                                            )}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* ── 크리에이터 다른 테마 ── */}
                {activeTab === "more" && (
                    <div className="flex flex-col gap-6">
                        {otherThemes.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-20 gap-3">
                                <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                                    <rect x="3" y="3" width="18" height="18" rx="3"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/>
                                </svg>
                                <p className="text-[13px]" style={{ color: "#aeaeb2" }}>다른 테마가 없어요.</p>
                            </div>
                        ) : (
                            <>
                                <div className="grid gap-4" style={{ gridTemplateColumns: "repeat(5, 1fr)" }}>
                                    {otherThemes.map(t => (
                                        <a key={t.id} href={`/store/${t.id}`} className="flex flex-col gap-2 group">
                                            <div className="w-full rounded-2xl overflow-hidden" style={{ aspectRatio: "1 / 1", background: "#f2f2f7" }}>
                                                {t.thumbnailUrl ? (
                                                    <img src={t.thumbnailUrl} alt={t.title} className="w-full h-full object-cover transition-transform duration-200 group-hover:scale-105" />
                                                ) : (
                                                    <div className="w-full h-full flex items-center justify-center">
                                                        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#c8c8cd" strokeWidth="1.5" strokeLinecap="round">
                                                            <rect x="3" y="3" width="18" height="18" rx="3"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/>
                                                        </svg>
                                                    </div>
                                                )}
                                            </div>
                                            <div className="flex flex-col gap-0.5">
                                                <p className="text-[12px] font-medium truncate transition-colors" style={{ color: "#1c1c1e" }}>{t.title}</p>
                                                <p className="text-[11px]" style={{ color: "#aeaeb2" }}>{t.price === 0 ? "무료" : `${t.price.toLocaleString()}원`}</p>
                                            </div>
                                        </a>
                                    ))}
                                </div>
                                {creatorId && (
                                    <div className="flex justify-center pt-2">
                                        <a
                                            href={`/creator/${creatorId}`}
                                            className="flex items-center gap-1.5 text-[13px] font-medium transition-opacity hover:opacity-60"
                                            style={{ color: "rgb(74,123,247)" }}
                                        >
                                            {creatorName ?? "크리에이터"}의 모든 테마 보기
                                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M5 12h14"/><path d="M12 5l7 7-7 7"/></svg>
                                        </a>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                )}
            </div>

            {/* 리뷰 모달 */}
            {showModal && (
                <ReviewModal
                    themeId={themeId}
                    themeName={themeName}
                    thumbnailUrl={thumbnailUrl}
                    onCloseAction={() => setShowModal(false)}
                    onSuccessAction={() => { setShowModal(false); fetchReviews(); }}
                    initialRating={myReview?.rating ?? 0}
                    initialContent={myReview?.content ?? ""}
                    initialImages={myReview?.images ?? []}
                    isEdit={!!myReview}
                />
            )}
        </div>
    );
}

{
    "crons": [
        {
            "path": "/api/cron/credit-expiry",
            "schedule": "0 0 * * *"
        }
    ]
}

{
    "crons": [
        {
            "path": "/api/cron/credit-expiry",
            "schedule": "0 0 * * *"
        },
        {
            "path": "/api/cron/subscription-expiry",
            "schedule": "0 1 * * *"
        }
    ]
}
